import type { SignTemplates } from './types';

export const taurusTemplates: SignTemplates = {
  overall: {
    high: [
      { ko: '금성의 축복이 오늘 당신을 온전히 감싸고 있습니다. 이 풍요로운 에너지는 감각을 예민하게 열어두는 자에게 더욱 풍성하게 찾아오기 때문에, 평소 지나쳤던 아름다움 하나를 오늘만큼은 제대로 음미해보세요. 당신이 느끼는 기쁨이 곧 더 큰 풍요를 불러오는 씨앗입니다.', en: 'Venus\'s blessing fully embraces you today, and this energy grows richer when you open your senses to receive it. Look for beauty in the details you usually rush past—a texture, a scent, a color. That conscious appreciation is exactly how you amplify Venus\'s gift.', zh: '金星的祝福今天完全笼罩着你，这份丰盛的能量会让敞开感官的人收获更多。细细品味平时忽略的美好，你的喜悦就是吸引更大丰盛的种子。', ja: '金星の祝福が今日完全にあなたを包んでいます。この豊かなエネルギーは感覚を敏感に開いている人により豊かに訪れるので、普段見過ごしていた美しさを今日だけはしっかり味わってみてください。あなたが感じる喜びがより大きな豊かさを呼び込む種です。', es: 'La bendición de Venus te envuelve completamente hoy, y esta energía se vuelve más abundante cuando abres tus sentidos a recibirla. Saborea algo que normalmente pasas por alto: una textura, un aroma, un color. Esa apreciación consciente amplifica el regalo de Venus.' },
      { ko: '꾸준히 쌓아온 노력이 드디어 빛을 발하는 날입니다. 황소자리의 인내는 단기 결과에 흔들리지 않는 대지처럼 깊기 때문에, 오늘 나타나는 성과는 그 깊이만큼의 진짜 보상입니다. 이 순간을 충분히 즐기고, 다음 씨앗을 심을 준비를 시작하세요.', en: 'Your steady efforts finally shine today—Taurus patience runs deep as the earth itself, unshaken by short-term setbacks. The results appearing now are a true reward matching that depth. Savor this moment fully, then prepare to plant your next seeds.', zh: '持续积累的努力今天终于发光了。金牛座的耐心像大地一样深沉，不被短期结果动摇，今天出现的成果是与那份深度相称的真正回报。充分享受这一刻，然后准备播下下一粒种子。', ja: '着実に積み重ねてきた努力がついに光を放つ日です。牡牛座の忍耐は大地のように深く短期結果に揺るがないため、今日現れる成果はその深さに見合った本物の報酬です。この瞬間を十分に楽しみ、次の種を植える準備を始めてください。', es: 'Tus esfuerzos constantes finalmente brillan hoy—la paciencia de Tauro es profunda como la tierra misma, inquebrantable ante contratiempos. Los resultados que aparecen ahora son una recompensa genuina. Saborea este momento y prepárate para plantar tus próximas semillas.' },
      { ko: '흙이 봄비를 머금듯 좋은 기운이 조용히 스며드는 하루입니다. 서두르거나 억지로 끌어당기지 않아도 흐름이 자연스럽게 당신 곁으로 옵니다. 오늘은 여유롭게 받아들이는 것 자체가 최고의 전략입니다.', en: 'Like earth quietly absorbing spring rain, good energy seeps into your day without force or urgency. The flow comes to you naturally—you don\'t need to chase it. Today, allowing yourself to receive with ease is your highest strategy.', zh: '像泥土悄悄吸收春雨一样，好运正在渗入你的一天。无需强求，流动自然来到你身边。今天，从容地接受本身就是最高策略。', ja: '土が春雨を静かに含むように良い気運がじっくり染み込む一日です。急いだり無理に引き寄せなくても流れが自然にあなたのそばに来ます。今日は余裕を持って受け入れること自体が最高の戦略です。', es: 'Como la tierra absorbiendo suavemente la lluvia de primavera, buena energía se filtra en tu día sin esfuerzo. El flujo llega naturalmente—no necesitas perseguirlo. Hoy, permitirte recibir con calma es tu mayor estrategia.' },
      { ko: '당신의 묵묵한 성실함이 오늘 주변 사람들에게 깊이 인정받습니다. 말보다 행동으로 증명해온 당신의 방식이 신뢰의 기반이 되었기 때문입니다. 그 신뢰 위에서 자신감 있게 한 발 더 나아가세요.', en: 'Your quiet diligence is deeply recognized by those around you today—your way of proving through action rather than words has built a foundation of trust. Stand confidently on that trust and take one more step forward.', zh: '你默默的勤奋今天得到周围人深深的认可。你用行动而非言语证明自己的方式已成为信任的基础。在那份信任上自信地再迈出一步。', ja: 'あなたの黙々とした誠実さが今日周りの人に深く認められます。言葉より行動で証明してきたあなたのやり方が信頼の基盤となったからです。その信頼の上で自信を持ってもう一歩踏み出してください。', es: 'Tu diligencia silenciosa es profundamente reconocida hoy—tu forma de demostrar con acciones ha construido una base de confianza. Párate con confianza sobre esa base y da un paso más adelante.' },
      { ko: '안정 속에서 풍요가 자라나는 최적의 시기입니다. 황소자리는 흔들림 없는 지속성이 가장 큰 강점이기 때문에, 지금의 페이스를 유지하는 것 자체가 이미 이기는 전략입니다. 조급해하지 말고 대지처럼 묵직하게 전진하세요.', en: 'Abundance grows within stability—this is prime time for Taurus. Your unwavering consistency is your greatest strength, making the very act of maintaining your current pace a winning strategy. Move forward with the solidity of the earth, unhurried.', zh: '丰收在稳定中生长，这是金牛座的最佳时期。坚定的持续性是你最大的优势，保持现在的节奏本身就已经是制胜策略。不要着急，像大地一样沉稳地前进。', ja: '安定の中で豊かさが育つ最適な時期です。牡牛座は揺るぎない持続性が最大の強みなので、今のペースを維持すること自体がすでに勝つ戦略です。焦らず大地のようにどっしりと前進してください。', es: 'La abundancia crece en la estabilidad—este es el momento óptimo para Tauro. Tu consistencia inquebrantable es tu mayor fortaleza, haciendo que mantener tu ritmo actual sea la estrategia ganadora. Avanza con la solidez de la tierra, sin prisa.' },
      { ko: '오감이 활짝 열리는 날입니다. 평소 무심코 지나쳤던 것들 속에 오늘의 행운이 숨어 있기 때문에, 감각을 예민하게 열고 주변을 탐색해보세요. 황소자리의 직관적 감각이 오늘 최고의 안내자가 되어줄 것입니다.', en: 'Your five senses open fully today—luck hides in the details you usually walk past without noticing. Heighten your awareness and explore your surroundings with curiosity. Taurus\'s intuitive sensory radar is your finest guide today.', zh: '五感全面开启的一天。今天的好运藏在平时随手错过的事物中，保持感官敏锐，探索周围的世界。金牛座的直觉感官今天将成为你最好的向导。', ja: '五感が大きく開く日です。普段何気なく見過ごしていたものの中に今日の幸運が隠れているので、感覚を鋭く開いて周りを探索してみてください。牡牛座の直感的な感覚が今日最高の案内者になってくれるでしょう。', es: 'Tus cinco sentidos se abren por completo hoy—la suerte se esconde en detalles que normalmente pasas sin notar. Agudiza tu conciencia y explora tu entorno con curiosidad. El radar sensorial intuitivo de Tauro es tu mejor guía hoy.' },
      { ko: '대지의 에너지가 오늘 당신의 발걸음을 든든하게 받쳐주고 있습니다. 황소자리 특유의 중심이 잡힌 존재감이 주변 사람들에게 신뢰를 주기 때문에, 어디를 가든 흔들리지 않는 당신이 분위기를 이끌게 됩니다. 그 자연스러운 리더십을 믿으세요.', en: 'Earth\'s energy firmly supports your every step today, and Taurus\'s naturally grounded presence inspires confidence in those around you. Wherever you go, your unshakable steadiness sets the tone. Trust that natural leadership—it\'s one of your finest gifts.', zh: '大地能量今天坚实地支撑着你的每一步。金牛座独特的稳重存在感给周围人带来信任，无论去哪里，你不动摇的稳定性都在引领氛围。相信那种自然的领导力。', ja: '大地のエネルギーが今日あなたの足取りをしっかり支えています。牡牛座特有の芯の通った存在感が周りの人に信頼を与えるので、どこに行っても揺るがないあなたが雰囲気を引っ張ることになります。その自然なリーダーシップを信じてください。', es: 'La energía de la tierra apoya firmemente cada paso tuyo hoy, y la presencia estable de Tauro inspira confianza en quienes te rodean. Donde vayas, tu solidez inquebrantable marca el tono. Confía en ese liderazgo natural—es uno de tus mayores dones.' },
      { ko: '오랫동안 기다려온 일이 드디어 결실을 맺는 시점입니다. 서두르지 않았기에 뿌리가 깊어졌고, 그 깊은 뿌리 덕분에 열매가 더 달 수밖에 없습니다. 우주는 황소자리의 인내를 기억하고 있었고, 오늘이 그 답을 내놓는 날입니다.', en: 'What you\'ve long awaited finally bears fruit—because you didn\'t rush, the roots grew deep, and deep roots make the sweetest harvest. The universe has been keeping track of your Taurus patience, and today it delivers its answer.', zh: '等待已久的事情终于到了结果的时候。因为没有急躁，根扎得更深，深根结出的果实更甜。宇宙记得金牛座的耐心，今天是它给出答案的日子。', ja: '長い間待ち望んでいたことがついに実を結ぶ時点です。急がなかったために根が深くなり、その深い根のおかげで実がより甘くなるのです。宇宙は牡牛座の忍耐を覚えており、今日がその答えを出す日です。', es: 'Lo que has esperado tanto tiempo finalmente da frutos—porque no te apresuraste, las raíces crecieron profundo, y las raíces profundas producen la cosecha más dulce. El universo recuerda la paciencia de Tauro, y hoy entrega su respuesta.' },
      { ko: '주변에 안정감을 주는 당신의 존재 자체가 오늘 빛나고 있습니다. 함께하는 사람들이 당신 곁에서 느끼는 편안함은 황소자리만이 줄 수 있는 고유한 선물이기 때문입니다. 그 따뜻한 존재감을 오늘 더 넉넉하게 나눠보세요.', en: 'Your very presence shines today—the comfort people feel beside you is a uniquely Taurus gift that cannot be faked or rushed. Those around you feel genuinely grateful just being near you. Be generous with that warmth today.', zh: '给周围带来安定感的你的存在本身今天在闪耀。身边的人在你身边感受到的舒适是金牛座独有的礼物。今天，更加慷慨地分享那份温暖的存在感。', ja: '周りに安定感を与えるあなたの存在そのものが今日輝いています。一緒にいる人々がそばで感じる心地よさは牡牛座だけが与えられる固有の贈り物だからです。その温かい存在感を今日はより豊かに分かち合ってみてください。', es: 'Tu presencia misma brilla hoy—la comodidad que la gente siente a tu lado es un regalo único de Tauro que no puede falsificarse. Quienes te rodean sienten genuina gratitud. Sé generoso/a con esa calidez hoy.' },
      { ko: '현실적 판단력이 오늘 최고조에 달합니다. 금성과 대지의 에너지가 결합하여 당신의 감각적 직관에 날카로운 이성을 더해주기 때문에, 중요한 결정을 내리기에 이보다 더 좋은 날은 없습니다. 망설이지 말고 결단을 내리세요.', en: 'Your practical judgment peaks today—Venus and earth energy combine to add sharp rationality to your sensory intuition, making this the ideal day for important decisions. Don\'t hesitate; trust your assessment and decide with clarity.', zh: '现实判断力今天达到最高点。金星与大地能量结合，为你的感官直觉增添锐利的理性，没有比今天更适合做重要决定的日子了。不要犹豫，下定决心。', ja: '現実的な判断力が今日最高潮に達します。金星と大地のエネルギーが結合してあなたの感覚的直感に鋭い理性を加えるため、重要な決定を下すのにこれ以上ない日です。躊躇わずに決断を下してください。', es: 'Tu juicio práctico alcanza su punto máximo hoy—Venus y la energía de la tierra combinan para añadir racionalidad aguda a tu intuición sensorial, haciendo de este el día ideal para decisiones importantes. No dudes; confía en tu evaluación y decide con claridad.' },
    ],
    medium: [
      { ko: '일상의 루틴 속에서 소소한 행복을 발견하는 하루입니다. 황소자리는 평범한 반복 속에 숨겨진 풍요를 남들보다 잘 느끼는 별자리이기 때문에, 오늘의 작은 기쁨을 외면하지 마세요. 지금 눈앞의 것에 진심으로 감사하는 것이 더 큰 행복의 문을 엽니다.', en: 'Today offers small happiness woven into your daily routine—Taurus is gifted at sensing abundance hidden in ordinary repetition that others rush past. Don\'t dismiss today\'s quiet joys. Genuine gratitude for what\'s right in front of you opens the door to greater happiness.', zh: '今天是在日常中发现小幸福的一天。金牛座比其他人更善于感受平凡重复中隐藏的丰盛，不要忽视今天的小喜悦。对眼前事物的真诚感恩会打开更大幸福之门。', ja: '日常のルーティンの中で些細な幸せを見つける一日です。牡牛座は平凡な繰り返しの中に隠れた豊かさを他の人より感じ取るのが得意な星座なので、今日の小さな喜びを見逃さないでください。目の前のものに心から感謝することがより大きな幸せへの扉を開きます。', es: 'Hoy ofrece pequeñas felicidades tejidas en tu rutina diaria—Tauro tiene el don de sentir la abundancia escondida en la repetición ordinaria que otros apresuran. No desestimes las alegrías tranquilas de hoy. La gratitud genuina por lo que tienes abre la puerta a mayor felicidad.' },
      { ko: '급격한 변화보다 평소의 리듬을 유지하는 것이 오늘 당신에게 최선입니다. 대지가 계절을 급히 바꾸지 않듯, 황소자리의 힘은 꾸준한 속도에서 나옵니다. 무리한 속도전 대신 안정된 페이스를 지키는 것 자체가 오늘의 승리입니다.', en: 'Maintaining your usual rhythm beats seeking drastic change today. Just as the earth never rushes through the seasons, Taurus strength comes from steady speed. Keeping a stable pace rather than forcing a sprint is today\'s real victory.', zh: '今天保持平时的节奏比寻求急剧变化更好。就像大地不急于改变季节，金牛座的力量来自稳定的速度。保持平稳步伐而非强行冲刺本身就是今天的胜利。', ja: '急激な変化より普段のリズムを維持することが今日のあなたには最善です。大地が季節を急いで変えないように、牡牛座の力は安定したスピードから生まれます。無理な速度競争より安定したペースを守ること自体が今日の勝利です。', es: 'Mantener tu ritmo habitual supera buscar cambios drásticos hoy. Al igual que la tierra nunca apresura las estaciones, la fortaleza de Tauro viene de la velocidad constante. Mantener un paso estable en lugar de forzar un sprint es la victoria real de hoy.' },
      { ko: '금성의 에너지가 오늘 잔잔하지만 따뜻하게 흐릅니다. 강한 흐름보다 부드러운 흐름이 더 깊은 곳까지 스며들기 때문에, 오늘은 무리하지 않고 편안한 속도로 하루를 보내세요. 그 여유로움 속에서 의외의 영감이 찾아올 것입니다.', en: 'Venus\'s energy flows gently but warmly today—soft currents seep deeper than forceful ones. Move comfortably without pushing, and within that ease, unexpected inspiration will find you.', zh: '金星的能量今天平静而温暖地流动。柔和的流动比强力流动渗透得更深，今天不要勉强，舒适地度过。在那份从容中，意外的灵感将会到来。', ja: '金星のエネルギーが今日穏やかだけど温かく流れています。強い流れより柔らかな流れが深いところまで染み込むので、今日は無理せず快適なペースで一日を過ごしてください。その余裕の中で思わぬインスピレーションが訪れるでしょう。', es: 'La energía de Venus fluye suave pero cálidamente hoy—las corrientes suaves penetran más profundo que las forzadas. Muévete cómodamente sin empujar, y dentro de esa facilidad, la inspiración inesperada te encontrará.' },
      { ko: '계획한 일들이 오늘 예상대로 착실히 진행됩니다. 극적인 사건은 없지만, 황소자리에게 예측 가능한 안정은 곧 풍요의 토양이기 때문에 오늘의 든든함을 과소평가하지 마세요. 꾸준히 쌓이는 것들이 결국 가장 큰 자산이 됩니다.', en: 'Plans proceed steadily as expected today—nothing dramatic, but for Taurus, predictable stability is the very soil of abundance. Don\'t underestimate today\'s solidity. What accumulates steadily always becomes the greatest asset.', zh: '计划中的事情今天按预期稳步进行。没有戏剧性事件，但对金牛座来说，可预测的稳定就是丰盛的土壤，不要低估今天的踏实感。稳步积累的东西最终成为最大的资产。', ja: '計画したことが今日予想通りしっかり進みます。劇的なことはありませんが、牡牛座にとって予測可能な安定はすなわち豊かさの土壌なので、今日の心強さを過小評価しないでください。着実に積み重なるものが結局最大の資産になります。', es: 'Los planes avanzan firmemente según lo esperado hoy—nada dramático, pero para Tauro, la estabilidad predecible es exactamente el suelo de la abundancia. No subestimes la solidez de hoy. Lo que se acumula constantemente siempre se convierte en el mayor activo.' },
      { ko: '주변 환경을 정리하고 정돈하면 마음에도 여유가 생기는 날입니다. 황소자리는 물리적 공간과 내면 상태가 긴밀하게 연결되어 있기 때문에, 작은 청소와 정리가 예상 밖의 큰 에너지 회복을 가져옵니다. 지금 당장 공간 하나만 정리해보세요.', en: 'Organizing and tidying your surroundings brings real peace of mind today. Taurus has a tight mind-body-space connection, meaning small cleaning tasks can unexpectedly restore significant energy. Start with just one area right now.', zh: '整理周围环境，心里也会有余裕的一天。金牛座的物理空间与内心状态紧密相连，所以小小的清扫整理会带来意想不到的大能量恢复。现在就整理一个空间试试。', ja: '周りの環境を整理整頓すると心にも余裕が生まれる日です。牡牛座は物理的空間と内面状態が密接に結びついているため、小さな掃除や整理が思わぬ大きなエネルギー回復をもたらします。今すぐ一つだけ空間を整理してみてください。', es: 'Organizar y ordenar tu entorno trae verdadera paz mental hoy. Tauro tiene una conexión estrecha entre mente, cuerpo y espacio, lo que significa que pequeñas tareas de limpieza pueden restaurar energía inesperadamente. Empieza con solo un área ahora mismo.' },
      { ko: '현재의 상황을 점검하고 다음 단계를 차분히 준비하기 좋은 날입니다. 황소자리의 강점은 급하게 치고 나가는 것이 아니라 다음 수를 미리 준비하는 데 있기 때문에, 오늘의 조용한 준비가 다음 단계의 큰 성공을 만듭니다. 서두르지 말고 탄탄히 쌓아가세요.', en: 'Today is well-suited for reviewing your situation and calmly preparing next steps. Taurus strength lies not in rushing forward but in preparing the next move in advance—today\'s quiet preparation creates tomorrow\'s big success. Build solidly, without hurrying.', zh: '适合检视现状并冷静准备下一步的一天。金牛座的优势不在于急速推进，而在于提前准备下一步，今天的安静准备将创造下一阶段的大成功。不要急，稳扎稳打。', ja: '現在の状況を点検し次のステップを落ち着いて準備するのに良い日です。牡牛座の強みは急いで突き進むことではなく、次の手を前もって準備することにあるので、今日の静かな準備が次のステップの大きな成功を作り出します。急がずしっかり積み上げていきましょう。', es: 'Hoy es adecuado para revisar tu situación y preparar tranquilamente los próximos pasos. La fortaleza de Tauro no está en apresurarse sino en preparar el siguiente movimiento con anticipación—la preparación tranquila de hoy crea el gran éxito del mañana. Construye sólidamente, sin prisa.' },
      { ko: '자연 속에서 시간을 보내면 흙 원소의 에너지가 충전됩니다. 황소자리는 대지와의 연결이 특히 강하기 때문에, 짧은 산책만으로도 기분이 환하게 전환될 수 있습니다. 오늘 스트레스가 있다면 자연이 가장 빠른 해독제입니다.', en: 'Time in nature recharges your earth element energy today. Taurus has an especially strong connection to the land, so even a short walk can dramatically lift your mood. If you\'re stressed today, nature is your fastest antidote.', zh: '在大自然中度过时间可以充电土元素能量。金牛座与大地的联结特别强，即使是短暂的散步也能明显改善心情。今天如果有压力，大自然是最快的解毒剂。', ja: '自然の中で時間を過ごすと土のエレメントのエネルギーが充電されます。牡牛座は大地とのつながりが特に強いので、短い散歩だけでも気分が明るく切り替わることができます。今日ストレスがあれば自然が最も早い解毒剤です。', es: 'El tiempo en la naturaleza recarga tu energía del elemento tierra hoy. Tauro tiene una conexión especialmente fuerte con la tierra, así que incluso un paseo corto puede levantar dramáticamente tu ánimo. Si estás estresado/a hoy, la naturaleza es tu antídoto más rápido.' },
      { ko: '오늘은 새로운 도전보다 익숙한 일에 집중하는 것이 훨씬 효율적입니다. 황소자리의 강점은 깊이 있는 집중인데, 그것은 이미 알고 있는 영역에서 더 빛나기 때문입니다. 오늘 익숙한 일에서 새로운 개선점을 찾는 것이 진짜 혁신입니다.', en: 'Focusing on familiar tasks is far more efficient than new challenges today. Taurus\'s strength is deep concentration, which shines brightest in areas you already know well. Finding new improvements in familiar work—that\'s where true innovation lives for you today.', zh: '今天专注于熟悉的事情比新挑战更有效率。金牛座的优势是深度集中，这在已经熟悉的领域里更加突出。今天在熟悉的工作中找到新的改进点才是真正的创新。', ja: '今日は新しい挑戦より馴染みのあることに集中するのがはるかに効率的です。牡牛座の強みは深い集中力で、それはすでに知っている分野でより輝くからです。今日は馴染みのある仕事で新しい改善点を見つけることが本当のイノベーションです。', es: 'Enfocarte en tareas familiares es mucho más eficiente que nuevos desafíos hoy. La fortaleza de Tauro es la concentración profunda, que brilla más en áreas que ya conoces bien. Encontrar nuevas mejoras en trabajo familiar—ahí vive la verdadera innovación para ti hoy.' },
      { ko: '안정적인 기반 위에서 천천히 전진하는 중입니다. 다른 사람들이 빠르게 움직이는 것이 부러워 보일 수 있지만, 황소자리의 느린 걸음은 더 깊이 뿌리내리고 있다는 증거입니다. 조급해하지 말고 대지처럼 묵직하게 나아가세요.', en: 'You\'re advancing steadily on a solid foundation. Others moving faster may seem enviable, but Taurus\'s slower pace is evidence of deeper roots being laid. Don\'t be impatient—move forward with the weight and certainty of the earth.', zh: '在稳定的基础上慢慢前进中。其他人快速行动可能看起来令人羡慕，但金牛座较慢的步伐是在扎更深的根的证明。不要着急，像大地一样沉稳地前进。', ja: '安定した基盤の上でゆっくり前進しています。他の人が速く動いているのが羨ましく見えるかもしれませんが、牡牛座のゆっくりとした歩みはより深く根付いているという証拠です。焦らず大地のようにどっしりと進んでください。', es: 'Estás avanzando firmemente sobre una base sólida. Que otros se muevan más rápido puede parecer envidiable, pero el ritmo más lento de Tauro es evidencia de raíces más profundas. No te impacientes—avanza con el peso y la certeza de la tierra.' },
      { ko: '감각적인 즐거움을 충분히 누리세요. 좋은 음악이나 맛있는 음식이 황소자리에게 단순한 즐거움을 넘어 에너지 충전의 원천이 됩니다. 오늘 하루 자신에게 감각적 선물 하나를 주는 것이 내일을 위한 가장 현명한 투자입니다.', en: 'Enjoy sensory pleasures fully today. Good music or delicious food goes beyond simple enjoyment for Taurus—it\'s a genuine energy source. Giving yourself one sensory gift today is the wisest investment for tomorrow.', zh: '充分享受感官的乐趣。好音乐或美食对金牛座来说不仅仅是简单的享受，而是能量充电的来源。今天给自己一份感官礼物是为明天做出的最明智投资。', ja: '感覚的な楽しみを十分に味わってください。良い音楽や美味しい食事が牡牛座にとって単なる楽しみを超えてエネルギー充電の源になります。今日一日自分に感覚的な贈り物を一つあげることが明日のための最も賢い投資です。', es: 'Disfruta plenamente los placeres sensoriales hoy. La buena música o la comida deliciosa va más allá del simple disfrute para Tauro—es una fuente genuina de energía. Darte un regalo sensorial hoy es la inversión más sabia para mañana.' },
    ],
    low: [
      { ko: '오늘은 고집을 잠시 내려놓아야 할 때입니다. 황소자리의 완고함은 강점이지만, 고집이 새로운 해결책을 막고 있다면 유연함이 오히려 더 강한 전략입니다. 틀을 조금 열어두면 전혀 예상치 못한 곳에서 돌파구가 보일 것입니다.', en: 'Today calls for setting stubbornness aside for a moment. Taurus tenacity is a strength, but when it blocks new solutions, flexibility becomes the stronger strategy. Open your frame just a little—you\'ll find a breakthrough in an entirely unexpected place.', zh: '今天是暂时放下固执的时候。金牛座的顽强是优势，但如果固执阻碍了新的解决方案，灵活反而是更强的策略。稍微打开框架，你会在意想不到的地方看到突破口。', ja: '今日は頑固さをしばらく手放すべき時です。牡牛座の完固さは強みですが、頑固さが新しい解決策を阻んでいるなら柔軟さがむしろより強い戦略です。틀を少し開けておくと全く予想外のところに突破口が見えるでしょう。', es: 'Hoy pide dejar la terquedad a un lado por un momento. La tenacidad de Tauro es una fortaleza, pero cuando bloquea nuevas soluciones, la flexibilidad se convierte en la estrategia más fuerte. Abre tu marco un poco—encontrarás un avance en un lugar completamente inesperado.' },
      { ko: '변화에 저항할수록 오히려 손해가 커지는 날입니다. 황소자리는 안정을 원하지만, 때로는 작은 변화를 받아들이는 것이 더 큰 안정을 지키는 방법임을 기억하세요. 흐름을 거스르지 말고, 부드럽게 함께 움직여보세요.', en: 'Resistance to change only magnifies losses today. Taurus craves stability, but sometimes accepting small change is the way to protect greater stability. Instead of fighting the current, try moving gently with it.', zh: '越抵抗变化损失越大的一天。金牛座渴望稳定，但有时接受小变化才是保护更大稳定的方式。不要逆流而行，试着温和地随之流动。', ja: '変化に抵抗するほどかえって損害が大きくなる日です。牡牛座は安定を求めますが、時には小さな変化を受け入れることがより大きな安定を守る方法であることを覚えておいてください。流れに逆らわず、柔らかく一緒に動いてみてください。', es: 'La resistencia al cambio solo magnifica las pérdidas hoy. Tauro anhela estabilidad, pero a veces aceptar pequeños cambios es la manera de proteger mayor estabilidad. En lugar de luchar contra la corriente, intenta moverte suavemente con ella.' },
      { ko: '물질적 안정에 대한 불안이 오늘 특히 커질 수 있습니다. 그러나 황소자리의 지나친 걱정은 실제 위험보다 상상 속 위험을 더 크게 키우는 경향이 있습니다. 지금 당신이 실제로 가진 것들을 구체적으로 적어보면 불안이 한결 줄어들 것입니다.', en: 'Anxiety about material stability may spike today. But Taurus excessive worry tends to inflate imagined dangers beyond real ones. Try writing down specifically what you actually have right now—you\'ll find the anxiety eases considerably.', zh: '对物质稳定的不安今天可能特别大。但金牛座的过度担忧往往会把想象中的危险放大得比实际危险更大。具体写下你现在实际拥有的东西，不安会减轻很多。', ja: '物質的な安定への不安が今日特に大きくなる可能性があります。しかし牡牛座の過度な心配は実際の危険より想像の中の危険をより大きく育てる傾向があります。今自分が実際に持っているものを具体的に書き出してみると不安がずっと減るでしょう。', es: 'La ansiedad sobre la estabilidad material puede aumentar hoy. Pero la preocupación excesiva de Tauro tiende a inflar peligros imaginados más allá de los reales. Intenta escribir específicamente lo que realmente tienes ahora—encontrarás que la ansiedad disminuye considerablemente.' },
      { ko: '익숙한 방식만 고수하면 새로운 가능성을 놓치게 됩니다. 황소자리는 검증된 방법을 선호하지만, 오늘만큼은 한 발짝 바깥으로 나서보는 실험이 필요합니다. 완전한 변화가 아니어도 좋습니다. 작은 차이 하나가 새로운 문을 열어줄 것입니다.', en: 'Clinging only to familiar methods means missing new possibilities today. Taurus prefers proven approaches, but today calls for a small experiment outside your comfort zone. A complete overhaul isn\'t needed—just one small difference can open a new door.', zh: '只坚持熟悉的方式会错过新的可能性。金牛座偏好经过验证的方法，但今天需要迈出一步进行小小实验。不需要完全改变，一个小小的差异就能打开新的大门。', ja: '馴染みの方法だけに固執すると新しい可能性を逃します。牡牛座は検証された方法を好みますが、今日だけは一歩外に踏み出す実験が必要です。完全な変化でなくても良いです。小さな違い一つが新しい扉を開いてくれるでしょう。', es: 'Aferrarte solo a métodos familiares significa perder nuevas posibilidades hoy. Tauro prefiere enfoques probados, pero hoy pide un pequeño experimento fuera de tu zona de confort. No se necesita una revisión completa—solo una pequeña diferencia puede abrir una nueva puerta.' },
      { ko: '소유욕이 평소보다 강해지는 날입니다. 사람이나 상황을 너무 꽉 쥐고 있으면 오히려 잃게 된다는 것을 황소자리는 깊은 곳에서 알고 있습니다. 오늘은 집착을 내려놓는 연습이 가장 용감한 행동이 됩니다.', en: 'Possessiveness runs stronger than usual today. Deep down, Taurus knows that gripping too tightly—people or situations—leads to losing them. Practicing release today is the most courageous act you can take.', zh: '占有欲比平时更强的一天。金牛座内心深处知道，把人或情况握得太紧反而会失去。今天放下执着的练习是最勇敢的行为。', ja: '所有欲が普段より強くなる日です。人や状況をあまりにもきつく握っていると、かえって失うことになると牡牛座は深いところで知っています。今日は執着を手放す練習が最も勇敢な行動になります。', es: 'La posesividad es más fuerte que de costumbre hoy. En lo profundo, Tauro sabe que aferrar demasiado—personas o situaciones—lleva a perderlas. Practicar el soltar hoy es el acto más valiente que puedes tomar.' },
      { ko: '에너지가 정체된 느낌이 드는 날입니다. 황소자리는 이런 날 그냥 버티는 경향이 있지만, 작은 변화 하나가 정체된 흐름을 다시 움직이게 합니다. 일상에서 평소와 다른 작은 것 하나를 시도해보면 생각보다 큰 전환이 일어날 것입니다.', en: 'Energy feels stagnant today. Taurus tends to simply endure these days, but even one small change can get the stuck flow moving again. Try one small thing differently from usual—the shift will be bigger than you expect.', zh: '感到能量停滞的一天。金牛座在这样的日子往往只是硬撑，但一个小变化就能让停滞的流动重新启动。在日常中尝试一个与平时不同的小事，会出现比预期更大的转变。', ja: 'エネルギーが停滞した感じがする日です。牡牛座はこんな日そのまま耐える傾向がありますが、小さな変化一つが停滞した流れを再び動かします。日常で普段と違う小さなことを一つ試してみると思ったより大きな転換が起こるでしょう。', es: 'La energía se siente estancada hoy. Tauro tiende a simplemente resistir estos días, pero incluso un pequeño cambio puede volver a mover el flujo bloqueado. Intenta una cosa pequeña diferente de lo usual—el cambio será mayor de lo que esperas.' },
      { ko: '게으름에 빠지기 쉬운 날이지만, 황소자리의 안락함 추구가 오늘 적이 되고 있습니다. 작은 목표 하나라도 정해서 실행에 옮기면, 그 작은 성취가 다음 행동을 부르는 도미노가 됩니다. 지금 당장 5분이라도 시작해보세요.', en: 'Easy to fall into laziness today—Taurus\'s love of comfort is working against you now. Set even one small goal and act on it; that small achievement becomes a domino calling the next action. Start something right now, even just for 5 minutes.', zh: '容易陷入懒惰的一天，金牛座对舒适的追求今天成了敌人。哪怕设定一个小目标并付诸行动，那个小小的成就就会成为引发下一个行动的多米诺骨牌。现在就开始，哪怕只是5分钟。', ja: '怠惰に陥りやすい日ですが、牡牛座の安楽さの追求が今日は敵になっています。小さな目標一つでも定めて実行に移せば、その小さな達成が次の行動を呼ぶドミノになります。今すぐ5分だけでも始めてみてください。', es: 'Es fácil caer en la pereza hoy—el amor de Tauro por la comodidad está trabajando en tu contra ahora. Establece al menos una meta pequeña y actúa; ese pequeño logro se convierte en un dominó que llama a la siguiente acción. Comienza algo ahora mismo, aunque sea solo 5 minutos.' },
      { ko: '감정을 속으로만 삼키고 있지 않은지 오늘 점검이 필요합니다. 황소자리는 자기 감정을 쉽게 내보이지 않는 경향이 있지만, 오래 묻어두면 예상치 못한 방식으로 터져나옵니다. 신뢰하는 사람에게 솔직하게 이야기하는 것이 오늘 가장 필요한 해방입니다.', en: 'Check whether you\'re swallowing emotions today. Taurus tends not to show feelings easily, but feelings buried too long burst out unexpectedly. Talking honestly with someone you trust is the liberation you most need today.', zh: '今天需要检查自己是否在把情绪吞在心里。金牛座不容易表露感情，但长时间埋藏会以意想不到的方式爆发。今天最需要的解放就是对信任的人坦诚地说出来。', ja: '感情を内に飲み込んでいないか今日点検が必要です。牡牛座は自分の感情を簡単に表に出さない傾向がありますが、長く埋めておくと予想外の方法で爆発します。信頼する人に正直に話すことが今日最も必要な解放です。', es: 'Comprueba si estás tragándote emociones hoy. Tauro tiende a no mostrar sentimientos fácilmente, pero los sentimientos enterrados demasiado tiempo estallan inesperadamente. Hablar honestamente con alguien de confianza es la liberación que más necesitas hoy.' },
      { ko: '완벽을 추구하다 시작조차 못하는 패턴을 오늘 깨야 합니다. 황소자리의 완벽주의는 높은 기준이라는 강점이지만, 시작을 막는 장벽이 된다면 그것은 더 이상 강점이 아닙니다. "완벽하지 않아도 괜찮다"는 한마디가 오늘 당신을 앞으로 움직이게 할 것입니다.', en: 'Today you must break the pattern of perfectionism preventing you from even starting. Taurus perfectionism is a strength as high standards, but when it becomes a barrier to beginning, it\'s no longer a strength. "Not perfect is okay" are the words that will move you forward today.', zh: '今天必须打破因追求完美而连开始都没有的模式。金牛座的完美主义作为高标准是优势，但如果它成为开始的障碍，就不再是优势了。"不完美也没关系"这句话会让你今天向前迈进。', ja: '完璧を追求して始めることすらできないパターンを今日は破るべきです。牡牛座の完璧主義は高い基準という強みですが、始まりを阻む壁になるならそれはもはや強みではありません。「完璧でなくても大丈夫」という一言が今日あなたを前に動かすでしょう。', es: 'Hoy debes romper el patrón del perfeccionismo que te impide comenzar. El perfeccionismo de Tauro es una fortaleza como altos estándares, pero cuando se convierte en una barrera para empezar, ya no es una fortaleza. "No perfecto está bien" son las palabras que te moverán hacia adelante hoy.' },
      { ko: '과거에 대한 미련이 오늘 발목을 잡을 수 있습니다. 황소자리는 변화에 신중하기 때문에 지나간 것을 쉽게 놓지 못하는 경향이 있습니다. 그러나 과거는 이미 완성된 챕터이고, 다음 챕터는 앞을 봐야만 쓸 수 있습니다. 한 걸음 앞을 보는 용기를 내세요.', en: 'Lingering over the past may hold you back today. Taurus is cautious about change, making it hard to release what has passed. But the past is a completed chapter, and the next chapter can only be written by looking forward. Summon the courage to take one step ahead.', zh: '对过去的留恋今天可能拖住你。金牛座对变化谨慎，因此不容易放下过去的东西。但过去已经是完成的章节，下一章节只有向前看才能书写。鼓起勇气向前看一步。', ja: '過去への未練が今日足を引っ張る可能性があります。牡牛座は変化に慎重なため、過ぎ去ったものをなかなか手放せない傾向があります。しかし過去はすでに完成したチャプターで、次のチャプターは前を見てこそ書けます。一歩前を見る勇気を出してください。', es: 'Aferrarte al pasado puede detenerte hoy. Tauro es cauteloso con el cambio, haciendo difícil soltar lo que ha pasado. Pero el pasado es un capítulo completado, y el siguiente capítulo solo puede escribirse mirando hacia adelante. Convoca el valor para dar un paso adelante.' },
    ],
  },
  love: {
    high: [
      { ko: '금성이 오늘 사랑의 에너지를 가득 보내고 있습니다. 황소자리에게 감각적 교감은 언어보다 더 깊은 소통이기 때문에, 오늘은 함께하는 시간의 질을 높이는 것이 관계를 비약적으로 깊게 만들 것입니다. 오감으로 상대방을 느끼는 하루를 보내세요.', en: 'Venus floods you with love energy today. For Taurus, sensory connection is deeper communication than words—so raising the quality of shared time will deepen the relationship dramatically. Let today be a day you experience your partner through all five senses.', zh: '金星今天给你送来满满的爱情能量。对金牛座来说，感官交流比语言更深层，提升共处时光的质量将大幅加深关系。今天用五感去感受对方。', ja: '金星が今日愛のエネルギーをたっぷり送っています。牡牛座にとって感覚的な交流は言葉より深いコミュニケーションなので、今日は一緒に過ごす時間の質を高めることが関係を飛躍的に深めるでしょう。五感で相手を感じる一日を過ごしてください。', es: 'Venus te inunda con energía de amor hoy. Para Tauro, la conexión sensorial es comunicación más profunda que las palabras—así que elevar la calidad del tiempo compartido profundizará la relación dramáticamente. Haz que hoy sea un día en que experimentes a tu pareja con los cinco sentidos.' },
      { ko: '당신의 변치 않는 진심이 오늘 상대방의 마음속에 깊이 전해집니다. 화려한 표현보다 꾸준한 사랑이 더 강력한 이유는, 황소자리의 헌신이 시간이 갈수록 더 빛나기 때문입니다. 오늘 그 꾸준함을 있는 그대로 보여주세요.', en: 'Your unchanging sincerity penetrates deeply into your partner\'s heart today. Steadfast love is more powerful than flashy expression because Taurus devotion only shines brighter with time. Let today show that steadiness just as it is—unpolished and true.', zh: '你不变的真心今天深深地传达到对方内心。持续的爱比华丽的表达更有力，因为金牛座的奉献随着时间越来越闪亮。今天就展示那份坚持，真实而不加修饰。', ja: 'あなたの変わらない真心が今日相手の心の中に深く伝わります。華やかな表現より着実な愛がより強力な理由は、牡牛座の献身が時間が経つほどより輝くからです。今日はその着実さをそのまま見せてください。', es: 'Tu sinceridad inquebrantable penetra profundamente en el corazón de tu pareja hoy. El amor constante es más poderoso que la expresión llamativa porque la devoción de Tauro solo brilla más con el tiempo. Deja que hoy muestre esa constancia tal como es—sin pulir y verdadera.' },
      { ko: '감각적인 데이트를 오늘 계획해보세요. 황소자리는 오감으로 나누는 경험에서 가장 깊은 연결감을 느끼기 때문에, 좋은 음식을 함께 먹거나 아름다운 장소를 산책하는 것이 어떤 대화보다 관계를 깊게 만들 것입니다. 오늘의 데이트는 기억에 남을 것입니다.', en: 'Plan a sensory date today. Taurus feels the deepest connection through shared experiences engaging all five senses—enjoying good food together or walking a beautiful place will deepen the relationship more than any conversation. Tonight\'s date will be memorable.', zh: '今天计划一个感官约会。金牛座在通过五感分享的体验中感受最深的联结，一起享用美食或在美丽的地方散步，比任何对话都更能加深关系。今天的约会将令人难忘。', ja: '感覚的なデートを今日計画してみてください。牡牛座は五感で分かち合う体験から最も深いつながりを感じるため、美味しい食事を一緒に食べたり美しい場所を散歩することがどんな会話より関係を深めるでしょう。今日のデートは記憶に残るものになります。', es: 'Planea una cita sensorial hoy. Tauro siente la conexión más profunda a través de experiencias compartidas que involucran los cinco sentidos—disfrutar buena comida juntos o caminar por un lugar hermoso profundizará la relación más que cualquier conversación. La cita de hoy será memorable.' },
      { ko: '솔로라면 오늘 안정감 있는 당신만의 매력이 환하게 빛납니다. 황소자리의 편안하면서도 단단한 존재감은 상대방에게 깊은 안도감을 주는 희귀한 매력이기 때문입니다. 자연스러운 만남에 마음을 열어두면 인연이 가까이 있을 것입니다.', en: 'If single, your uniquely grounding charm shines brightly today. Taurus\'s comfortable yet solid presence gives others a rare sense of deep reassurance that is genuinely attractive. Keep your heart open to natural encounters—the connection you seek may be close.', zh: '如果单身，今天你独特的稳重魅力明亮地闪耀。金牛座舒适而坚实的存在感给对方带来深深的安慰感，这是罕见的魅力。向自然的相遇敞开心扉，缘分可能就在附近。', ja: 'シングルなら今日安定感のあるあなただけの魅力が明るく輝きます。牡牛座の心地よくも揺るぎない存在感は相手に深い安堵感を与える稀な魅力だからです。自然な出会いに心を開いておけば縁が近くにあるでしょう。', es: 'Si estás soltero/a, tu encanto único y estabilizador brilla intensamente hoy. La presencia cómoda pero sólida de Tauro da a otros una rara sensación de profunda tranquilidad que es genuinamente atractiva. Mantén tu corazón abierto a encuentros naturales—la conexión que buscas puede estar cerca.' },
      { ko: '오래된 관계에 오늘 새로운 활력이 싹트고 있습니다. 반복되는 일상이 권태로 느껴질 때, 황소자리의 감각적 센스로 작은 특별함을 만들어내는 것이 관계를 환기시키는 가장 빠른 방법입니다. 작은 선물이나 손편지 하나가 상대방의 마음에 오래 남을 것입니다.', en: 'New vitality is sprouting in your long-term relationship today. When routine feels dull, Taurus\'s sensory creativity is the fastest way to refresh things—a small gift or handwritten note will linger in your partner\'s heart far longer than you expect.', zh: '旧关系今天萌生了新的活力。当日常感到无聊时，金牛座的感官创意是最快刷新关系的方式。一个小礼物或手写的信会在对方心中留存很久，超出你的预期。', ja: '長い関係に今日新しい活力が芽生えています。繰り返しの日常が倦怠に感じられる時、牡牛座の感覚的なセンスで小さな特別さを作り出すことが関係を換気する最も早い方法です。小さなプレゼントや手紙一つが相手の心に長く残るでしょう。', es: 'Nueva vitalidad brota en tu relación duradera hoy. Cuando la rutina se siente aburrida, la creatividad sensorial de Tauro es la manera más rápida de refrescar las cosas—un pequeño regalo o nota escrita a mano permanecerá en el corazón de tu pareja mucho más de lo que esperas.' },
      { ko: '함께 요리를 하거나 예술을 감상하면 금성 에너지가 극대화됩니다. 황소자리에게 함께 만들고 함께 느끼는 공동 체험은 말로 채울 수 없는 친밀감을 쌓아주기 때문입니다. 오늘 하나의 공동 창조 경험이 두 사람의 연결을 훨씬 깊게 만들어줄 것입니다.', en: 'Cooking together or enjoying art maximizes Venus energy today. Shared creation and shared feeling build an intimacy that words cannot fill for Taurus. One co-creative experience today will deepen your connection far beyond what conversation alone could achieve.', zh: '一起做饭或欣赏艺术可以最大化金星能量。对金牛座来说，共同创造和共同感受的体验建立了语言无法填补的亲密感。今天的一次共同创造体验将使两人的联结比仅仅对话深得多。', ja: '一緒に料理をしたり芸術を鑑賞すると金星エネルギーが最大化されます。牡牛座にとって一緒に作り一緒に感じる共同体験は言葉で埋めることのできない親密さを積み上げてくれるからです。今日一つの共同創造体験が二人のつながりをずっと深めてくれるでしょう。', es: 'Cocinar juntos o disfrutar del arte maximiza la energía de Venus hoy. La creación compartida y el sentir compartido construyen una intimidad que las palabras no pueden llenar para Tauro. Una experiencia co-creativa hoy profundizará tu conexión mucho más allá de lo que la conversación sola podría lograr.' },
      { ko: '진심 어린 헌신이 오늘 상대방의 마음을 깊게 움직입니다. 황소자리의 사랑은 말보다 행동으로 쌓이는 것이기 때문에, 오늘 보여주는 작은 배려 하나하나가 상대방의 신뢰를 더욱 단단하게 합니다. 사랑을 증명하는 것은 행동으로 충분합니다.', en: 'Heartfelt devotion moves your partner deeply today. Taurus love accumulates through actions rather than words—so every small act of care you show today further solidifies their trust. Actions are more than enough to prove love.', zh: '真诚的奉献今天深深打动对方。金牛座的爱通过行动而非言语积累，今天展示的每一个小小关怀都会进一步巩固对方的信任。用行动证明爱就已经足够了。', ja: '心からの献身が今日相手の心を深く動かします。牡牛座の愛は言葉より行動で積み上がるものなので、今日見せる小さな気遣い一つ一つが相手の信頼をさらに固めます。愛を証明するのは行動で十分です。', es: 'La devoción sincera mueve profundamente a tu pareja hoy. El amor de Tauro se acumula a través de acciones más que de palabras—así que cada pequeño acto de cuidado que muestras hoy solidifica aún más su confianza. Las acciones son más que suficientes para probar el amor.' },
      { ko: '스킨십이 오늘 특히 효과적인 날입니다. 황소자리는 촉각을 통해 가장 깊은 안정감을 느끼고 전달하기 때문에, 따뜻한 손잡기나 포옹이 천 마디의 말보다 훨씬 더 많은 것을 전할 수 있습니다. 오늘은 말 대신 온기를 나누세요.', en: 'Physical affection is especially powerful today. Taurus feels and transmits the deepest reassurance through touch—a warm hand-hold or hug conveys far more than a thousand words ever could. Today, share warmth instead of words.', zh: '肢体接触今天特别有效。金牛座通过触觉感受和传递最深的安定感，温暖的牵手或拥抱能传达的远超千言万语。今天，用温暖代替言语。', ja: 'スキンシップが今日特に効果的な日です。牡牛座は触覚を通して最も深い安定感を感じて伝えるため、温かい手つなぎやハグが千の言葉よりずっと多くのことを伝えられます。今日は言葉の代わりに温かさを分かち合ってください。', es: 'El contacto físico es especialmente poderoso hoy. Tauro siente y transmite la tranquilidad más profunda a través del tacto—un apretón de manos cálido o un abrazo transmite mucho más de lo que mil palabras jamás podrían. Hoy, comparte calidez en vez de palabras.' },
      { ko: '관계의 기반이 더욱 튼튼해지는 시기입니다. 황소자리에게 미래를 함께 설계하는 대화는 가장 깊은 친밀함의 표현이기 때문에, 서로의 꿈과 계획을 나누는 것이 오늘 관계를 한 단계 더 성숙하게 만들 것입니다. 진지하지만 따뜻하게 이야기해보세요.', en: 'The foundation of your relationship grows stronger now. For Taurus, designing the future together is the deepest expression of intimacy—sharing your dreams and plans will mature the relationship by one more level today. Talk seriously but warmly.', zh: '关系的基础变得更加坚固。对金牛座来说，共同规划未来是最深层亲密的表达，分享彼此的梦想和计划将使关系今天更加成熟一步。认真但温暖地谈谈。', ja: '関係の基盤がさらに強くなる時期です。牡牛座にとって未来を一緒に設計する会話は最も深い親密さの表現なので、お互いの夢と計画を分かち合うことが今日関係をもう一段階成熟させるでしょう。真剣だけど温かく話してみてください。', es: 'La base de tu relación crece más fuerte ahora. Para Tauro, diseñar el futuro juntos es la expresión más profunda de intimidad—compartir tus sueños y planes madurará la relación un nivel más hoy. Hablen seria pero cálidamente.' },
      { ko: '당신의 충실함과 따뜻함이 오늘 최고의 매력으로 빛납니다. 황소자리의 사랑은 꾸밈이 없이 진실하기 때문에, 있는 그대로의 모습이 곧 가장 강력한 매력입니다. 오늘 자신을 꾸미거나 변장할 필요가 없습니다. 그냥 당신이면 됩니다.', en: 'Your loyalty and warmth shine as your greatest attraction today. Taurus love is unadorned and true—your natural self is your most powerful charm. No need to dress up or perform today. Just being you is exactly enough.', zh: '你的忠诚和温暖今天作为最大魅力闪耀。金牛座的爱朴实而真诚，真实的你就是最强的魅力。今天不需要打扮或伪装，就是你自己就够了。', ja: 'あなたの忠実さと温かさが今日最高の魅力として輝きます。牡牛座の愛は飾り気がなく真実なので、ありのままの姿がすなわち最も強力な魅力です。今日自分を飾ったり変装する必要はありません。ただあなたであるだけで十分です。', es: 'Tu lealtad y calidez brillan como tu mayor atracción hoy. El amor de Tauro es sin adornos y verdadero—tu yo natural es tu encanto más poderoso. No hay necesidad de arreglarse o actuar hoy. Solo siendo tú es exactamente suficiente.' },
    ],
    medium: [
      { ko: '안정적인 관계가 유지되는 하루입니다. 황소자리의 사랑은 극적인 사건보다 일상의 작은 배려가 쌓여 완성되기 때문에, 오늘의 평범한 하루가 사실 관계에서 가장 중요한 날일 수 있습니다. 작은 것 하나에 진심을 담아보세요.', en: 'A stable relationship is maintained today. Taurus love is completed by small daily gestures stacking up rather than dramatic events—so today\'s ordinary day may actually be the most important one for your relationship. Put genuine heart into one small thing.', zh: '稳定的关系维持的一天。金牛座的爱由日常小关怀的积累完成，而非戏剧性事件，所以今天平凡的一天实际上可能是关系中最重要的一天。在小事上倾注真心。', ja: '安定した関係が維持される一日です。牡牛座の愛は劇的なことより日常の小さな気遣いが積み重なって完成されるので、今日の平凡な一日が実は関係で最も大事な日かもしれません。小さなことに真心を込めてみてください。', es: 'Una relación estable se mantiene hoy. El amor de Tauro se completa por pequeños gestos diarios que se acumulan más que por eventos dramáticos—así que el día ordinario de hoy puede ser en realidad el más importante para tu relación. Pon corazón genuino en una pequeña cosa.' },
      { ko: '서두르지 말고 관계를 천천히 깊게 가꾸세요. 황소자리의 사랑은 숙성될수록 더 향기롭기 때문에, 인위적으로 빠르게 진전시키려 할 필요가 없습니다. 지금 이 속도가 두 사람에게 최적의 속도입니다.', en: 'Don\'t rush—nurture your relationship slowly and deeply. Taurus love becomes more fragrant as it matures, so there\'s no need to artificially accelerate it. The current pace is the optimal pace for both of you.', zh: '不要着急，慢慢深入培养关系。金牛座的爱越成熟越香，没有必要人为地快速推进。现在的速度就是两个人的最佳速度。', ja: '焦らず関係をゆっくり深く育ててください。牡牛座の愛は熟成するほどより香しくなるので、人為的に速く進めようとする必要はありません。今のこのスピードが二人にとって最適のスピードです。', es: 'No te apresures—cultiva la relación lentamente y profundamente. El amor de Tauro se vuelve más fragante al madurar, así que no hay necesidad de acelerarlo artificialmente. El ritmo actual es el ritmo óptimo para ambos.' },
      { ko: '상대방의 공간을 존중하면서도 따뜻한 존재감을 보여주는 균형이 필요합니다. 황소자리는 가까워지고 싶은 욕구가 강하지만, 적당한 거리감이 오히려 상대방이 당신에게 돌아오게 만드는 마법입니다. 오늘은 넉넉하게 공간을 내주세요.', en: 'Balance is needed: respect their space while still showing warm presence. Taurus has strong desire to be close, but appropriate distance is actually the magic that makes them come back to you. Today, give space generously.', zh: '需要平衡：在尊重对方空间的同时展示温暖的存在感。金牛座想亲近的欲望很强，但适当的距离感反而是让对方回到你身边的魔法。今天，慷慨地给对方空间。', ja: '相手の空間を尊重しながらも温かい存在感を示すバランスが必要です。牡牛座は近づきたい欲求が強いですが、適度な距離感がむしろ相手があなたのところに戻ってくる魔法です。今日は余裕を持って空間を与えてください。', es: 'Se necesita equilibrio: respetar su espacio mientras se muestra presencia cálida. Tauro tiene fuerte deseo de estar cerca, pero la distancia apropiada es en realidad la magia que hace que regresen a ti. Hoy, da espacio generosamente.' },
      { ko: '연인과 함께하는 식사가 오늘 관계에 특별한 활력을 줍니다. 황소자리에게 음식을 함께 나누는 것은 단순한 식사가 아니라 깊은 돌봄의 표현이기 때문입니다. 오늘 맛있는 것을 정성껏 함께 나누며 그 따뜻함을 느껴보세요.', en: 'Sharing a meal with your partner brings special vitality to the relationship today. For Taurus, sharing food is not mere eating but deep expression of care. Today, share something delicious with sincerity and savor that warmth together.', zh: '与恋人一起用餐今天给关系带来特别的活力。对金牛座来说，共享食物不仅仅是用餐，而是深深关怀的表达。今天，精心地一起分享美食，感受那份温暖。', ja: '恋人と一緒の食事が今日関係に特別な活力を与えます。牡牛座にとって食事を一緒に分かち合うことは単なる食事ではなく深い気遣いの表現だからです。今日は美味しいものを心を込めて一緒に分かち合いその温かさを感じてみてください。', es: 'Compartir una comida con tu pareja aporta vitalidad especial a la relación hoy. Para Tauro, compartir comida no es mera alimentación sino profunda expresión de cuidado. Hoy, comparte algo delicioso con sinceridad y saboreen esa calidez juntos.' },
      { ko: '감정을 말로 표현하는 연습이 필요한 시기입니다. 황소자리는 행동으로 표현하는 것이 자연스럽지만, 상대방은 가끔 말을 통한 확인도 필요합니다. 오늘 속마음을 조금씩 꺼내는 연습이 관계를 더 단단하게 만들 것입니다.', en: 'It\'s time to practice expressing emotions verbally. Taurus naturally expresses through action, but your partner sometimes also needs verbal confirmation. Practicing to share inner feelings little by little today will make the relationship more solid.', zh: '需要练习用语言表达情感。金牛座自然地通过行动表达，但对方有时也需要语言确认。今天练习一点一点说出心里话，会让关系更加稳固。', ja: '感情を言葉で表現する練習が必要な時期です。牡牛座は行動で表現するのが自然ですが、相手は時々言葉による確認も必要です。今日は心の内を少しずつ出す練習が関係をより固くするでしょう。', es: 'Es hora de practicar expresar emociones verbalmente. Tauro naturalmente expresa a través de acciones, pero tu pareja a veces también necesita confirmación verbal. Practicar compartir sentimientos internos poco a poco hoy hará la relación más sólida.' },
      { ko: '편안하고 안전한 관계가 오늘도 유지됩니다. 황소자리가 쌓아온 신뢰의 기반이 두 사람을 든든하게 받쳐주고 있기 때문입니다. 지금의 따뜻함을 당연하게 여기지 말고, 오늘 그 감사함을 표현해보세요.', en: 'A comfortable and safe relationship continues today. The foundation of trust Taurus has built firmly supports both of you. Don\'t take this warmth for granted—express that gratitude today.', zh: '舒适安全的关系今天继续维持。金牛座建立的信任基础坚实地支撑着两个人。不要把现在的温暖视为理所当然，今天表达那份感恩。', ja: '快適で安全な関係が今日も維持されます。牡牛座が積み上げてきた信頼の基盤が二人をしっかり支えているからです。今の温かさを当たり前に思わず、今日その感謝を表現してみてください。', es: 'Una relación cómoda y segura continúa hoy. La base de confianza que Tauro ha construido sostiene firmemente a ambos. No des esta calidez por sentada—expresa esa gratitud hoy.' },
      { ko: '솔로라면 자연스러운 만남을 기대하되 조급해하지 마세요. 황소자리의 사랑은 갑자기 피는 꽃이 아니라 천천히 익는 열매이기 때문에, 준비된 상태에서 찾아오는 인연이 가장 오래 갑니다. 지금은 자신을 더 풍요롭게 가꾸는 시간입니다.', en: 'If single, expect natural encounters but don\'t rush. Taurus love isn\'t a flower that blooms suddenly but fruit that ripens slowly—the connection that comes when you\'re ready lasts the longest. Right now is time to cultivate yourself more richly.', zh: '如果单身，期待自然的相遇但不要着急。金牛座的爱不是突然盛开的花，而是慢慢成熟的果实，在准备好的时候到来的缘分持续最长。现在是让自己更加丰富成长的时间。', ja: 'シングルなら自然な出会いを期待しつつ焦らないでください。牡牛座の愛は突然咲く花ではなくゆっくり熟する実なので、準備ができた状態で訪れる縁が最も長く続きます。今は自分をより豊かに育てる時間です。', es: 'Si estás soltero/a, espera encuentros naturales pero sin prisa. El amor de Tauro no es una flor que florece de repente sino fruto que madura lentamente—la conexión que llega cuando estás listo/a dura más. Ahora es tiempo de cultivarte a ti mismo/a más ricamente.' },
      { ko: '물질적 선물도 좋지만, 오늘은 함께 시간을 보내는 것이 더 깊은 선물이 됩니다. 황소자리에게 진정한 풍요는 물건이 아니라 함께하는 순간의 충만함에서 옵니다. 오늘 상대방과 함께 온전히 존재하는 시간을 만들어보세요.', en: 'Material gifts are nice, but spending time together is the deeper gift today. For Taurus, true abundance comes not from things but from the fullness of shared moments. Create time today to be fully present with your partner.', zh: '物质礼物也好，但今天一起度过的时间是更深的礼物。对金牛座来说，真正的丰盛不来自物品，而来自共同时刻的充实感。今天创造与对方完全在场的时间。', ja: '物質的な贈り物も良いですが、今日は一緒に時間を過ごすことがより深い贈り物になります。牡牛座にとって真の豊かさはものではなく一緒にいる瞬間の充実感から来ます。今日は相手と共に完全に存在する時間を作ってみてください。', es: 'Los regalos materiales están bien, pero pasar tiempo juntos es el regalo más profundo hoy. Para Tauro, la abundancia verdadera no viene de las cosas sino de la plenitud de los momentos compartidos. Crea tiempo hoy para estar completamente presente con tu pareja.' },
      { ko: '평소 표현하지 못했던 감사의 마음을 오늘 전해보세요. 황소자리는 감사함을 느끼지만 말로 표현하는 것이 어색할 수 있습니다. 하지만 그 한마디가 상대방의 하루를 완전히 바꿔놓을 수 있기 때문에, 오늘 용기를 내보세요.', en: 'Express gratitude you haven\'t shown before today. Taurus feels gratitude but may feel awkward putting it into words. Yet that one sentence can completely change your partner\'s day—summon the courage today.', zh: '今天传达平时没有表达的感恩之心。金牛座有感恩之情但可能觉得用言语表达很别扭。然而那一句话可能完全改变对方的一天，今天鼓起勇气吧。', ja: '普段表現できなかった感謝の気持ちを今日伝えてみてください。牡牛座は感謝を感じますが言葉で表現するのが気恥ずかしいかもしれません。しかしその一言が相手の一日を完全に変えることができるので、今日は勇気を出してみてください。', es: 'Expresa gratitud que no has mostrado antes hoy. Tauro siente gratitud pero puede sentirse incómodo/a expresándola con palabras. Sin embargo, esa oración puede cambiar completamente el día de tu pareja—convoca el valor hoy.' },
      { ko: '파트너의 작은 변화를 오늘 알아채고 반응해주세요. 황소자리의 섬세한 감각이 상대방의 미세한 변화를 읽어낼 수 있기 때문에, 그것을 알아채고 말해주는 것이 상대방에게 깊이 배려받는 느낌을 줄 것입니다. 오늘 상대방을 더 세심하게 관찰해보세요.', en: 'Notice and respond to your partner\'s small changes today. Taurus\'s refined senses can read subtle shifts in them—acknowledging those changes out loud gives your partner the deep feeling of being truly cared for. Observe your partner more attentively today.', zh: '今天注意到伴侣的小变化并回应。金牛座细腻的感官能读出对方微细的变化，注意到并说出来会让对方感到被深深关怀。今天更细心地观察对方。', ja: 'パートナーの小さな変化を今日気づいて反応してあげてください。牡牛座の繊細な感覚が相手の微細な変化を読み取れるので、それに気づいて言葉にすることが相手に深く気遣われている感覚を与えるでしょう。今日は相手をより注意深く観察してみてください。', es: 'Nota y responde a los pequeños cambios de tu pareja hoy. Los sentidos refinados de Tauro pueden leer cambios sutiles en ellos—reconocer esos cambios en voz alta le da a tu pareja la profunda sensación de ser verdaderamente cuidado/a. Observa a tu pareja más atentamente hoy.' },
    ],
    low: [
      { ko: '소유욕이 과도해지지 않도록 오늘 경계가 필요합니다. 사랑하는 사람을 꽉 쥐고 있으면 결국 손 안의 모래처럼 빠져나간다는 것을 황소자리는 알고 있을 것입니다. 오늘은 쥐는 대신 열린 손으로 상대방을 품어보세요.', en: 'Guard against excessive possessiveness today. You know that gripping someone too tightly makes them slip away like sand in a fist. Today, try holding your partner with an open hand instead of a clenched one.', zh: '今天需要警惕占有欲过度。你知道把爱人握得太紧最终会像手中的沙一样流走。今天试着用张开的手而不是握紧的拳头来容纳对方。', ja: '所有欲が過度にならないよう今日は警戒が必要です。愛する人をぎゅっと握っていると結局手の中の砂のように抜け出ていくことを牡牛座は知っているでしょう。今日は握る代わりに開いた手で相手を包んでみてください。', es: 'Cuídate de la posesividad excesiva hoy. Sabes que apretar demasiado a alguien los hace escapar como arena en un puño. Hoy, intenta sostener a tu pareja con una mano abierta en lugar de cerrada.' },
      { ko: '질투심을 다스려야 할 때입니다. 황소자리의 질투는 깊은 사랑에서 오는 것이지만, 지나치면 상대방을 숨막히게 합니다. 신뢰를 기반으로 한 여유가 오히려 상대방을 당신 곁에 더 오래 머물게 하는 가장 강력한 사랑의 방식입니다.', en: 'Time to manage jealousy. Taurus jealousy comes from deep love, but in excess it suffocates your partner. Ease rooted in trust is actually the most powerful way to keep someone close to you longest.', zh: '是控制嫉妒心的时候了。金牛座的嫉妒来自深深的爱，但过度则会让对方窒息。基于信任的从容反而是让对方在你身边停留最久的最有力的爱的方式。', ja: '嫉妬心をコントロールすべき時です。牡牛座の嫉妬は深い愛から来るものですが、過ぎると相手を息苦しくさせます。信頼に基づいたゆとりがむしろ相手をあなたのそばに最も長く留まらせる最も強力な愛の方法です。', es: 'Es hora de manejar los celos. Los celos de Tauro vienen del amor profundo, pero en exceso ahogan a tu pareja. La calma arraigada en la confianza es en realidad la manera más poderosa de mantener a alguien cerca por más tiempo.' },
      { ko: '고집으로 인한 갈등이 예상되는 하루입니다. 황소자리는 자신이 옳다고 믿는 것에 강하게 집착하지만, 관계에서 이기는 것보다 함께 더 나은 답을 찾는 것이 훨씬 중요합니다. 오늘 상대의 의견에 진심으로 귀를 기울여보세요.', en: 'Conflict from stubbornness is expected today. Taurus strongly clings to what it believes is right, but in relationships, finding a better answer together matters far more than winning. Genuinely listen to your partner\'s opinion today.', zh: '预计今天会因固执产生冲突。金牛座强烈执着于自己认为正确的事，但在关系中，一起找到更好的答案远比赢得争论重要。今天真诚地倾听对方的意见。', ja: '頑固さによる葛藤が予想される一日です。牡牛座は自分が正しいと信じることに強く執着しますが、関係においては勝つことより一緒により良い答えを見つけることがずっと重要です。今日は相手の意見に真心から耳を傾けてみてください。', es: 'Se esperan conflictos por terquedad hoy. Tauro se aferra fuertemente a lo que cree correcto, pero en las relaciones, encontrar una mejor respuesta juntos importa mucho más que ganar. Escucha genuinamente la opinión de tu pareja hoy.' },
      { ko: '감정 표현을 미루면 오해가 쌓이고 깊어집니다. 황소자리는 말보다 행동을 선호하지만, 상대방은 "왜 아무 말도 없지?"라고 오해할 수 있습니다. 오늘 솔직하게 한마디를 꺼내는 것이 쌓인 거리를 한번에 좁혀줄 것입니다.', en: 'Delaying emotional expression piles up and deepens misunderstandings. Taurus prefers action over words, but your partner may wonder "Why nothing said?" Today, one honest sentence will instantly close accumulated distance.', zh: '推迟表达情感会积累并加深误解。金牛座偏好行动而非言语，但对方可能会误解"为什么一句话都没说？"。今天坦诚地说一句话，会一下子缩短积累的距离。', ja: '感情表現を先延ばしにすると誤解が積み重なり深まります。牡牛座は言葉より行動を好みますが、相手は「なぜ何も言わないの？」と誤解するかもしれません。今日正直に一言を出すことが積み重なった距離を一度に縮めてくれるでしょう。', es: 'Retrasar la expresión emocional acumula y profundiza los malentendidos. Tauro prefiere acciones sobre palabras, pero tu pareja puede preguntarse "¿Por qué no dice nada?" Hoy, una oración honesta cerrará instantáneamente la distancia acumulada.' },
      { ko: '물질적 조건으로 상대를 판단하고 있지 않은지 오늘 돌아봐야 합니다. 황소자리는 현실적 안정을 중요시하지만, 사람의 가치는 숫자로 환산될 수 없습니다. 오늘 상대방이 가진 눈에 보이지 않는 가치들을 발견해보세요.', en: 'Reflect today on whether you\'re judging your partner by material standards. Taurus values practical stability, but a person\'s worth cannot be converted to numbers. Today, discover the invisible values your partner holds.', zh: '今天要回顾一下是否在用物质条件评判对方。金牛座重视现实稳定，但人的价值无法用数字换算。今天发现对方拥有的那些看不见的价值。', ja: '物質的な条件で相手を判断していないか今日振り返る必要があります。牡牛座は現実的な安定を重視しますが、人の価値は数字に換算できません。今日は相手が持っている目に見えない価値たちを発見してみてください。', es: 'Reflexiona hoy sobre si estás juzgando a tu pareja por condiciones materiales. Tauro valora la estabilidad práctica, pero el valor de una persona no puede convertirse en números. Hoy, descubre los valores invisibles que tiene tu pareja.' },
      { ko: '변화를 거부하면 관계가 정체되고 서서히 시들 수 있습니다. 황소자리의 안정 추구는 아름답지만, 함께 성장하지 않는 관계는 결국 한쪽이 답답해집니다. 오늘 새로운 시도 하나가 관계에 신선한 바람을 불어넣을 것입니다.', en: 'Refusing change can stagnate and slowly wither the relationship. Taurus\'s pursuit of stability is beautiful, but a relationship that doesn\'t grow together eventually feels suffocating for one side. One new attempt today will breathe fresh air into the relationship.', zh: '拒绝变化会让关系停滞并慢慢枯萎。金牛座追求稳定是美好的，但不一起成长的关系最终会让一方感到憋闷。今天一个新的尝试将给关系注入新鲜空气。', ja: '変化を拒否すると関係が停滞し徐々にしぼんでいく可能性があります。牡牛座の安定追求は美しいですが、一緒に成長しない関係は結局一方が息苦しくなります。今日新しい試み一つが関係に新鮮な風を吹き込むでしょう。', es: 'Rechazar el cambio puede estancar y marchitar lentamente la relación. La búsqueda de estabilidad de Tauro es hermosa, pero una relación que no crece juntos eventualmente se siente sofocante para un lado. Un nuevo intento hoy respirará aire fresco en la relación.' },
      { ko: '과거 연인에 대한 미련이 현재 관계를 방해하고 있지 않은지 확인하세요. 황소자리는 변화가 느려 과거를 오래 붙잡는 경향이 있지만, 어제의 연인에게 준 자리는 오늘의 관계를 위해 비워두어야 합니다. 지금 이 순간에 완전히 집중하세요.', en: 'Check whether lingering feelings for an ex are interfering with your current relationship. Taurus changes slowly and tends to hold the past long, but the place you gave to yesterday\'s lover must be cleared for today\'s relationship. Focus completely on this moment now.', zh: '检查对前任的留恋是否在妨碍现在的关系。金牛座变化缓慢，倾向于长时间抓住过去，但给过去恋人的位置需要为今天的关系清空。完全专注于现在这一刻。', ja: '過去の恋人への未練が現在の関係を妨げていないか確認してください。牡牛座は変化が遅く過去を長く握り続ける傾向がありますが、昨日の恋人に与えた場所は今日の関係のために空けておかなければなりません。今この瞬間に完全に集中してください。', es: 'Verifica si los sentimientos persistentes por un ex están interfiriendo con tu relación actual. Tauro cambia lentamente y tiende a aferrarse al pasado por mucho tiempo, pero el lugar que le diste al amante de ayer debe despejarse para la relación de hoy. Enfócate completamente en este momento ahora.' },
      { ko: '상대의 자유를 존중하는 것이 오늘 특히 중요합니다. 황소자리의 집착은 사랑에서 비롯되지만, 과도한 확인과 통제는 상대방이 숨 막혀 도망치게 만듭니다. 오늘은 한 발 뒤에서 믿고 기다리는 것이 가장 큰 사랑의 표현입니다.', en: 'Respecting your partner\'s freedom is especially important today. Taurus attachment comes from love, but excessive checking and control makes your partner feel suffocated and want to flee. Today, stepping back and trusting is the greatest expression of love.', zh: '今天特别重要的是尊重对方的自由。金牛座的执着来自爱，但过度的确认和控制让对方感到窒息想要逃跑。今天退一步信任和等待是最大的爱的表达。', ja: '相手の自由を尊重することが今日特に重要です。牡牛座の執着は愛から来ていますが、過度な確認とコントロールは相手が息苦しくなって逃げ出したくなります。今日は一歩引いて信じて待つことが最も大きな愛の表現です。', es: 'Respetar la libertad de tu pareja es especialmente importante hoy. El apego de Tauro viene del amor, pero el control y chequeo excesivos hace que tu pareja se sienta sofocada y quiera huir. Hoy, dar un paso atrás y confiar es la mayor expresión de amor.' },
      { ko: '감정을 삼키고 있으면 언젠가 예상치 못한 순간에 한꺼번에 폭발합니다. 황소자리는 참는 것이 미덕이라고 배워왔을 수 있지만, 작은 불만도 그때그때 가볍게 대화하는 것이 대폭발을 막는 가장 현명한 예방법입니다. 오늘 하나만 꺼내보세요.', en: 'Bottling up emotions will eventually explode at an unexpected moment. Taurus may have learned that enduring is virtue, but addressing even small complaints through gentle conversation is the wisest prevention against a major explosion. Today, open up just one thing.', zh: '吞下情绪总有一天会在意想不到的时刻一下子爆发。金牛座可能被教导忍耐是美德，但对小小的不满也通过轻松的对话及时沟通，是防止大爆发最明智的预防方式。今天就说出一件事。', ja: '感情を飲み込んでいるといつか予想外の瞬間に一度に爆発します。牡牛座は耐えることが美徳だと学んできたかもしれませんが、小さな不満もその都度軽く話し合うことが大爆発を防ぐ最も賢い予防法です。今日は一つだけ出してみてください。', es: 'Reprimir emociones eventualmente explotará en un momento inesperado. Tauro puede haber aprendido que resistir es virtud, pero abordar incluso pequeñas quejas a través de conversación gentil es la prevención más sabia contra una gran explosión. Hoy, abre solo una cosa.' },
      { ko: '안정에 대한 불안이 관계를 오늘 경직시킬 수 있습니다. 황소자리는 완벽한 안정을 원하지만, 완벽한 관계란 존재하지 않습니다. 불완전함 속에서도 함께하는 것을 선택하는 것이 진짜 사랑임을 오늘 기억하세요.', en: 'Anxiety about stability can rigidify the relationship today. Taurus wants perfect stability, but a perfect relationship doesn\'t exist. Remember today that choosing to be together even in imperfection is real love.', zh: '对稳定的不安今天可能使关系僵化。金牛座想要完美的稳定，但完美的关系不存在。今天记住，即使在不完美中选择在一起才是真正的爱。', ja: '安定への不安が今日関係を硬直させる可能性があります。牡牛座は完璧な安定を望みますが、完璧な関係は存在しません。不完全さの中でも一緒にいることを選ぶことが本物の愛であることを今日思い出してください。', es: 'La ansiedad por la estabilidad puede rigidizar la relación hoy. Tauro quiere estabilidad perfecta, pero una relación perfecta no existe. Recuerda hoy que elegir estar juntos incluso en la imperfección es el amor real.' },
    ],
  },
  career: {
    high: [
      { ko: '꾸준히 쌓아온 실력이 오늘 드디어 인정받습니다. 황소자리는 단기 성과에 연연하지 않고 묵묵히 실력을 쌓아왔기 때문에, 오늘의 인정은 가장 무게 있는 종류의 인정입니다. 지금까지의 여정을 스스로 자랑스럽게 여기세요.', en: 'Your steadily built skills are finally recognized today. Because Taurus builds skills quietly without fixating on short-term results, today\'s recognition is the most weighty kind. Be proud of your journey up to now.', zh: '持续积累的实力今天终于得到认可。因为金牛座不在乎短期成果，默默积累实力，今天的认可是最有分量的那种。为自己迄今的历程感到自豪。', ja: '着実に積み上げてきた実力が今日ついに認められます。牡牛座は短期成果にこだわらず黙々と実力を積んできたため、今日の認定は最も重みのある種類の認定です。これまでの旅路を自分で誇りに思ってください。', es: 'Tus habilidades construidas con constancia finalmente son reconocidas hoy. Porque Tauro construye habilidades silenciosamente sin fijarse en resultados a corto plazo, el reconocimiento de hoy es del tipo más sustancioso. Siéntete orgulloso/a de tu camino hasta ahora.' },
      { ko: '실무 능력이 오늘 특히 돋보이는 시기입니다. 황소자리의 강점은 큰 그림보다 디테일에서 발휘되기 때문에, 오늘 세부적인 부분에서 탁월함을 보여주는 것이 차별화의 핵심이 됩니다. 디테일을 통해 당신만의 차이를 만들어내세요.', en: 'Your practical skills are especially outstanding today. Taurus strength is displayed in details more than big picture—showing excellence in the specifics today is the core of your differentiation. Make your unique difference through details.', zh: '实务能力今天特别突出。金牛座的优势体现在细节而非宏观图景，今天在细部展示卓越是差异化的核心。通过细节创造你独特的差异。', ja: '実務能力が今日特に際立つ時期です。牡牛座の強みは大きな絵よりディテールで発揮されるので、今日は細部の部分で卓越さを見せることが差別化の核心になります。ディテールを通してあなただけの差を作り出してください。', es: 'Tus habilidades prácticas son especialmente sobresalientes hoy. La fortaleza de Tauro se muestra en los detalles más que en el panorama general—mostrar excelencia en los detalles hoy es el núcleo de tu diferenciación. Haz tu diferencia única a través de los detalles.' },
      { ko: '장기 프로젝트에서 오늘 의미 있는 진전이 이루어집니다. 황소자리의 인내심이 마침내 보상받는 순간이기 때문에, 이 진전을 과소평가하지 마세요. 결실이 시작되는 이 순간이 다음 단계로 나아가는 신호입니다.', en: 'Meaningful progress happens in your long-term project today. This is the moment Taurus patience is finally rewarded—don\'t underestimate this advancement. This beginning of results is the signal to move to your next phase.', zh: '今天长期项目取得有意义的进展。这是金牛座耐心终于得到回报的时刻，不要低估这个进步。这个成果开始的时刻是迈向下一阶段的信号。', ja: '長期プロジェクトで今日意味のある進展が起こります。牡牛座の忍耐がついに報われる瞬間なので、この進展を過小評価しないでください。実りが始まるこの瞬間が次のステップに進む信号です。', es: 'Progreso significativo ocurre en tu proyecto a largo plazo hoy. Este es el momento en que la paciencia de Tauro finalmente es recompensada—no subestimes este avance. Este inicio de resultados es la señal para avanzar a tu próxima fase.' },
      { ko: '재정 관련 업무에서 오늘 특히 좋은 성과를 거둘 수 있습니다. 황소자리의 타고난 숫자 감각과 실용적 판단력이 빛을 발하기 때문에, 오늘 재정 분석이나 예산 관련 업무를 우선순위에 두세요. 당신의 감각이 팀에 실질적 이익을 가져올 것입니다.', en: 'Especially good results await in financial tasks today. Taurus\'s innate number sense and practical judgment shine—prioritize financial analysis or budget-related work today. Your instincts will bring tangible benefit to the team.', zh: '今天在财务相关工作中可以取得特别好的成果。金牛座天生的数字感觉和实用判断力发光，今天优先处理财务分析或预算相关工作。你的感觉将为团队带来实质利益。', ja: '財務関連の業務で今日特に良い成果を収められます。牡牛座の生まれつきの数字感覚と実用的な判断力が輝くため、今日は財務分析や予算関連業務を優先順位に置いてください。あなたの感覚がチームに実質的な利益をもたらすでしょう。', es: 'Especialmente buenos resultados esperan en tareas financieras hoy. El sentido numérico innato de Tauro y el juicio práctico brillan—prioriza el análisis financiero o el trabajo relacionado con presupuestos hoy. Tus instintos traerán beneficio tangible al equipo.' },
      { ko: '안정적이고 체계적인 당신의 업무 방식이 오늘 팀에 큰 기여를 합니다. 황소자리는 일관성과 신뢰성으로 팀의 중심이 되는 별자리이기 때문에, 당신의 존재 자체가 팀에게 안정감을 줍니다. 오늘 그 역할을 당당하게 수행하세요.', en: 'Your stable and systematic work style greatly contributes to the team today. Taurus is the sign that becomes a team\'s center through consistency and reliability—your very presence provides stability. Perform that role with pride today.', zh: '你稳定而系统的工作方式今天对团队做出了很大贡献。金牛座是通过一致性和可靠性成为团队中心的星座，你的存在本身给团队带来安定感。今天自豪地履行那个角色。', ja: '安定的で体系的なあなたの業務方式が今日チームに大きく貢献します。牡牛座は一貫性と信頼性でチームの中心になる星座なので、あなたの存在そのものがチームに安定感を与えます。今日その役割を堂々と果たしてください。', es: 'Tu estilo de trabajo estable y sistemático contribuye enormemente al equipo hoy. Tauro es el signo que se convierte en el centro de un equipo a través de la consistencia y fiabilidad—tu propia presencia proporciona estabilidad. Realiza ese papel con orgullo hoy.' },
      { ko: '협상이나 계약에서 오늘 유리한 결과를 얻을 수 있습니다. 황소자리의 끈질긴 인내와 침착한 협상력이 빛을 발하는 시기이기 때문에, 서두르지 말고 자신의 페이스를 유지하며 임하세요. 조급해하는 상대를 기다리는 것이 오늘의 전략입니다.', en: 'Favorable results in negotiations or contracts are achievable today. Taurus persistent patience and calm negotiating power shine—maintain your own pace without rushing. Waiting out a hasty opponent is today\'s strategy.', zh: '今天在谈判或合同中可以获得有利的结果。金牛座坚韧的耐心和沉稳的谈判力发光，不要着急，保持自己的节奏。等待对方着急是今天的策略。', ja: '交渉や契約で今日有利な結果を得られます。牡牛座の粘り強い忍耐と冷静な交渉力が輝く時期なので、急がず自分のペースを保ちながら臨んでください。焦る相手を待つことが今日の戦略です。', es: 'Resultados favorables en negociaciones o contratos son alcanzables hoy. La persistente paciencia de Tauro y el poder de negociación calmado brillan—mantén tu propio ritmo sin apresurarte. Esperar a un oponente apresurado es la estrategia de hoy.' },
      { ko: '감각적 판단력이 오늘 빛나는 날입니다. 황소자리는 품질과 미적 감각이 탁월하기 때문에, 디자인, 품질 관리, 또는 사용자 경험 관련 결정에서 당신의 직관이 팀 전체의 선택을 이끌 것입니다. 자신의 감각을 자신 있게 제안하세요.', en: 'Your aesthetic judgment shines today. Taurus excels in quality and aesthetic sense—in design, quality control, or user experience decisions, your intuition will guide the whole team\'s choices. Propose your sensory judgment with confidence.', zh: '感官判断力今天闪耀。金牛座在品质和美感上非常出色，在设计、品质管理或用户体验相关决策中，你的直觉将引导整个团队的选择。自信地提出你的感官判断。', ja: '感覚的な判断力が今日輝く日です。牡牛座は品質と美的センスが卓越しているので、デザイン、品質管理、またはユーザー体験関連の決定でのあなたの直感がチーム全体の選択を導くでしょう。自分の感覚を自信を持って提案してください。', es: 'Tu juicio estético brilla hoy. Tauro sobresale en calidad y sentido estético—en diseño, control de calidad o decisiones de experiencia de usuario, tu intuición guiará las elecciones de todo el equipo. Propón tu juicio sensorial con confianza.' },
      { ko: '동료들의 신뢰를 기반으로 한 협업이 오늘 좋은 결과를 가져옵니다. 황소자리는 오랜 시간 쌓아온 신뢰가 있기 때문에, 오늘 그 신뢰 자본을 활용하는 협업에서 예상보다 훨씬 큰 성과가 나올 것입니다. 혼자 하는 것보다 함께 할 때 더 빛납니다.', en: 'Collaboration built on colleagues\' trust brings excellent results today. Taurus has built trust over a long time—leveraging that trust capital in collaboration today will yield far greater results than expected. You shine more together than alone.', zh: '基于同事信任的合作今天带来好结果。金牛座有长时间积累的信任，今天利用那份信任资本的合作将产生比预期大得多的成果。与他人合作比独自行动更加闪耀。', ja: '同僚の信頼を基盤にした協業が今日良い結果をもたらします。牡牛座は長い時間積み上げてきた信頼があるので、今日その信頼資本を活用する協業で予想よりずっと大きな成果が出るでしょう。一人でするより一緒にやる方がより輝きます。', es: 'La colaboración construida sobre la confianza de los colegas trae excelentes resultados hoy. Tauro ha construido confianza durante mucho tiempo—aprovechar ese capital de confianza en la colaboración hoy producirá resultados mucho mayores de lo esperado. Brillas más juntos que solo/a.' },
      { ko: '오래 준비해온 발표나 제안이 오늘 좋은 반응을 얻습니다. 황소자리의 철저한 준비는 당신에게 가장 강력한 무기이기 때문에, 오늘 그 준비를 믿고 자신감 있게 임하세요. 준비된 자는 기회 앞에서 흔들리지 않습니다.', en: 'Your long-prepared presentation or proposal receives positive response today. Taurus thorough preparation is your most powerful weapon—trust that preparation and approach with confidence. Those who are prepared don\'t waver before opportunity.', zh: '今天长期准备的发表或提案获得好的反响。金牛座彻底的准备是你最有力的武器，相信那份准备，自信地面对。准备好的人在机会面前不会动摇。', ja: '長く準備してきた発表や提案が今日良い反応を得ます。牡牛座の徹底的な準備があなたにとって最も強力な武器なので、今日はその準備を信じて自信を持って臨んでください。準備された者は機会の前で揺るがないものです。', es: 'Tu presentación o propuesta largamente preparada recibe respuesta positiva hoy. La preparación minuciosa de Tauro es tu arma más poderosa—confía en esa preparación y abórdalo con confianza. Quienes están preparados no vacilan ante la oportunidad.' },
      { ko: '실질적 성과로 말하는 당신의 스타일이 오늘 상사의 눈에 확실히 들 것입니다. 황소자리는 화려한 말보다 행동과 결과로 신뢰를 쌓는 스타일이기 때문에, 오늘 그 실적이 조직에서 당신의 위치를 더욱 공고하게 만들어줄 것입니다.', en: 'Your style of letting real results speak will clearly catch your boss\'s eye today. Taurus builds trust through action and results rather than flashy words—today those results will further solidify your position in the organization.', zh: '用实际成果说话的你的风格今天会确实引起上司的注意。金牛座通过行动和结果而非华丽的话语建立信任，今天那些实绩将进一步巩固你在组织中的地位。', ja: '実質的な成果で語るあなたのスタイルが今日上司の目に確実に留まるでしょう。牡牛座は華やかな言葉より行動と結果で信頼を築くスタイルなので、今日その実績が組織でのあなたの立場をさらに固めてくれるでしょう。', es: 'Tu estilo de dejar que los resultados reales hablen claramente llamará la atención de tu jefe hoy. Tauro construye confianza a través de acciones y resultados más que palabras llamativas—hoy esos resultados solidificarán aún más tu posición en la organización.' },
    ],
    medium: [
      { ko: '맡은 바 업무를 차분히 처리하면 오늘 무난하고 든든한 하루가 됩니다. 황소자리는 화려한 하루보다 예측 가능하고 성실한 하루에서 진짜 에너지를 얻기 때문에, 오늘은 기본에 충실하게 임하는 것이 가장 현명한 선택입니다.', en: 'Calmly handling your tasks makes for a smooth, solid day. Taurus gains real energy from predictable, diligent days rather than flashy ones—staying true to the basics is the wisest choice today.', zh: '冷静处理分内工作，今天会是平稳踏实的一天。金牛座从可预测的、勤奋的一天而非华丽的一天中获得真正的能量，今天忠实于基本是最明智的选择。', ja: '担当の業務を落ち着いて処理すれば今日は無難で心強い一日になります。牡牛座は華やかな一日より予測可能で誠実な一日から本当のエネルギーを得るので、今日は基本に忠実に臨むことが最も賢明な選択です。', es: 'Manejar tus tareas con calma hace un día tranquilo y sólido hoy. Tauro obtiene energía real de días predecibles y diligentes más que llamativos—ser fiel a lo básico es la elección más sabia hoy.' },
      { ko: '새로운 업무보다 기존 업무를 정리하고 마무리하는 데 집중하면 오늘 훨씬 효율적입니다. 황소자리는 미완성 과제가 남아있을 때 내면에 무게가 쌓이는 별자리이기 때문에, 오늘 하나를 완전히 마무리하는 것이 심리적 가벼움을 가져올 것입니다.', en: 'Focusing on organizing and finishing existing work is far more efficient than starting new tasks today. Taurus accumulates internal heaviness when unfinished tasks remain—completing one thing fully today will bring psychological lightness.', zh: '今天专注于整理和完成现有工作比开始新任务效率高得多。金牛座在未完成任务积压时内心会积累沉重感，今天彻底完成一件事将带来心理上的轻盈。', ja: '新しい業務より既存の業務を整理し仕上げることに集中する方が今日はずっと効率的です。牡牛座は未完成の課題が残っている時に内面に重さが溜まる星座なので、今日一つを完全に仕上げることが心理的な軽さをもたらすでしょう。', es: 'Enfocarte en organizar y terminar el trabajo existente es mucho más eficiente que empezar nuevas tareas hoy. Tauro acumula pesadez interna cuando quedan tareas incompletas—completar una cosa plenamente hoy traerá ligereza psicológica.' },
      { ko: '업무 환경을 정비하면 오늘 생산성이 눈에 띄게 올라갑니다. 황소자리는 물리적 공간과 업무 효율이 직접 연결되는 별자리이기 때문에, 책상 정리 하나만으로도 오늘 하루의 흐름이 완전히 달라질 수 있습니다. 지금 당장 5분만 투자해보세요.', en: 'Improving your work environment noticeably boosts productivity today. Taurus has a direct link between physical space and work efficiency—just organizing your desk can completely change today\'s flow. Invest just 5 minutes right now.', zh: '整理工作环境今天会显著提高生产力。金牛座的物理空间与工作效率直接相连，仅仅整理桌面就能完全改变今天的流程。现在就投入5分钟试试。', ja: '業務環境を整備すれば今日生産性が目に見えて上がります。牡牛座は物理的空間と業務効率が直接結びつく星座なので、机の整理一つだけでも今日一日の流れが完全に変わる可能性があります。今すぐ5分だけ投資してみてください。', es: 'Mejorar tu entorno de trabajo notablemente aumenta la productividad hoy. Tauro tiene un vínculo directo entre espacio físico y eficiencia laboral—solo organizar tu escritorio puede cambiar completamente el flujo de hoy. Invierte solo 5 minutos ahora mismo.' },
      { ko: '꾸준한 페이스를 유지하는 것이 오늘 특히 중요합니다. 황소자리는 과욕을 부릴 때보다 자신의 리듬을 지킬 때 더 좋은 성과를 내는 별자리이기 때문에, 오늘은 무리하지 말고 지속 가능한 속도로 일하세요. 지금의 페이스가 장기 레이스에서 이기는 비결입니다.', en: 'Maintaining a steady pace is especially important today. Taurus produces better results when keeping its own rhythm than when overreaching—work at a sustainable speed without pushing today. Your current pace is the secret to winning the long race.', zh: '保持稳定的节奏今天特别重要。金牛座保持自己节奏时比贪心时产生更好的成果，今天不要勉强，以可持续的速度工作。现在的节奏是赢得长跑的秘诀。', ja: '着実なペースを維持することが今日特に重要です。牡牛座は過欲を出す時より自分のリズムを守る時に良い成果を出す星座なので、今日は無理せず持続可能なスピードで仕事をしてください。今のペースが長期レースで勝つ秘訣です。', es: 'Mantener un ritmo constante es especialmente importante hoy. Tauro produce mejores resultados manteniendo su propio ritmo que cuando se excede—trabaja a una velocidad sostenible sin forzar hoy. Tu ritmo actual es el secreto para ganar la carrera larga.' },
      { ko: '팀 내에서 안정적인 역할을 맡아 조용히 기여하는 것이 오늘 좋겠습니다. 황소자리의 묵묵한 기여는 단기적으로 눈에 띄지 않을 수 있지만, 장기적으로 팀에서 가장 없어서는 안 될 존재가 되는 방식입니다. 오늘 그 가치를 조용히 쌓아가세요.', en: 'Taking a stable role and contributing quietly within the team is recommended today. Taurus\'s quiet contribution may not stand out short-term, but long-term it\'s the way to become the most indispensable person on the team. Quietly build that value today.', zh: '今天在团队内担任稳定的角色安静地贡献比较好。金牛座默默的贡献短期内可能不引人注目，但长期来看是成为团队中最不可或缺存在的方式。今天安静地积累那份价值。', ja: 'チーム内で安定した役割を担い静かに貢献するのが今日は良いでしょう。牡牛座の黙々とした貢献は短期的に目立たないかもしれませんが、長期的にはチームで最も欠かせない存在になる方法です。今日その価値を静かに積み上げていきましょう。', es: 'Asumir un rol estable y contribuir silenciosamente en el equipo es recomendable hoy. La contribución silenciosa de Tauro puede no destacar a corto plazo, pero a largo plazo es la manera de convertirse en la persona más indispensable del equipo. Construye silenciosamente ese valor hoy.' },
      { ko: '서류 작업이나 데이터 정리 등 꼼꼼함이 필요한 일에서 오늘 강점을 발휘하세요. 황소자리의 세심한 주의력은 다른 사람들이 놓치는 오류를 잡아내는 능력을 줍니다. 오늘 그 능력을 적극 활용해보세요.', en: 'Leverage your strengths in meticulous tasks like paperwork or data organization today. Taurus\'s careful attention catches errors others miss. Make active use of that ability today.', zh: '今天在需要细心的文件工作或数据整理等方面发挥优势。金牛座的细心注意力让你能发现别人遗漏的错误。今天积极利用那种能力。', ja: '書類作業やデータ整理など細心さが必要な仕事で今日強みを発揮してください。牡牛座の細やかな注意力は他の人が見逃すエラーを見つける能力を与えてくれます。今日その能力を積極的に活用してみてください。', es: 'Aprovecha tus fortalezas en tareas meticulosas como papeleo u organización de datos hoy. La atención cuidadosa de Tauro detecta errores que otros pasan por alto. Haz uso activo de esa habilidad hoy.' },
      { ko: '업무 루틴을 점검하고 비효율적인 부분을 개선하면 장기적으로 큰 도움이 됩니다. 황소자리는 한번 자리잡은 습관을 좀처럼 바꾸지 않기 때문에, 오늘 작은 개선 하나가 수년간의 업무 효율을 바꾸는 큰 변화가 될 수 있습니다. 오늘 작은 비효율 하나를 찾아 개선해보세요.', en: 'Reviewing your work routine and improving inefficiencies helps enormously long-term. Taurus rarely changes established habits, so one small improvement today can be a major change that transforms years of work efficiency. Find and fix one small inefficiency today.', zh: '检视工作例程并改善低效部分，长期来看帮助很大。金牛座很少改变已经建立的习惯，所以今天一个小改进可以成为改变多年工作效率的重大变化。今天找到并改善一个小的低效之处。', ja: '業務ルーティンを点検し非効率な部分を改善すれば長期的に大きく助けになります。牡牛座は一度定着した習慣をなかなか変えないため、今日の小さな改善一つが数年間の業務効率を変える大きな変化になり得ます。今日小さな非効率を一つ見つけて改善してみてください。', es: 'Revisar tu rutina de trabajo y mejorar ineficiencias ayuda enormemente a largo plazo. Tauro raramente cambia hábitos establecidos, así que una pequeña mejora hoy puede ser un cambio mayor que transforme años de eficiencia laboral. Encuentra y corrige una pequeña ineficiencia hoy.' },
      { ko: '동료와의 관계에서 신뢰를 쌓는 데 오늘 집중하세요. 황소자리에게 성실한 태도 자체가 최선의 네트워킹이기 때문에, 화려한 말보다 작은 행동 하나하나가 쌓여서 당신의 직장 내 인맥을 만들어갑니다. 오늘 한 동료에게 진심 어린 관심을 보여주세요.', en: 'Focus on building trust with colleagues today. For Taurus, a sincere attitude is the best networking—small actions accumulate to create your workplace network rather than flashy words. Show genuine interest in one colleague today.', zh: '今天专注于与同事建立信任。对金牛座来说，诚实的态度本身就是最好的社交，一个个小行动积累起来而非华丽的话语，构建你的职场人脉。今天对一位同事表现出真诚的关心。', ja: '同僚との関係で信頼を築くことに今日集中してください。牡牛座にとって誠実な態度自体が最善のネットワーキングなので、華やかな言葉より小さな行動一つ一つが積み重なってあなたの職場内の人脈を作っていきます。今日は一人の同僚に真心こもった関心を見せてください。', es: 'Enfócate en construir confianza con colegas hoy. Para Tauro, una actitud sincera es el mejor networking—las pequeñas acciones se acumulan para crear tu red laboral más que las palabras llamativas. Muestra interés genuino en un colega hoy.' },
      { ko: '급한 결정보다 충분히 검토한 후 판단하는 것이 오늘 더 안전합니다. 황소자리의 신중함은 단기적으로 느려 보일 수 있지만, 황소자리가 내린 결정은 나중에 번복될 가능성이 낮습니다. 오늘은 그 신중함을 믿고 서두르지 마세요.', en: 'It\'s safer to judge after thorough review rather than rushing decisions today. Taurus deliberateness may seem slow short-term, but decisions made by Taurus are unlikely to be reversed later. Trust that deliberateness today and don\'t rush.', zh: '今天充分审查后再判断比仓促决定更安全。金牛座的谨慎短期看可能显得缓慢，但金牛座做出的决定后来不太可能被推翻。今天相信那份谨慎，不要着急。', ja: '急いだ決定より十分に検討した後に判断する方が今日は安全です。牡牛座の慎重さは短期的に遅く見えるかもしれませんが、牡牛座が下した決定は後で覆される可能性が低いです。今日はその慎重さを信じて急がないでください。', es: 'Es más seguro juzgar después de una revisión exhaustiva que apresurarse en decisiones hoy. La deliberación de Tauro puede parecer lenta a corto plazo, pero las decisiones tomadas por Tauro tienen pocas probabilidades de revertirse después. Confía en esa deliberación hoy y no te apresures.' },
      { ko: '작은 목표를 하나씩 달성해가며 성취감을 쌓아가는 것이 오늘 효과적입니다. 황소자리는 큰 도약보다 착실한 한 걸음이 주는 심리적 만족이 더 강하기 때문에, 오늘 작은 완료 하나하나가 다음을 향한 가장 강력한 동기부여가 됩니다. 지금 가장 작은 것부터 시작하세요.', en: 'Achieving small goals one by one and building a sense of accomplishment is effective today. Taurus finds stronger psychological satisfaction in a steady single step than a big leap—each small completion today becomes the most powerful motivation for what comes next. Start with the smallest thing right now.', zh: '今天一个个达成小目标，积累成就感是有效的。金牛座从稳定的一小步而非大跃进中获得更强的心理满足，今天每一个小小的完成都成为迈向下一步的最强动力。从最小的事情开始。', ja: '小さな目標を一つずつ達成して成就感を積み上げていくのが今日は効果的です。牡牛座は大きな跳躍より着実な一歩が与える心理的満足がより強いので、今日の小さな完了一つ一つが次に向けた最も強力なモチベーションになります。今すぐ最も小さなことから始めてください。', es: 'Lograr metas pequeñas una por una y construir un sentido de logro es efectivo hoy. Tauro encuentra mayor satisfacción psicológica en un paso constante que en un gran salto—cada pequeña finalización hoy se convierte en la motivación más poderosa para lo que viene después. Empieza con lo más pequeño ahora mismo.' },
    ],
    low: [
      { ko: '변화하는 업무 환경에 유연하게 대응해야 하는 날입니다. 황소자리는 검증된 방식을 선호하지만, 기존 방식만 고수하면 빠르게 변하는 환경에서 뒤처질 수 있습니다. 오늘 새로운 방식을 하나만 시도해보는 것이 장기적 경쟁력을 지키는 길입니다.', en: 'Today requires flexible response to a changing work environment. Taurus prefers proven methods, but sticking only to old ways can leave you behind in a rapidly changing environment. Trying just one new approach today is the path to long-term competitiveness.', zh: '今天需要灵活应对变化的工作环境。金牛座偏好经过验证的方式，但只坚持旧方式可能在快速变化的环境中落后。今天只尝试一种新方式是维护长期竞争力的途径。', ja: '変化する業務環境に柔軟に対応しなければならない日です。牡牛座は検証された方式を好みますが、既存の方式だけに固執すると急速に変化する環境で遅れをとる可能性があります。今日新しい方式を一つだけ試してみることが長期的な競争力を守る道です。', es: 'Hoy requiere respuesta flexible a un entorno laboral cambiante. Tauro prefiere métodos probados, pero aferrarse solo a formas antiguas puede dejarte atrás en un entorno que cambia rápidamente. Probar solo un nuevo enfoque hoy es el camino para mantener la competitividad a largo plazo.' },
      { ko: '완벽주의가 오늘 업무 속도를 늦추고 있습니다. 황소자리의 높은 기준은 강점이지만, 완벽한 결과를 기다리다 마감을 놓치면 그 완벽함은 아무런 가치가 없습니다. 오늘은 80%의 완성도로 제때 내는 것이 100% 늦게 내는 것보다 훨씬 낫습니다.', en: 'Perfectionism is slowing your work pace today. Taurus\'s high standards are a strength, but if waiting for a perfect result misses the deadline, that perfection is worthless. Delivering 80% quality on time today is far better than delivering 100% late.', zh: '完美主义今天正在拖慢工作速度。金牛座的高标准是优势，但如果等待完美结果而错过截止日期，那完美就毫无价值。今天准时交出80%的完成度远好于100%迟交。', ja: '完璧主義が今日業務速度を遅くしています。牡牛座の高い基準は強みですが、完璧な結果を待って締め切りを逃せばその完璧さは何の価値もありません。今日は80%の完成度で間に合わせることが100%遅れて出すよりずっと良いです。', es: 'El perfeccionismo está ralentizando tu ritmo de trabajo hoy. Los altos estándares de Tauro son una fortaleza, pero si esperar un resultado perfecto pierde la fecha límite, esa perfección no tiene valor. Entregar 80% de calidad a tiempo hoy es mucho mejor que entregar 100% tarde.' },
      { ko: '동료와의 의견 충돌이 예상되는 날입니다. 황소자리의 확신은 강점이지만, 직장에서 매번 자신의 방식만 밀어붙이면 신뢰를 잃게 됩니다. 오늘은 경청하는 자세가 당신의 의견을 더 오래 관철시키는 더 영리한 전략입니다.', en: 'Conflicts with colleagues are expected today. Taurus conviction is a strength, but always pushing your own way at work will lose trust over time. Today, the listening posture is the smarter strategy for getting your views to prevail longer.', zh: '预计今天与同事发生意见冲突。金牛座的确信是优势，但在工作中每次都只推进自己的方式会失去信任。今天倾听的姿态是让你的意见更长久得到贯彻的更聪明策略。', ja: '同僚との意見衝突が予想される日です。牡牛座の確信は強みですが、職場で毎回自分のやり方だけを押し通すと信頼を失います。今日は聴く姿勢があなたの意見をより長く貫徹させる賢い戦略です。', es: 'Se esperan conflictos con colegas hoy. La convicción de Tauro es una fortaleza, pero siempre empujar tu propio camino en el trabajo perderá confianza con el tiempo. Hoy, la postura de escucha es la estrategia más inteligente para que tus puntos de vista prevalezcan más tiempo.' },
      { ko: '업무에 대한 동기부여가 오늘 떨어질 수 있습니다. 황소자리는 보상이 보여야 움직이는 경향이 있기 때문에, 오늘은 작은 완료마다 자신에게 작은 보상을 설정해두는 것이 가장 효과적인 자기 관리 방법입니다. 당근을 직접 만들어보세요.', en: 'Work motivation may drop today. Taurus tends to move when rewards are visible—setting small self-rewards for each small completion today is the most effective self-management method. Create the carrot yourself.', zh: '工作动力今天可能下降。金牛座倾向于能看到奖励才行动，今天在每个小完成时为自己设定小奖励是最有效的自我管理方法。自己制造胡萝卜。', ja: '業務へのモチベーションが今日下がる可能性があります。牡牛座は報酬が見えてこそ動く傾向があるので、今日は小さな完了ごとに自分に小さなご褒美を設定しておくことが最も効果的な自己管理方法です。自分でニンジンを作ってみてください。', es: 'La motivación laboral puede caer hoy. Tauro tiende a moverse cuando las recompensas son visibles—establecer pequeñas auto-recompensas para cada pequeña finalización hoy es el método de auto-gestión más efectivo. Crea la zanahoria tú mismo/a.' },
      { ko: '새로운 기술이나 방법을 배우는 데 저항감을 느낄 수 있습니다. 황소자리는 낯선 것에 불편함을 느끼는 것이 자연스럽지만, 그 불편함을 피하면 결국 기술적으로 뒤처지게 됩니다. 오늘 딱 15분만 새로운 것을 탐색해보세요. 그것으로 충분합니다.', en: 'You may resist learning new skills or methods today. It\'s natural for Taurus to feel discomfort with the unfamiliar, but avoiding that discomfort eventually leaves you technically behind. Explore something new for just 15 minutes today. That\'s enough.', zh: '今天可能对学习新技术或方法感到抗拒。金牛座对陌生事物感到不适是自然的，但回避那种不适最终会让你在技术上落后。今天只花15分钟探索新事物，那就够了。', ja: '新しい技術や方法を学ぶことに抵抗感を感じるかもしれません。牡牛座は馴染みのないものに不快感を感じるのが自然ですが、その不快感を避けると結局技術的に遅れていきます。今日だけ15分新しいものを探索してみてください。それで十分です。', es: 'Puedes resistirte a aprender nuevas habilidades o métodos hoy. Es natural que Tauro sienta incomodidad con lo desconocido, pero evitar esa incomodidad eventualmente te deja atrás técnicamente. Explora algo nuevo por solo 15 minutos hoy. Con eso es suficiente.' },
      { ko: '과도한 업무량에 스트레스를 받을 수 있는 날입니다. 황소자리는 묵묵히 견디는 경향이 있지만, 오늘은 한계를 명확히 말하는 것이 필요합니다. 우선순위를 명확히 하고, 정말 해야 할 것과 미뤄도 될 것을 구분하면 부담이 훨씬 줄어들 것입니다.', en: 'Heavy workload may cause stress today. Taurus tends to silently endure, but today it\'s necessary to clearly state your limits. Clarify priorities and distinguish what truly must be done from what can be postponed—the burden will lighten considerably.', zh: '过多的工作量今天可能带来压力。金牛座倾向于默默忍耐，但今天需要明确说出界限。明确优先级，区分真正必须做的和可以推迟的，负担会大大减轻。', ja: '過度な業務量でストレスを受ける可能性がある日です。牡牛座は黙々と耐える傾向がありますが、今日は限界を明確に言うことが必要です。優先順位を明確にし、本当にすべきことと先延ばしにしても良いことを区別すると負担がずっと減るでしょう。', es: 'La carga excesiva de trabajo puede causar estrés hoy. Tauro tiende a resistir silenciosamente, pero hoy es necesario declarar claramente tus límites. Clarifica prioridades y distingue lo que verdaderamente debe hacerse de lo que puede postponerse—la carga aligerará considerablemente.' },
      { ko: '의사결정을 미루면 오늘 기회를 놓칠 수 있습니다. 황소자리는 신중하게 결정하는 것이 강점이지만, 때로는 적시에 내리는 70% 확신의 결정이 늦게 내리는 100% 확신보다 훨씬 가치 있습니다. 오늘은 완벽한 때를 기다리지 말고 결단을 내리세요.', en: 'Delaying decisions may cause missed opportunities today. Taurus decisiveness is a strength, but sometimes a 70% confident decision made timely is far more valuable than a 100% confident decision made late. Don\'t wait for the perfect moment today—decide.', zh: '推迟决策今天可能错过机会。金牛座的谨慎决策是优势，但有时及时做出70%确信的决定远比晚些做出100%确信的决定更有价值。今天不要等待完美的时机，做出决定。', ja: '意思決定を先延ばしにすると今日機会を逃す可能性があります。牡牛座は慎重に決定するのが強みですが、時には適時に下す70%の確信の決定が遅く下す100%の確信より価値があります。今日は完璧な時を待たずに決断を下してください。', es: 'Retrasar decisiones puede hacer que pierdas oportunidades hoy. La precaución de Tauro es una fortaleza, pero a veces una decisión tomada a tiempo con 70% de certeza es mucho más valiosa que una con 100% de certeza tomada tarde. No esperes el momento perfecto hoy—decide.' },
      { ko: '편안한 환경에 안주하고 있지 않은지 오늘 스스로 점검이 필요합니다. 황소자리는 익숙한 것에서 행복을 찾는 별자리이지만, 성장은 불편함 속에서만 일어납니다. 오늘 작은 불편함 하나를 자발적으로 선택하는 것이 정체를 막는 최고의 방법입니다.', en: 'Self-check is needed today: are you settling in comfort? Taurus finds happiness in the familiar, but growth only happens in discomfort. Voluntarily choosing one small discomfort today is the best way to prevent stagnation.', zh: '今天需要自我检查：是否安于舒适？金牛座在熟悉的事物中找到幸福，但成长只在不适中发生。今天主动选择一个小小的不适是防止停滞的最好方法。', ja: '快適な環境に安住していないか今日自分で点検が必要です。牡牛座は馴染みのものから幸せを見つける星座ですが、成長は不快感の中でのみ起こります。今日小さな不快感を一つ自発的に選ぶことが停滞を防ぐ最高の方法です。', es: 'Es necesaria una auto-verificación hoy: ¿te estás acomodando en la comodidad? Tauro encuentra felicidad en lo familiar, pero el crecimiento solo ocurre en la incomodidad. Elegir voluntariamente una pequeña incomodidad hoy es la mejor manera de prevenir el estancamiento.' },
      { ko: '직장 내 인간관계에서 소유적 태도를 보이지 않도록 오늘 주의하세요. 황소자리는 자신의 영역과 사람에 대한 소유 욕구가 강한 편이지만, 직장에서 그것이 과도해지면 관계를 파괴합니다. 오늘은 동료가 다른 사람들과 잘 지내는 것을 마음 편히 응원해보세요.', en: 'Be careful not to show possessive attitudes in workplace relationships today. Taurus has strong ownership instincts about their territory and people, but in excess at work, it destroys relationships. Today, comfortably cheer for your colleague thriving with others.', zh: '今天注意在职场人际关系中不要表现出占有态度。金牛座对自己的领域和人有强烈的占有欲，但在职场过度表现会破坏关系。今天，从容地为同事与他人相处融洽而高兴。', ja: '職場内の人間関係で所有的な態度を見せないよう今日は注意してください。牡牛座は自分の領域と人への所有欲求が強い方ですが、職場でそれが過度になると関係を破壊します。今日は同僚が他の人たちとうまくやっていることを心穏やかに応援してみてください。', es: 'Ten cuidado de no mostrar actitudes posesivas en las relaciones laborales hoy. Tauro tiene fuertes instintos de posesión sobre su territorio y personas, pero en exceso en el trabajo, destruye relaciones. Hoy, anima cómodamente a tu colega prosperando con otros.' },
      { ko: '안정을 추구하는 것은 좋지만, 변화를 완전히 거부하면 오늘 정체됩니다. 황소자리에게 변화는 위협이 아니라 더 큰 안정을 향한 발판임을 기억하세요. 오늘 작은 변화 하나를 시도하는 것이 미래의 더 큰 안정을 만들어가는 현명한 투자입니다.', en: 'Seeking stability is fine, but completely rejecting change leads to stagnation today. Remember for Taurus that change is not a threat but a stepping stone toward greater stability. Trying one small change today is the wise investment that builds greater stability in the future.', zh: '追求稳定是好的，但完全拒绝变化今天会导致停滞。记住对金牛座来说，变化不是威胁，而是通向更大稳定的踏板。今天尝试一个小变化是建立未来更大稳定的明智投资。', ja: '安定を追求するのは良いですが、変化を完全に拒否すると今日停滞します。牡牛座にとって変化は脅威ではなくより大きな安定への踏み台であることを覚えておいてください。今日小さな変化を一つ試みることが将来のより大きな安定を作っていく賢い投資です。', es: 'Buscar estabilidad está bien, pero rechazar totalmente el cambio lleva al estancamiento hoy. Recuerda para Tauro que el cambio no es una amenaza sino un peldaño hacia mayor estabilidad. Probar un pequeño cambio hoy es la inversión sabia que construye mayor estabilidad en el futuro.' },
    ],
  },
  health: {
    high: [
      { ko: '몸과 마음이 안정된 최적의 상태입니다. 꾸준히 쌓아온 건강 습관의 효과가 지금 드러나고 있기 때문에, 황소자리의 일관성이 가장 빛나는 순간입니다. 오늘 이 상태를 더 강화하는 한 가지 긍정적 습관을 추가해보세요.', en: 'Body and mind are in their optimal stable state. The effects of steadily accumulated health habits are showing now—this is the moment Taurus consistency shines brightest. Add one positive habit today to further strengthen this state.', zh: '身心处于最佳稳定状态。持续积累的健康习惯效果现在显现，这是金牛座一致性最闪耀的时刻。今天添加一个积极习惯来进一步强化这种状态。', ja: '体と心が安定した最適な状態です。着実に積み重ねてきた健康習慣の効果が今現れているため、牡牛座の一貫性が最も輝く瞬間です。今日この状態をさらに強化する一つのポジティブな習慣を追加してみてください。', es: 'Cuerpo y mente están en su estado estable óptimo. Los efectos de los hábitos saludables acumulados constantemente se muestran ahora—este es el momento en que la consistencia de Tauro brilla más. Agrega un hábito positivo hoy para fortalecer aún más este estado.' },
      { ko: '자연 속 활동이 오늘 특별한 활력을 줍니다. 황소자리의 흙 원소 에너지는 대지와의 직접적 접촉에서 가장 강하게 충전되기 때문에, 공원 산책이나 정원 가꾸기가 어떤 보충제보다 더 효과적인 에너지 회복제가 됩니다. 오늘 대지와 연결되는 시간을 내보세요.', en: 'Nature activities bring special vitality today. Taurus earth element energy charges most powerfully through direct contact with the ground—park walks or gardening are more effective energy restorers than any supplement. Make time to connect with the earth today.', zh: '大自然中的活动今天带来特别的活力。金牛座的土元素能量通过与大地的直接接触充电最强，公园散步或园艺比任何补充剂都更有效地恢复能量。今天抽时间与大地连接。', ja: '自然の中での活動が今日特別な活力を与えます。牡牛座の土エレメントエネルギーは大地との直接的な接触で最も強く充電されるため、公園の散歩や庭いじりがどんなサプリメントよりも効果的なエネルギー回復剤になります。今日大地とつながる時間を作ってみてください。', es: 'Las actividades en la naturaleza traen vitalidad especial hoy. La energía del elemento tierra de Tauro se carga más poderosamente a través del contacto directo con el suelo—los paseos por el parque o la jardinería son restauradores de energía más efectivos que cualquier suplemento. Haz tiempo para conectarte con la tierra hoy.' },
      { ko: '황소자리의 풍부한 감각이 오늘 치유의 도구가 됩니다. 오감을 자극하는 힐링—아로마테라피의 향기, 마사지의 촉감, 따뜻한 목욕의 온기—은 금성의 에너지를 신체에 직접 통하게 하는 방법입니다. 오늘 하나의 감각 치유를 의식적으로 선택해 완전히 몰입해보세요.', en: 'Taurus\'s rich sensory capacity becomes a healing tool today. Sensory therapies—aromatherapy, massage, warm baths—work by channeling Venus\'s energy directly through the body. Choose one sensory healing practice today and fully immerse yourself in it rather than rushing through.', zh: '金牛座丰富的感官今天成为治愈工具。芳香疗法、按摩、温水浴等感官疗愈，是让金星能量直接通过身体的方式。今天有意识地选择一种感官治愈，完全沉浸其中。', ja: '牡牛座の豊かな感覚が今日は癒しの道具になります。アロマテラピーの香り、マッサージの触感、温かいお風呂の温もりなど感覚を刺激する癒しは、金星のエネルギーを直接体に通す方法です。今日一つの感覚癒しを意識的に選んで完全に没入してみてください。', es: 'La rica capacidad sensorial de Tauro se convierte hoy en una herramienta sanadora. La aromaterapia, el masaje, los baños calientes canalizan directamente la energía de Venus a través del cuerpo. Elige hoy una práctica de sanación sensorial e inmérjate completamente en ella.' },
      { ko: '오늘 황소자리의 미식 감각이 건강을 위한 최고의 동맹이 됩니다. 제철 식재료를 구입하고 그 풍미를 충분히 느끼며 요리하는 행위 자체가, 몸에 영양을 공급하면서 동시에 황소자리의 영혼을 채웁니다. 맛있게 먹고 건강해지는 두 마리 토끼를 오늘 동시에 잡아보세요.', en: 'Today Taurus\'s gourmet sensibility becomes your greatest health ally. Buying seasonal ingredients and cooking while truly enjoying their flavors nourishes the body while simultaneously feeding the Taurus soul. The pleasure you take in good food today is itself part of the medicine.', zh: '今天金牛座的美食感官成为健康最好的盟友。购买当季食材，充分感受其风味烹饪的行为本身，既为身体提供营养，又滋养金牛座的灵魂。今天可以同时实现美食与健康。', ja: '今日牡牛座の美食感覚が健康のための最高の同盟者になります。旬の食材を購入してその風味を十分に感じながら料理する行為自体が、体に栄養を供給しながら同時に牡牛座の魂を満たします。美味しく食べて健康になる二つのことを今日同時に達成してみてください。', es: 'El sentido gourmet de Tauro se convierte hoy en tu mayor aliado para la salud. Comprar ingredientes de temporada y cocinar apreciando plenamente sus sabores nutre el cuerpo mientras alimenta el alma de Tauro. El placer que encuentras en la buena comida es parte de la medicina.' },
      { ko: '황소자리의 취약 부위인 목과 어깨가 오늘은 에너지로 가득 차 있습니다. 이 최상의 컨디션을 더욱 활성화하려면, 황소자리가 주관하는 목소리를 사용하는 것—노래, 발성 연습, 심지어 큰 소리로 읽기—이 신체와 감정 모두에 활력을 불어넣어 줍니다. 오늘 목소리를 마음껏 내보세요.', en: 'Taurus\'s vulnerable zone—neck and shoulders—is full of energy today. To further activate this peak condition, use the voice that Taurus governs: singing, vocal exercises, or even reading aloud energizes both body and emotions. Let your voice out freely today.', zh: '金牛座的薄弱部位——颈部和肩膀今天充满能量。为了进一步激活这种最佳状态，使用金牛座掌管的声音——歌唱、发声练习甚至大声朗读，能为身体和情感注入活力。今天尽情发出自己的声音吧。', ja: '牡牛座の弱点部位である首と肩が今日はエネルギーで満ちています。この最高のコンディションをさらに活性化するには、牡牛座が管轄する声を使うこと——歌、発声練習、声に出して読むことさえも——が身体と感情の両方に活力を吹き込みます。今日は思いきり声を出してみてください。', es: 'La zona vulnerable de Tauro—cuello y hombros—está llena de energía hoy. Para activar aún más esta condición óptima, usa la voz que gobierna Tauro: cantar, ejercicios vocales o incluso leer en voz alta energiza cuerpo y emociones. Deja salir tu voz libremente hoy.' },
      { ko: '황소자리는 12별자리 중 루틴을 가장 잘 지키는 존재이며, 지금 그 능력이 건강의 방패가 되고 있습니다. 규칙적인 기상·취침·식사 시간은 황소자리의 면역 시스템을 최상으로 작동시키는 코드이기 때문에, 오늘 하루 이 리듬을 흔들림 없이 지켜낸 것 자체가 대단한 건강 투자입니다. 이 루틴이 당신의 몸을 지키는 가장 강력한 방어막임을 자랑스럽게 여기세요.', en: 'Taurus is the zodiac\'s most consistent keeper of routine, and right now that ability is serving as your health shield. Regular sleep, wake, and meal times are the exact code that keeps Taurus\'s immune system running at peak—maintaining this rhythm today is itself a powerful health investment. Be proud that your consistency is your strongest defense.', zh: '金牛座是十二星座中最善于保持规律的，现在这种能力正在成为健康的盾牌。规律的起床、就寝、进餐时间是使金牛座免疫系统最佳运转的密码。今天坚守这种节奏本身就是强大的健康投资。为你的坚持感到自豪。', ja: '牡牛座は12星座の中でルーティンを最もよく守る存在であり、今その能力が健康の盾となっています。規則的な起床・就寝・食事時間は牡牛座の免疫システムを最高に動作させるコードなので、今日このリズムを守り抜いたこと自体が素晴らしい健康投資です。このルーティンがあなたの体を守る最強の防衛壁であることを誇りに思ってください。', es: 'Tauro es el mejor guardián de rutinas del zodíaco, y ahora esa habilidad es tu escudo de salud. Los horarios regulares de sueño, despertar y comidas son el código exacto que mantiene el sistema inmune de Tauro funcionando al máximo. Mantener este ritmo hoy es una poderosa inversión en salud—siéntete orgulloso/a de ello.' },
      { ko: '오늘 황소자리의 흙 원소 치유 에너지가 특별히 강하게 활성화되어 있습니다. 현대 과학도 인정하는 어싱(Earthing)—맨발로 땅에 닿는 것—은 지구의 자유전자가 몸 속 염증을 줄여주는 실제 메커니즘으로 작동합니다. 오늘 5분이라도 풀밭이나 흙 위에 맨발로 서는 것이 어떤 건강 보조제보다 강력한 황소자리의 충전 방법입니다.', en: 'Today Taurus\'s earth element healing energy is particularly powerfully activated. Earthing—bare feet on the ground—is validated by modern science as a real mechanism where the earth\'s free electrons reduce bodily inflammation. Even 5 minutes of barefoot contact with grass or soil today is a more powerful Taurus recharge than any supplement.', zh: '今天金牛座的土元素治愈能量特别强烈地被激活。现代科学也认可的接地法——赤脚接触大地——是地球自由电子减少体内炎症的真实机制。今天哪怕5分钟站在草地或土地上，都是比任何健康补充剂更强大的金牛座充电方法。', ja: '今日牡牛座の土エレメント治癒エネルギーが特別強く活性化されています。現代科学も認めるアーシング——裸足で地面に触れること——は、地球の自由電子が体内の炎症を減らす実際のメカニズムとして機能します。今日5分でも草地や土の上に裸足で立つことが、どんな健康サプリメントよりも強力な牡牛座の充電方法です。', es: 'Hoy la energía sanadora del elemento tierra de Tauro está especialmente activada. El earthing—pies descalzos sobre la tierra—está validado por la ciencia moderna como un mecanismo real donde los electrones libres de la tierra reducen la inflamación. Incluso 5 minutos de contacto descalzo con hierba o suelo hoy es una recarga de Tauro más poderosa que cualquier suplemento.' },
      { ko: '황소자리는 요란한 것보다 꾸준한 것에서 진정한 강함을 발휘합니다. 요가나 필라테스처럼 집중력과 인내를 동시에 요구하는 운동이 황소자리의 기질과 완벽하게 맞기 때문에, 다른 사람보다 더 오래 더 깊이 발전할 수 있는 잠재력을 가지고 있습니다. 오늘이 바로 그 잠재력을 깨울 첫 번째 날로 삼아보세요.', en: 'Taurus finds its true strength not in flashy efforts but in consistent ones. Exercises like yoga or Pilates that demand both focus and patience match Taurus\'s temperament perfectly—you have the potential to progress deeper and longer than anyone else. Make today the first day of awakening that potential.', zh: '金牛座在持续稳定中而不是华而不实中发挥真正的力量。瑜伽或普拉提这类同时需要专注和耐心的运动与金牛座的气质完美契合，让你有比他人更深入、更长久发展的潜力。让今天成为唤醒这种潜力的第一天。', ja: '牡牛座は派手なものよりも着実なものに真の強さを発揮します。ヨガやピラティスのように集中力と忍耐を同時に要求する運動が牡牛座の気質と完璧に合うため、他の人よりも深く長く発展できる潜在力を持っています。今日をその潜在力を目覚めさせる最初の日にしてみてください。', es: 'Tauro encuentra su verdadera fuerza no en los esfuerzos llamativos sino en los constantes. Ejercicios como yoga o Pilates que demandan tanto enfoque como paciencia encajan perfectamente con el temperamento de Tauro—tienes el potencial de progresar más profundo y más tiempo que nadie. Haz de hoy el primer día para despertar ese potencial.' },
      { ko: '지금 당신의 몸과 마음이 완벽한 안정 상태에 있어, 오랫동안 미뤄왔던 건강 검진을 받기에 이보다 좋은 타이밍이 없습니다. 황소자리는 한번 결심하면 반드시 실행하는 별자리이기 때문에, 오늘의 이 안정감을 활용해 약속 예약 전화 한 통만 하면 충분합니다. 미래의 당신이 오늘 이 결정에 감사하게 될 것입니다.', en: 'Your body and mind are in a perfectly stable state right now—there\'s no better timing for getting that long-postponed health checkup. Taurus, once committed, always follows through, so leverage today\'s stability by making just one appointment call. Your future self will thank you for this decision today.', zh: '现在你的身心处于完美稳定状态，没有比现在更好的时机去做一直推迟的体检。金牛座一旦下定决心就一定会执行，利用今天的稳定感，只需打一个预约电话就够了。未来的你会感谢今天的这个决定。', ja: '今あなたの心身が完璧な安定状態にあり、長い間先延ばしにしてきた健康診断を受けるのにこれ以上良いタイミングはありません。牡牛座は一度決心すれば必ず実行する星座なので、今日の安定感を活用して予約の電話一本をかけるだけで十分です。未来のあなたが今日のこの決断に感謝するでしょう。', es: 'Tu cuerpo y mente están en un estado perfectamente estable ahora—no hay mejor momento para hacerse ese chequeo médico postergado. Tauro, una vez comprometido, siempre cumple, así que aprovecha la estabilidad de hoy haciendo solo una llamada para hacer la cita. Tu yo futuro te agradecerá esta decisión.' },
      { ko: '황소자리에게 수면은 단순한 휴식이 아니라 신체가 가장 깊이 회복하는 성스러운 시간입니다. 지금 이 시기에 수면의 질이 자연스럽게 올라가고 있으며, 편안한 침구·향기·온도 같은 감각적 환경을 갖춰주면 이 회복력이 두 배 이상 강화됩니다. 오늘 밤 잠자리 환경에 작은 사치 하나를 더해보세요—그것이 내일의 에너지가 됩니다.', en: 'For Taurus, sleep is not mere rest but sacred time when the body recovers most deeply. Sleep quality is naturally rising now, and creating sensory comfort—bedding, scent, temperature—more than doubles this recovery power. Add one small luxury to your sleep environment tonight; it becomes tomorrow\'s energy.', zh: '对金牛座来说，睡眠不仅仅是休息，而是身体最深层恢复的神圣时间。现在睡眠质量自然地在提升，提供舒适的寝具、香气、温度等感官环境，可以让这种恢复力加倍以上。今晚为睡眠环境增加一个小奢华——那将成为明天的能量。', ja: '牡牛座にとって睡眠は単なる休息ではなく、体が最も深く回復する神聖な時間です。今この時期に睡眠の質が自然と上がっており、快適な寝具・香り・温度のような感覚的環境を整えれば、この回復力が2倍以上強化されます。今夜の寝床環境に小さな贅沢を一つ加えてみてください——それが明日のエネルギーになります。', es: 'Para Tauro, el sueño no es mero descanso sino tiempo sagrado donde el cuerpo se recupera más profundamente. La calidad del sueño está mejorando naturalmente ahora, y crear comodidad sensorial—ropa de cama, aroma, temperatura—más que duplica este poder de recuperación. Añade un pequeño lujo a tu ambiente de sueño esta noche; se convierte en la energía de mañana.' },
    ],
    medium: [
      { ko: '건강이 특별히 나쁘지도 좋지도 않은 평온한 상태입니다. 황소자리의 건강은 극적인 변화보다 꾸준한 유지에서 빛을 발하는데, 지금이 바로 그 꾸준함이 기반을 다지는 중요한 시간입니다. 오늘 규칙적인 식사와 수면 리듬을 지키는 것이 다음 에너지 고점을 위한 현명한 준비입니다.', en: 'Health is in a calm state—neither especially bad nor particularly good. Taurus health shines not in dramatic changes but in steady maintenance, and right now is important time for that consistency to build its foundation. Keeping regular meal and sleep rhythms today is smart preparation for your next energy peak.', zh: '健康处于平稳状态——不特别差也不特别好。金牛座的健康在稳定维护而非戏剧性变化中发光，现在正是这种稳定打基础的重要时期。今天保持规律的饮食和睡眠节奏，是为下一个能量高峰做的聪明准备。', ja: '健康は特別に悪くも良くもない平穏な状態です。牡牛座の健康は劇的な変化よりも着実な維持で輝くのですが、今がその着実さが基盤を固める重要な時間です。今日規則的な食事と睡眠リズムを守ることが次のエネルギー高点のための賢い準備です。', es: 'La salud está en un estado tranquilo—ni especialmente mala ni particularmente buena. La salud de Tauro brilla no en cambios dramáticos sino en el mantenimiento constante, y ahora es tiempo importante para que esa consistencia construya su base. Mantener ritmos regulares de comida y sueño hoy es preparación inteligente para tu próximo pico de energía.' },
      { ko: '황소자리가 지배하는 목과 어깨에 약간의 긴장감이 느껴질 수 있는데, 이것은 몸이 보내는 조기 경보 신호입니다. 황소자리 특유의 감각 민감성이 사실은 이런 미세한 신호를 남보다 먼저 포착하게 해주는 장점이기도 합니다. 지금 1분 스트레칭 한 번이 나중의 며칠치 통증을 막아줄 수 있으니 몸의 말을 듣고 바로 움직여보세요.', en: 'Light tension may gather in the neck and shoulders Taurus governs—this is your body sending an early warning. Taurus\'s characteristic sensory sensitivity is actually an advantage that lets you catch these subtle signals before others do. One minute of stretching now can prevent days of pain later, so listen to your body and move right away.', zh: '金牛座掌管的颈部和肩膀可能会感到轻微紧张，这是身体发出的早期警报信号。金牛座特有的感官敏感性实际上是一种优势，让你比别人更早捕捉到这些细微信号。现在一分钟的伸展可以防止之后几天的疼痛，倾听身体的声音，立刻行动吧。', ja: '牡牛座が支配する首と肩に軽い緊張感が感じられるかもしれませんが、これは体が送る早期警報サインです。牡牛座特有の感覚的敏感性が実はこのような微細なサインを他の人より早くキャッチさせてくれる利点でもあります。今の1分間のストレッチ一回が後の数日分の痛みを防いでくれるので、体の声を聞いてすぐ動いてみてください。', es: 'Puede acumularse tensión leve en el cuello y hombros que gobierna Tauro—tu cuerpo enviando una advertencia temprana. La sensibilidad sensorial característica de Tauro es en realidad una ventaja que te permite captar estas señales sutiles antes que otros. Un minuto de estiramiento ahora puede prevenir días de dolor después, así que escucha a tu cuerpo y muévete ahora mismo.' },
      { ko: '오늘 몸이 강한 자극보다 부드럽고 지속적인 움직임을 원하고 있습니다. 황소자리의 흙 원소 에너지와 가장 잘 맞는 산책이나 요가는 단순한 가벼운 운동이 아니라, 몸과 대지를 연결하며 깊은 에너지 회복을 이끌어내는 황소자리의 전통적 치유 방법입니다. 오늘의 부드러운 움직임이 내일의 활력을 위한 투자라는 것을 기억하세요.', en: 'Your body today wants gentle, sustained movement rather than strong stimulation. Walking or yoga, which align best with Taurus\'s earth element energy, aren\'t just light exercise—they\'re Taurus\'s traditional healing method that connects body to earth and draws out deep energy recovery. Remember that today\'s gentle movement is an investment in tomorrow\'s vitality.', zh: '今天身体想要的是温和持续的运动，而不是强烈刺激。与金牛座土元素能量最相配的散步或瑜伽，不只是轻运动，而是连接身体与大地、引导深层能量恢复的金牛座传统治愈方式。记住，今天的温和运动是对明天活力的投资。', ja: '今日体は強い刺激よりも穏やかで持続的な動きを求めています。牡牛座の土エレメントエネルギーと最もよく合う散歩やヨガは、単なる軽い運動ではなく、体と大地をつなぎ深いエネルギー回復を引き出す牡牛座の伝統的な治癒方法です。今日の穏やかな動きが明日の活力のための投資であることを忘れないでください。', es: 'Tu cuerpo hoy quiere movimiento suave y sostenido en lugar de estimulación intensa. Caminar o hacer yoga, que mejor se alinean con la energía del elemento tierra de Tauro, no son simplemente ejercicio ligero—son el método de curación tradicional de Tauro que conecta el cuerpo con la tierra y extrae una recuperación de energía profunda. Recuerda que el movimiento suave de hoy es una inversión en la vitalidad de mañana.' },
      { ko: '황소자리의 아킬레스건 중 하나는 맛있는 것 앞에서의 절제인데, 오늘이 바로 그 균형을 연습하기 좋은 날입니다. 맛을 포기하지 않으면서 과식만 조절해도, 황소자리의 타고난 감각이 실제로 더 깊은 풍미를 느끼게 해주는 역설적 보상이 따라옵니다. 더 천천히, 더 의식적으로 먹는 것이 오늘의 식사를 더 풍요롭게 만드는 비결입니다.', en: 'One of Taurus\'s Achilles\' heels is restraint before delicious things—today is a good day to practice that balance. By controlling only overeating without giving up flavor, there\'s a paradoxical reward: Taurus\'s innate sensory ability makes you taste deeper flavors. Eating more slowly and consciously is the secret to making today\'s meal more abundant.', zh: '金牛座的弱点之一是面对美食时的克制，今天正是练习这种平衡的好日子。不放弃美味，只控制过量进食，金牛座天生的感官能力会带来品味更深层风味的矛盾奖励。更慢、更有意识地进食是让今天的饮食更丰盛的秘诀。', ja: '牡牛座のアキレス腱の一つは美味しいものの前での節制ですが、今日がそのバランスを練習するのに良い日です。味を諦めずに過食だけを調節しても、牡牛座の生来の感覚がより深い風味を感じさせてくれるという逆説的な報酬が伴います。より ゆっくり、より意識的に食べることが今日の食事をより豊かにする秘訣です。', es: 'Uno de los talones de Aquiles de Tauro es la moderación ante las cosas deliciosas—hoy es un buen día para practicar ese equilibrio. Al controlar solo el comer en exceso sin renunciar al sabor, hay una recompensa paradójica: la capacidad sensorial innata de Tauro te hace saborear sabores más profundos. Comer más lentamente y conscientemente es el secreto para hacer la comida de hoy más abundante.' },
      { ko: '황소자리의 신체 취약 부위인 갑상선은 수분과 밀접한 관계가 있습니다. 충분한 수분 섭취는 갑상선 호르몬의 정상적 순환을 돕고 신진대사 전반을 조절하는데, 황소자리의 풍요를 사랑하는 본성상 물도 의식적이고 충분하게 마셔야 진정한 활력이 유지됩니다. 좋아하는 허브티나 과일 인퓨즈드 워터로 수분 섭취를 즐거운 의식으로 만들어보세요.', en: 'The thyroid—Taurus\'s body vulnerable zone—is closely connected to hydration. Sufficient water intake helps thyroid hormones circulate normally and regulates overall metabolism. Given Taurus\'s nature that loves abundance, you need to drink consciously and sufficiently to maintain true vitality. Make hydration an enjoyable ritual with herbal tea or fruit-infused water.', zh: '金牛座身体薄弱部位甲状腺与水分密切相关。充足的水分摄入有助于甲状腺激素正常循环，调节整体新陈代谢。鉴于金牛座热爱丰盛的本性，只有有意识地充分饮水才能维持真正的活力。用喜欢的花草茶或水果泡水，把补水变成愉快的仪式。', ja: '牡牛座の身体の弱点部位である甲状腺は水分と密接な関係があります。十分な水分摂取は甲状腺ホルモンの正常な循環を助け、新陳代謝全般を調節しますが、牡牛座の豊かさを愛する本性上、水も意識的に十分に飲まないと本当の活力が維持されません。好きなハーブティーやフルーツインフューズドウォーターで水分補給を楽しい儀式にしてみてください。', es: 'La tiroides—la zona corporal vulnerable de Tauro—está íntimamente conectada a la hidratación. Suficiente ingesta de agua ayuda a que las hormonas tiroideas circulen normalmente y regula el metabolismo general. Dada la naturaleza de Tauro que ama la abundancia, necesitas beber consciente y suficientemente para mantener la vitalidad real. Haz de la hidratación un ritual agradable con té de hierbas o agua infusionada con frutas.' },
      { ko: '황소자리는 특유의 강인함으로 피로 신호를 자주 무시하는 경향이 있는데, 지금이 바로 그 패턴을 멈춰야 할 타이밍입니다. 피로가 임계점을 넘으면 회복에 3배 이상의 시간이 걸리는 반면, 지금 미리 쉬면 내일 오히려 더 큰 에너지로 활동할 수 있습니다. 짧은 휴식을 "약함"이 아닌 "현명한 에너지 관리"로 재정의해보세요.', en: 'Taurus tends to often ignore fatigue signals with its characteristic toughness—right now is the moment to stop that pattern. When fatigue crosses a threshold, recovery takes three times longer, but resting now means having even more energy tomorrow. Redefine brief rest as "smart energy management" rather than weakness.', zh: '金牛座倾向于凭借其特有的坚韧经常忽视疲劳信号，现在正是停止这种模式的时机。疲劳超过临界点后，恢复需要三倍以上的时间，而现在提前休息，明天反而可以用更大的能量活动。把短暂休息重新定义为"聪明的能量管理"而非软弱。', ja: '牡牛座は特有の強靭さで疲労サインを頻繁に無視する傾向がありますが、今がそのパターンを止めるべきタイミングです。疲労が臨界点を超えると回復に3倍以上の時間がかかる一方、今先に休めば明日はむしろより大きなエネルギーで活動できます。短い休息を「弱さ」ではなく「賢いエネルギー管理」として再定義してみてください。', es: 'Tauro tiende a ignorar frecuentemente las señales de fatiga con su resistencia característica—ahora es el momento de detener ese patrón. Cuando la fatiga supera un umbral, la recuperación tarda tres veces más, pero descansar ahora significa tener aún más energía mañana. Redefine el descanso breve como "gestión inteligente de energía" en lugar de debilidad.' },
      { ko: '건강의 드라마틱한 변화를 원하는 사람은 많지만, 황소자리처럼 일관성을 진짜 실천할 수 있는 별자리는 많지 않습니다. 지금 눈에 잘 보이지 않더라도, 꾸준히 쌓아온 건강 습관들이 내부에서 조용히 기적을 만들어가고 있습니다. 오늘도 그 일관성의 한 페이지를 충실히 써내려가세요.', en: 'Many people want dramatic health changes, but few signs can truly practice consistency like Taurus can. Even if it\'s not obviously visible right now, the health habits you\'ve steadily built are quietly creating miracles inside. Write another faithful page of that consistency today.', zh: '想要健康戏剧性变化的人很多，但能像金牛座那样真正实践一致性的星座不多。即使现在看不出明显变化，持续积累的健康习惯正在内部悄悄创造奇迹。今天也忠实地写下那份坚持的一页。', ja: '健康のドラマチックな変化を望む人は多いですが、牡牛座のように一貫性を本当に実践できる星座は少ないです。今目に見えにくくても、着実に積み重ねてきた健康習慣が内部で静かに奇跡を作り続けています。今日もその一貫性の一ページを誠実に書き続けてください。', es: 'Muchas personas quieren cambios dramáticos de salud, pero pocos signos pueden practicar realmente la consistencia como Tauro. Aunque no sea obviamente visible ahora, los hábitos de salud que has acumulado constantemente están creando milagros silenciosamente por dentro. Escribe otra página fiel de esa consistencia hoy.' },
      { ko: '실내에 오래 있으면 황소자리의 흙 원소 에너지가 갇혀 답답함이 쌓일 수 있습니다. 짧게라도 야외 공간에 나가 하늘을 보고 바람을 느끼는 것이, 황소자리의 내면 에너지 흐름을 다시 열어주는 자연스러운 리셋 버튼 역할을 합니다. 오늘 하루 중 15분의 야외 시간을 의도적으로 확보해보세요.', en: 'Staying indoors too long can trap Taurus\'s earth element energy, letting restlessness accumulate. Even briefly going outside to see the sky and feel the breeze acts as a natural reset button that re-opens Taurus\'s inner energy flow. Intentionally secure 15 minutes of outdoor time somewhere in today.', zh: '长时间待在室内，金牛座的土元素能量可能被困住，积累烦闷感。即使短暂走出户外，看看天空感受微风，也能作为重新开启金牛座内在能量流动的自然重置按钮。今天有意识地确保15分钟的户外时间。', ja: '室内に長くいると牡牛座の土エレメントエネルギーが閉じ込められて答答しさが積もる可能性があります。短くても屋外空間に出て空を見て風を感じることが、牡牛座の内なるエネルギーの流れを再び開くナチュラルリセットボタンの役割をします。今日一日の中で15分の屋外時間を意図的に確保してみてください。', es: 'Quedarse demasiado tiempo en interiores puede atrapar la energía del elemento tierra de Tauro, dejando acumular inquietud. Incluso salir brevemente al exterior para ver el cielo y sentir la brisa actúa como un botón de reinicio natural que reabre el flujo de energía interior de Tauro. Asegúrate intencionalmente de tener 15 minutos de tiempo al aire libre en algún momento de hoy.' },
      { ko: '황소자리의 집중력은 뛰어나지만, 그 집중력이 몸을 오랫동안 같은 자세에 고정시키는 부작용을 만들기도 합니다. 목과 어깨는 황소자리가 관할하는 신체 부위로, 장시간 긴장 상태가 지속되면 가장 먼저 신호를 보냅니다. 한 시간마다 30초씩 의식적으로 자세를 바꾸고 목을 돌려주는 간단한 습관이 장기적인 통증을 예방하는 황소자리의 현명한 자기 보호 전략입니다.', en: 'Taurus\'s focus is outstanding, but that concentration can have a side effect of locking the body in the same position for too long. The neck and shoulders, Taurus\'s body domain, send the first signals when tension continues for too long. A simple habit of consciously changing position and rotating your neck for 30 seconds every hour is Taurus\'s wise self-protection strategy for preventing long-term pain.', zh: '金牛座的专注力很出色，但这种专注力也会产生将身体长时间固定在同一姿势的副作用。颈部和肩膀是金牛座管辖的身体部位，长时间持续紧张时会最先发出信号。每小时有意识地改变姿势并转动颈部30秒的简单习惯，是预防长期疼痛的金牛座明智自我保护策略。', ja: '牡牛座の集中力は優れていますが、その集中力が体を長時間同じ姿勢に固定してしまうという副作用を生み出すこともあります。首と肩は牡牛座が管轄する身体部位で、長時間緊張状態が続くと最初にサインを送ります。1時間ごとに30秒意識的に姿勢を変えて首を回すという簡単な習慣が、長期的な痛みを予防する牡牛座の賢い自己保護戦略です。', es: 'El enfoque de Tauro es sobresaliente, pero esa concentración puede tener un efecto secundario de fijar el cuerpo en la misma posición durante demasiado tiempo. El cuello y los hombros, dominio corporal de Tauro, envían las primeras señales cuando la tensión continúa demasiado tiempo. El simple hábito de cambiar conscientemente de posición y rotar el cuello 30 segundos cada hora es la estrategia inteligente de autoprotección de Tauro para prevenir el dolor a largo plazo.' },
      { ko: '건강을 크게 바꾸려 할 때 오히려 실패하기 쉬운데, 황소자리의 방식은 "작게, 그러나 영원히"입니다. 오늘 단 하나의 작은 건강 습관—아침 물 한 잔, 취침 전 스트레칭 3분, 계단 이용—을 결정하고 그것만 완벽하게 지켜보세요. 황소자리의 꾸준함이 그 한 가지를 6개월 뒤 완전히 다른 몸으로 만들어 줄 것입니다.', en: 'Trying to make big health changes actually leads to failure more easily—Taurus\'s way is "small but forever." Decide on just one small health habit today—one glass of water in the morning, 3 minutes of pre-sleep stretching, taking the stairs—and keep only that one perfectly. Taurus\'s consistency will transform that one thing into a completely different body six months from now.', zh: '试图大幅改变健康反而更容易失败，金牛座的方式是"小但永恒"。今天决定一个小健康习惯——早晨一杯水、睡前3分钟伸展、走楼梯——只把那一件事做到完美。金牛座的坚持将在6个月后把那一件事变成完全不同的身体。', ja: '健康を大きく変えようとするときにかえって失敗しやすいのですが、牡牛座の方式は「小さく、しかし永遠に」です。今日ただ一つの小さな健康習慣——朝の水一杯、就寝前の3分ストレッチ、階段利用——を決めてそれだけを完璧に守ってみてください。牡牛座の着実さがその一つを6か月後に全く違う体に変えてくれるでしょう。', es: 'Intentar hacer grandes cambios de salud en realidad lleva al fracaso más fácilmente—el camino de Tauro es "pequeño pero para siempre." Decide hoy un solo pequeño hábito de salud—un vaso de agua por la mañana, 3 minutos de estiramientos antes de dormir, usar las escaleras—y mantén solo ese perfectamente. La consistencia de Tauro transformará esa cosa en un cuerpo completamente diferente seis meses después.' },
    ],
    low: [
      { ko: '황소자리의 취약 부위인 목과 인후가 오늘 불편함을 호소할 수 있습니다. 이것은 몸이 당신에게 "속도를 줄이고 나를 돌봐달라"고 보내는 신호이니, 따뜻한 허브티 한 잔을 천천히 마시며 목을 감사히 여기는 시간을 가져보세요. 작은 돌봄이 지금 당신의 몸이 가장 필요로 하는 것이며, 이 증상이 더 커지기 전에 멈추는 현명한 선택입니다.', en: 'Taurus\'s vulnerable zone—neck and throat—may speak up with discomfort today. This is a signal your body sends saying "slow down and take care of me," so slowly sip a warm herbal tea and take a moment to appreciate your throat. This small care is exactly what your body needs most right now, and it\'s the wise choice to stop this symptom before it grows.', zh: '金牛座的薄弱部位——颈部和咽喉今天可能发出不适的声音。这是身体向你发出的"放慢速度，照顾我"的信号，所以慢慢喝一杯温热草药茶，花时间感谢你的喉咙。这小小的关怀正是你的身体现在最需要的，也是在症状变严重之前停下来的明智选择。', ja: '牡牛座の弱点部位である喉と咽頭が今日不快感を訴えるかもしれません。これはあなたの体が「速度を落として私をケアしてほしい」と送るサインなので、温かいハーブティーを一杯ゆっくり飲みながら喉に感謝する時間を取ってみてください。小さなケアが今あなたの体が最も必要としているものであり、この症状がもっと大きくなる前に止める賢明な選択です。', es: 'La zona vulnerable de Tauro—cuello y garganta—puede hablar con molestia hoy. Esta es una señal que tu cuerpo envía diciendo "aminora la marcha y cuídame," así que bebe lentamente una taza de té de hierbas caliente y tómate un momento para apreciar tu garganta. Este pequeño cuidado es exactamente lo que más necesita tu cuerpo ahora mismo, y es la sabia elección de detener este síntoma antes de que crezca.' },
      { ko: '오늘 과식의 유혹이 평소보다 강하게 느껴지는데, 이것은 사실 음식이 아닌 다른 무언가를 갈망하는 황소자리의 깊은 충족 욕구입니다. 금성의 감각 에너지를 음악 감상, 향기로운 목욕, 부드러운 직물의 촉감처럼 다른 감각 채널로 돌리면, 과식 충동이 줄어들면서 실제로 더 만족스러운 충족감을 얻을 수 있습니다. 오늘은 입이 아닌 다른 감각으로 풍요를 경험해보세요.', en: 'Today the temptation to overeat feels stronger than usual—this is actually Taurus\'s deep fulfillment need craving something other than food. Redirecting Venus\'s sensory energy to other channels—listening to music, a fragrant bath, the touch of soft fabric—reduces the overeating impulse while actually bringing more satisfying fulfillment. Experience abundance today through senses other than taste.', zh: '今天过量饮食的诱惑比平时更强烈，这实际上是金牛座渴望食物以外某种东西的深层满足需求。将金星的感官能量引导到其他感官渠道——听音乐、香气沐浴、柔软织物的触感——可以减少过食冲动，同时获得实际上更满足的充实感。今天通过味觉以外的感官来体验丰盛。', ja: '今日過食の誘惑が普段より強く感じられますが、これは実は食べ物ではない何か別のものを渇望する牡牛座の深い充足欲求です。金星の感覚エネルギーを音楽鑑賞、香り高いお風呂、柔らかい布の触感などの別の感覚チャンネルに向けると、過食衝動が減りながら実際により満足のいく充足感を得られます。今日は口ではなく他の感覚で豊かさを体験してみてください。', es: 'Hoy la tentación de comer en exceso se siente más fuerte que de costumbre—en realidad es la profunda necesidad de satisfacción de Tauro que ansía algo diferente a la comida. Redirigir la energía sensorial de Venus a otros canales—escuchar música, un baño aromático, la textura de telas suaves—reduce el impulso de comer en exceso mientras trae una satisfacción realmente más plena. Experimenta la abundancia hoy a través de otros sentidos además del gusto.' },
      { ko: '오늘 몸을 움직이기 싫은 황소자리 특유의 안락함 중독이 강하게 나타날 수 있습니다. 하지만 이 저항을 단 10분만 이겨내면, 신체에서 분비되는 도파민이 나머지 하루를 훨씬 활기차게 만들어준다는 것이 과학적으로 증명되어 있습니다. 10분의 움직임은 "운동"이 아니라 "뇌 화학을 바꾸는 가장 짧은 주문"입니다—지금 당장 시작해보세요.', en: 'Today Taurus\'s characteristic comfort addiction of not wanting to move the body may appear strongly. But overcoming this resistance for just 10 minutes is scientifically proven to release dopamine that makes the rest of the day much more energetic. Ten minutes of movement isn\'t "exercise"—it\'s the shortest spell for changing brain chemistry. Start right now.', zh: '今天金牛座特有的舒适成瘾——不想动身体——可能会强烈出现。但只需克服这种抗拒10分钟，身体分泌的多巴胺就会让余下的一天充满活力，这已得到科学证明。10分钟的运动不是"锻炼"，而是改变大脑化学的最短咒语——现在就开始。', ja: '今日体を動かしたくない牡牛座特有のコンフォート中毒が強く現れる可能性があります。しかし、この抵抗をたった10分だけ乗り越えると、体から分泌されるドーパミンが残りの一日をはるかに活き活きとさせてくれることが科学的に証明されています。10分の動きは「運動」ではなく「脳の化学を変える最も短い呪文」です——今すぐ始めてみてください。', es: 'Hoy puede aparecer fuertemente la adicción característica de Tauro a la comodidad de no querer mover el cuerpo. Pero está científicamente probado que superar esta resistencia durante solo 10 minutos libera dopamina que hace el resto del día mucho más enérgico. Diez minutos de movimiento no es "ejercicio"—es el hechizo más corto para cambiar la química cerebral. Empieza ahora mismo.' },
      { ko: '오늘 감정적 스트레스를 음식으로 채우려는 황소자리의 오래된 패턴이 활성화될 수 있습니다. 이 패턴이 시작되려 할 때, 20분의 산책은 음식이 줄 수 없는 방식으로 스트레스 호르몬을 실제로 분해해주는 신체 화학 반응을 일으킵니다. 음식 대신 신발을 신는 것, 오늘 그 선택 하나가 몸과 마음 모두에게 진정한 위로가 될 것입니다.', en: 'Today Taurus\'s old pattern of filling emotional stress with food may activate. When this pattern is about to start, 20 minutes of walking triggers real body chemistry that breaks down stress hormones in ways food cannot. Putting on shoes instead of reaching for food—that single choice today will be true comfort for both body and mind.', zh: '今天金牛座用食物填补情绪压力的旧有模式可能会被激活。当这种模式即将开始时，20分钟的散步会触发真实的身体化学反应，以食物无法做到的方式真正分解压力荷尔蒙。穿上鞋子而不是拿食物——今天这一个选择将是对身心的真正慰藉。', ja: '今日感情的なストレスを食べ物で埋めようとする牡牛座の古いパターンが活性化する可能性があります。このパターンが始まろうとするとき、20分の散歩が食べ物にはできない方法でストレスホルモンを実際に分解する身体の化学反応を引き起こします。食べ物の代わりに靴を履くこと、今日その選択一つが体と心の両方への本当の慰めになるでしょう。', es: 'Hoy puede activarse el viejo patrón de Tauro de llenar el estrés emocional con comida. Cuando este patrón está a punto de comenzar, 20 minutos de caminata desencadenan una química corporal real que descompone las hormonas del estrés de maneras que la comida no puede. Ponerse los zapatos en lugar de alcanzar la comida—esa única elección hoy será verdadero consuelo tanto para el cuerpo como para la mente.' },
      { ko: '황소자리의 지배 신체 부위인 갑상선이 오늘 주의 신호를 보내고 있을 수 있습니다. 황소자리는 몸의 불편함을 꾹 참고 견디는 경향이 있지만, 갑상선의 이상은 방치할수록 회복이 어려워지는 대표적인 케이스입니다. 작은 불편함이라도 느껴진다면, 지금 전문의 상담을 예약하는 것이 황소자리가 가장 잘하는 현명한 선제적 대처입니다.', en: 'The thyroid—Taurus\'s governing body area—may be sending cautionary signals today. Taurus tends to endure physical discomfort by gritting through, but thyroid irregularities are a prime example where recovery becomes harder the longer you wait. Even if the discomfort is small, booking a specialist consultation now is the wise preemptive action Taurus does best.', zh: '金牛座主管的身体部位甲状腺今天可能在发出警告信号。金牛座倾向于咬牙忍受身体不适，但甲状腺异常是典型的拖延越久恢复越难的案例。即使只是轻微不适，现在预约专科医生咨询也是金牛座最擅长的明智先发制人的应对。', ja: '牡牛座の支配身体部位である甲状腺が今日注意サインを送っているかもしれません。牡牛座は体の不快感をぐっと我慢する傾向がありますが、甲状腺の異常は放置するほど回復が難しくなる代表的なケースです。小さな不快感でも感じたら、今専門医の相談を予約することが牡牛座が最も得意とする賢明な先制的対処です。', es: 'La tiroides—el área corporal gobernada por Tauro—puede estar enviando señales de advertencia hoy. Tauro tiende a soportar el malestar físico aguantando, pero las irregularidades tiroideas son un ejemplo principal donde la recuperación se vuelve más difícil cuanto más se espera. Incluso si el malestar es pequeño, reservar una consulta especializada ahora es la acción preventiva inteligente que Tauro hace mejor.' },
      { ko: '황소자리가 지배하는 경추와 어깨에 오늘 통증이 찾아올 수 있으며, 이것은 무시하면 안 될 신호입니다. 바른 자세는 황소자리의 구조적 강함의 표현이기도 한데, 지금 이 부위에서 경고가 온다는 것은 그 구조가 흔들리고 있다는 의미입니다. 지금 당장 자세를 바로잡고 경추 스트레칭을 시작하면, 내일의 당신이 오늘의 이 결정에 감사할 것입니다.', en: 'Today pain may visit the cervical spine and shoulders that Taurus governs—a signal not to ignore. Good posture is also an expression of Taurus\'s structural strength, so when a warning comes from this area, it means that structure is being shaken. Correct your posture right now and begin cervical stretching—tomorrow\'s you will thank today\'s decision.', zh: '今天金牛座掌管的颈椎和肩膀可能会来疼痛，这是不能忽视的信号。正确的姿势也是金牛座结构力量的表现，当这个部位发出警告时，意味着那个结构正在动摇。现在立刻纠正姿势，开始颈椎伸展，明天的你会感谢今天的这个决定。', ja: '牡牛座が支配する頸椎と肩に今日痛みが訪れる可能性があり、これは無視してはいけないサインです。正しい姿勢は牡牛座の構造的強さの表現でもありますが、今この部位から警告が来るということはその構造が揺らいでいるという意味です。今すぐ姿勢を正して頸椎ストレッチを始めれば、明日のあなたが今日のこの決断に感謝するでしょう。', es: 'Hoy puede visitar el dolor a las cervicales y hombros que gobierna Tauro—una señal que no hay que ignorar. La buena postura también es una expresión de la fuerza estructural de Tauro, por lo que cuando llega una advertencia de esta área, significa que esa estructura está siendo sacudida. Corrige tu postura ahora mismo y comienza estiramientos cervicales—el tú de mañana agradecerá la decisión de hoy.' },
      { ko: '황소자리의 안락함 사랑이 오늘 활동량을 크게 줄일 위험이 있습니다. 하지만 이것은 성격의 결함이 아니라—풍요를 즐길 줄 아는 능력이기도 합니다—다만 몸이 필요로 하는 최소한의 움직임을 확보하기 위한 의식적 노력이 필요합니다. "운동"이라는 무거운 단어 대신, "오늘 내 몸에 주는 선물"이라고 바꿔 생각하면 실천하기가 훨씬 쉬워집니다.', en: 'Taurus\'s love of comfort risks significantly reducing activity today. But this isn\'t a character flaw—it\'s also the ability to enjoy abundance—however, conscious effort is needed to secure the minimum movement your body requires. Instead of the heavy word "exercise," thinking of it as "a gift I give my body today" makes it much easier to actually do.', zh: '金牛座对舒适的热爱今天有显著减少活动量的风险。但这不是性格缺陷——也是享受丰盛的能力——只是需要有意识的努力来确保身体所需的最低限度运动。把沉重的"运动"换成"今天给身体的礼物"来思考，实践起来会容易得多。', ja: '牡牛座の安楽さへの愛が今日活動量を大きく減らす危険があります。しかしこれは性格の欠陥ではなく——豊かさを楽しめる能力でもありますが——ただ体に必要な最低限の動きを確保するための意識的な努力が必要です。「運動」という重い言葉の代わりに、「今日体への贈り物」と言い換えて考えると、実践がずっと楽になります。', es: 'El amor de Tauro por la comodidad arriesga reducir significativamente la actividad hoy. Pero esto no es un defecto de carácter—también es la capacidad de disfrutar la abundancia—sin embargo, se necesita esfuerzo consciente para asegurar el movimiento mínimo que tu cuerpo requiere. En lugar de la pesada palabra "ejercicio," pensar en ello como "un regalo que le doy a mi cuerpo hoy" hace que sea mucho más fácil realmente hacerlo.' },
      { ko: '황소자리는 감정을 표현하기보다 안에서 묵혀두는 경향이 있는데, 오늘 그 억눌린 감정들이 신체 증상으로 표출될 가능성이 높습니다. 목의 긴장, 두통, 소화 불편이 사실은 감정적 신호일 수 있다는 것을 인식하고, 오늘은 말하거나 쓰거나 울거나—어떤 방식으로든 감정을 조금 밖으로 꺼내는 것이 몸을 치유하는 진짜 처방입니다.', en: 'Taurus tends to suppress emotions rather than express them—today those suppressed emotions are likely to manifest as physical symptoms. Recognize that neck tension, headaches, or digestive discomfort may actually be emotional signals, and today, speaking, writing, crying—releasing emotion outward in any way is the real prescription that heals the body.', zh: '金牛座倾向于把情绪积压在内而不是表达出来，今天那些被压抑的情绪很可能表现为身体症状。认识到颈部紧张、头痛、消化不适可能实际上是情绪信号，今天说出来、写出来、哭出来——以任何方式将情绪释放出去，才是治愈身体的真正处方。', ja: '牡牛座は感情を表現するよりも内側に溜め込む傾向がありますが、今日そのそぎ込まれた感情が身体症状として現れる可能性が高いです。首の緊張、頭痛、消化不快が実は感情的なサインかもしれないことを認識して、今日は話したり書いたり泣いたり——どんな方法でも感情を少し外に出すことが体を癒やす本当の処方箋です。', es: 'Tauro tiende a suprimir las emociones en lugar de expresarlas—hoy esas emociones suprimidas probablemente se manifestarán como síntomas físicos. Reconoce que la tensión en el cuello, los dolores de cabeza o el malestar digestivo pueden ser en realidad señales emocionales, y hoy, hablar, escribir, llorar—liberar emoción hacia afuera de cualquier manera es la prescripción real que sana el cuerpo.' },
      { ko: '황소자리의 규칙성이 오늘 흔들려 수면 패턴이 무너질 위험이 있습니다. 황소자리에게 수면은 단순한 충전이 아니라 흙 원소가 재생되는 핵심 시간이기 때문에, 수면이 불규칙해지면 에너지 전체의 시스템이 흔들립니다. 오늘 밤 어떤 이유가 있더라도 취침 시간을 30분 이내로 지키는 것이, 내일의 황소자리 에너지를 지키는 가장 중요한 선택입니다.', en: 'Taurus\'s regularity is being shaken today, risking sleep pattern disruption. For Taurus, sleep isn\'t just recharging—it\'s the core time when earth element regenerates, so when sleep becomes irregular, the entire energy system is shaken. Keeping tonight\'s bedtime within 30 minutes of your usual time, whatever the reason, is the most important choice for protecting tomorrow\'s Taurus energy.', zh: '金牛座的规律性今天可能动摇，有打乱睡眠模式的风险。对金牛座来说，睡眠不仅仅是充电，更是土元素再生的核心时间，所以睡眠不规律会动摇整个能量系统。今晚无论什么原因，将就寝时间控制在平时的30分钟以内，是保护明天金牛座能量的最重要选择。', ja: '牡牛座の規則性が今日揺らいで睡眠パターンが崩れる危険があります。牡牛座にとって睡眠は単なる充電ではなく、土エレメントが再生される核心の時間なので、睡眠が不規則になるとエネルギー全体のシステムが揺らぎます。今夜どんな理由があっても就寝時間を30分以内に守ることが、明日の牡牛座エネルギーを守る最も重要な選択です。', es: 'La regularidad de Tauro está siendo sacudida hoy, arriesgando la disrupción del patrón de sueño. Para Tauro, el sueño no es solo recarga—es el tiempo central donde el elemento tierra se regenera, por lo que cuando el sueño se vuelve irregular, todo el sistema de energía se sacude. Mantener la hora de dormir de esta noche dentro de 30 minutos de la habitual, cualquiera sea la razón, es la elección más importante para proteger la energía de Tauro mañana.' },
      { ko: '황소자리는 미식과 안락함을 사랑하기에 체중 관리가 생애의 중요한 테마 중 하나입니다. 오늘 체중 변화 신호가 느껴진다면, 이것을 자기 비판의 이유가 아닌 몸이 보내는 유용한 데이터로 받아들이세요. 균형 잡힌 식사와 꾸준한 움직임이라는 황소자리의 자연스러운 강점을 되살리면, 몸은 자신이 좋아하는 상태로 돌아오려는 본능적 지혜를 갖고 있습니다.', en: 'Taurus loves good food and comfort, making weight management one of life\'s important themes. If you sense weight change signals today, receive them not as reason for self-criticism but as useful data your body is sending. Revive Taurus\'s natural strengths—balanced eating and steady movement—and the body has instinctive wisdom to return to the state it prefers.', zh: '金牛座热爱美食和安逸，使体重管理成为生命中的重要主题之一。如果今天感到体重变化的信号，把它当作身体发送的有用数据，而不是自我批评的理由。重新唤起金牛座均衡饮食和持续运动的自然优势，身体有恢复到自己喜欢的状态的本能智慧。', ja: '牡牛座は美食と安楽さを愛するため、体重管理が人生の重要なテーマの一つです。今日体重変化のサインが感じられるなら、これを自己批判の理由ではなく体が送る有用なデータとして受け取ってください。均衡のとれた食事と着実な動きという牡牛座の自然な強みを蘇らせれば、体は自分が好む状態に戻ろうとする本能的な知恵を持っています。', es: 'Tauro ama la buena comida y la comodidad, haciendo de la gestión del peso uno de los temas importantes de la vida. Si hoy sientes señales de cambios de peso, recíbelas no como razón para la autocrítica sino como datos útiles que tu cuerpo está enviando. Revive las fortalezas naturales de Tauro—alimentación equilibrada y movimiento constante—y el cuerpo tiene la sabiduría instintiva para regresar al estado que prefiere.' },
    ],
  },
  money: {
    high: [
      { ko: '금성이 황소자리의 재정에 풍요의 에너지를 직접 불어넣고 있어, 오늘 당신의 재정 감각은 평소보다 훨씬 예리합니다. 이 기운은 서두르는 자보다 천천히 음미하며 살피는 자에게 더 큰 기회를 열어주기 때문에, 오늘 나타나는 투자 또는 소득 기회를 황소자리 특유의 신중함으로 꼼꼼히 살펴보세요. 당신이 가진 가치 평가 능력이 오늘 최고의 무기입니다.', en: 'Venus is directly infusing Taurus finances with abundance energy today, making your financial intuition much sharper than usual. This energy opens bigger opportunities to those who savor slowly rather than rush, so examine today\'s investment or income opportunities with Taurus\'s characteristic caution. Your value-assessment ability is your greatest weapon today.', zh: '金星今天正在直接向金牛座的财务注入丰盛能量，使你的财务直觉比平时更加敏锐。这种能量向慢慢品味而非急于行动的人开启更大的机会，所以用金牛座特有的谨慎仔细审视今天出现的投资或收入机会。你拥有的价值评估能力是今天最强的武器。', ja: '金星が今日牡牛座の財政に豊かさのエネルギーを直接吹き込んでいて、あなたの財政感覚が普段よりはるかに鋭いです。このエネルギーは急ぐ者よりもゆっくり吟味しながら観察する者により大きな機会を開くので、今日現れる投資または収入機会を牡牛座特有の慎重さでしっかり調べてみてください。あなたが持つ価値評価能力が今日最高の武器です。', es: 'Venus está infundiendo directamente energía de abundancia a las finanzas de Tauro hoy, haciendo tu intuición financiera mucho más aguda que de costumbre. Esta energía abre mayores oportunidades a quienes saborean lentamente en lugar de apresurarse, así que examina las oportunidades de inversión o ingresos que aparezcan hoy con la caución característica de Tauro. Tu capacidad de evaluación de valor es tu mayor arma hoy.' },
      { ko: '황소자리가 오랜 시간 신중하게 고민하고 준비해온 재정 계획이 이제 드디어 결실을 맺을 준비가 되어 있습니다. 많은 사람들이 황소자리의 느린 결정을 답답하게 보지만, 사실 그 신중함이 실패를 피하고 진정한 가치를 획득하는 황소자리만의 비밀 공식이었습니다. 오늘 이 성과를 당연히 여기지 말고, 당신이 쏟아온 인내의 가치를 스스로 축하해주세요.', en: 'The financial plan Taurus has carefully pondered and prepared over a long time is now finally ready to bear fruit. Many people see Taurus\'s slow decisions as frustrating, but in reality that carefulness has been Taurus\'s secret formula for avoiding failure and acquiring genuine value. Don\'t take today\'s result for granted—celebrate the worth of the patience you\'ve invested.', zh: '金牛座长时间谨慎思考和准备的财务计划现在终于准备好结果了。很多人把金牛座的缓慢决策看成令人沮丧的事，但实际上那份谨慎一直是金牛座避免失败和获取真正价值的秘密公式。今天不要把这个成果视为理所当然，自我庆祝你所付出的耐心的价值。', ja: '牡牛座が長い時間慎重に考えて準備してきた財政計画がいよいよ実を結ぶ準備ができています。多くの人が牡牛座の遅い決断をもどかしく見ますが、実はその慎重さが失敗を避けて真の価値を獲得する牡牛座だけの秘密の公式でした。今日この成果を当たり前に思わず、あなたが注いできた忍耐の価値を自分自身でお祝いしてください。', es: 'El plan financiero que Tauro ha considerado y preparado cuidadosamente durante mucho tiempo ahora está finalmente listo para dar frutos. Muchas personas ven las decisiones lentas de Tauro como frustrantes, pero en realidad esa cautela ha sido la fórmula secreta de Tauro para evitar el fracaso y adquirir valor genuino. No des este resultado de hoy por sentado—celebra el valor de la paciencia que has invertido.' },
      { ko: '황소자리의 가장 뛰어난 재정적 능력은 진짜 가치를 한 번에 알아보는 심미안입니다. 오늘 그 능력이 절정에 달해 있어, 싸지만 곧 교체해야 하는 것이 아닌 비싸더라도 오래 지속되는 진짜 가치를 정확하게 식별할 수 있습니다. 오늘 "품질에 대한 투자"를 결정할 기회가 있다면, 황소자리의 그 안목을 믿고 과감하게 행동해도 좋습니다.', en: 'Taurus\'s greatest financial ability is the discerning eye that instantly recognizes genuine value. Today that ability is at its peak—you can precisely identify true lasting value rather than cheap things that need replacing soon. If an opportunity to decide on "investing in quality" arises today, trust that Taurus discernment and act boldly.', zh: '金牛座最出色的财务能力是一眼看出真正价值的眼光。今天这种能力达到顶峰，能精确识别出即使昂贵但持久的真正价值，而不是便宜但很快就需要更换的东西。如果今天有机会做出"投资品质"的决定，相信金牛座的那份眼光，大胆行动也无妨。', ja: '牡牛座の最も優れた財政的能力は本物の価値を一目で見抜く審美眼です。今日その能力が絶頂に達していて、安いがすぐに交換が必要なものではなく高くても長く続く本物の価値を正確に識別できます。今日「品質への投資」を決める機会があれば、牡牛座のその審美眼を信じて大胆に行動しても良いです。', es: 'La mayor habilidad financiera de Tauro es el ojo discernidor que reconoce instantáneamente el valor genuino. Hoy esa habilidad está en su punto máximo—puedes identificar con precisión el verdadero valor duradero en lugar de cosas baratas que pronto necesitan reemplazo. Si surge una oportunidad hoy de decidir sobre "invertir en calidad," confía en ese discernimiento de Tauro y actúa con valentía.' },
      { ko: '흙 원소를 지배하는 황소자리에게 부동산과 실물 자산은 가장 자연스러운 부의 형태입니다. 오늘 이 분야에서 긍정적인 소식이나 기회의 신호가 나타날 수 있는데, 황소자리의 직관은 디지털 숫자보다 만지고 볼 수 있는 실물 가치에서 더 정확하게 작동합니다. 오늘 받게 되는 부동산 또는 유형 자산 관련 정보를 주의 깊게 살펴보세요—거기에 중요한 힌트가 있을 수 있습니다.', en: 'For Taurus that governs earth element, real estate and tangible assets are the most natural form of wealth. Today positive news or opportunity signals may appear in this field—Taurus\'s intuition works more accurately on tangible value you can touch and see than on digital numbers. Pay close attention to any real estate or tangible asset information you receive today—there may be important hints there.', zh: '对于主管土元素的金牛座来说，房地产和实物资产是最自然的财富形式。今天这个领域可能出现积极的消息或机会信号，金牛座的直觉在能触摸和看到的实物价值上比数字数值工作得更准确。仔细关注今天收到的与房地产或有形资产相关的信息——那里可能有重要的提示。', ja: '土エレメントを支配する牡牛座にとって、不動産と実物資産は最も自然な富の形です。今日この分野で肯定的なニュースや機会のサインが現れる可能性がありますが、牡牛座の直感はデジタルの数字よりも触れて見ることができる実物の価値でより正確に作動します。今日受け取る不動産または有形資産に関連した情報を注意深く見てみてください——そこに重要なヒントがあるかもしれません。', es: 'Para Tauro que gobierna el elemento tierra, los bienes raíces y activos tangibles son la forma más natural de riqueza. Hoy pueden aparecer noticias positivas o señales de oportunidad en este campo—la intuición de Tauro funciona más precisamente en valor tangible que puedes tocar y ver que en números digitales. Presta mucha atención a cualquier información relacionada con bienes raíces o activos tangibles que recibas hoy—puede haber pistas importantes allí.' },
      { ko: '당신이 한 푼 한 푼 꾸준히 쌓아온 저축이 오늘 든든한 안전망임을 실감하게 됩니다. 세상이 불안정할수록 황소자리의 이 재정적 토대는 빛을 발하는데, 지금 당신이 하고 있는 재정 습관이 장기적으로 가장 현명한 선택이라는 확신을 가져도 좋습니다. 오늘 이 안정감이 다른 일에서도 더 자신감 있게 행동할 수 있게 해주는 든든한 배경이 됩니다.', en: 'The savings you\'ve steadily built penny by penny become a solid safety net you truly feel today. The more unstable the world, the more Taurus\'s financial foundation shines—you can have confidence that the financial habits you\'re practicing now are the wisest long-term choices. Today this sense of security becomes the solid backdrop that lets you act more confidently in other areas too.', zh: '你一分一分持续积累的储蓄今天让你真实感受到它是坚实的安全网。世界越不稳定，金牛座的这个财务基础越发光芒四射——你可以有信心，你现在实践的财务习惯是长远来看最明智的选择。今天这种安全感成为让你在其他事情上也能更自信地行动的坚实背景。', ja: '一銭一銭着実に積み重ねてきた貯蓄が今日は心強いセーフティネットであることをしみじみと感じます。世界が不安定なほど牡牛座のこの財政的な基盤は輝きますが、今あなたが実践している財政習慣が長期的に最も賢明な選択だという確信を持っても良いです。今日この安定感が他のことでもより自信を持って行動できるようにしてくれる頼もしい背景になります。', es: 'Los ahorros que has acumulado centavo a centavo se convierten en una red de seguridad sólida que verdaderamente sientes hoy. Cuanto más inestable es el mundo, más brilla la base financiera de Tauro—puedes tener la confianza de que los hábitos financieros que practicas ahora son las elecciones más sabias a largo plazo. Hoy esta sensación de seguridad se convierte en el sólido trasfondo que te permite actuar con más confianza también en otras áreas.' },
      { ko: '오늘 재정 협상이나 계약 관련 상황에서 황소자리가 가장 강한 위치에 있습니다. 황소자리의 차분함과 쉽게 흔들리지 않는 기질은 협상 테이블에서 압박을 견뎌내는 가장 강력한 무기인데, 서두르지 않고 천천히 차분하게 임하는 것이 결국 유리한 결과를 이끌어낼 것입니다. 상대방이 먼저 말하게 하고, 당신은 들으면서 최적의 타이밍을 기다리세요.', en: 'In financial negotiations or contract situations today, Taurus is in its strongest position. Taurus\'s calm and unshakeable temperament is the most powerful weapon for enduring pressure at the negotiation table—approaching without haste, slowly and calmly, will ultimately lead to favorable outcomes. Let the other party speak first, and you listen while waiting for the optimal moment.', zh: '今天在财务谈判或合同相关情况中，金牛座处于最强势的位置。金牛座的冷静和不易动摇的气质是在谈判桌上承受压力的最强武器，不急躁、慢慢冷静地面对，最终将引导出有利的结果。让对方先说，你边听边等待最佳时机。', ja: '今日財政交渉や契約関連の状況で牡牛座が最も強い位置にあります。牡牛座の落ち着きと簡単には揺らがない気質は交渉テーブルでプレッシャーに耐える最も強力な武器で、焦らずゆっくり落ち着いて臨むことが結局有利な結果を導き出すでしょう。相手方に先に話させ、あなたは聞きながら最適なタイミングを待ってください。', es: 'En negociaciones financieras o situaciones relacionadas con contratos hoy, Tauro está en su posición más fuerte. La calma de Tauro y el temperamento imperturbable son las armas más poderosas para soportar la presión en la mesa de negociación—acercarse sin prisa, lenta y calmadamente, finalmente llevará a resultados favorables. Deja que la otra parte hable primero, y escucha mientras esperas el momento óptimo.' },
      { ko: '황소자리의 실용적 기술과 손재주는 오늘 추가 소득을 만들 수 있는 현실적인 기회로 이어집니다. 황소자리의 가장 큰 재정적 강점 중 하나가 바로 자신의 실질적 능력을 돈으로 전환할 줄 안다는 것인데, 오늘 그 가능성을 탐색할 기회가 자연스럽게 열립니다. 당신이 잘하는 것을 사람들이 돈을 내고 원한다는 사실—오늘 그것을 현실로 만들기 위한 첫 발을 내딛어보세요.', en: 'Taurus\'s practical skills and manual dexterity lead today to realistic opportunities to create additional income. One of Taurus\'s greatest financial strengths is knowing how to convert genuine abilities into money—today opportunities to explore that possibility open naturally. People pay money for what you do well—take the first step today toward making that a reality.', zh: '金牛座的实用技能和手工能力今天延伸到创造额外收入的现实机会。金牛座最大的财务优势之一就是知道如何将实际能力转化为金钱，今天探索这种可能性的机会自然打开。人们愿意为你擅长的事情付钱——今天迈出让这成为现实的第一步。', ja: '牡牛座の実用的なスキルと手先の器用さが今日追加収入を作れる現実的な機会につながります。牡牛座の最大の財政的強みの一つが自分の実質的な能力をお金に転換する方法を知っているということで、今日その可能性を探る機会が自然と開きます。あなたが得意なことを人々がお金を払って望んでいるという事実——今日それを現実にするための最初の一歩を踏み出してみてください。', es: 'Las habilidades prácticas y la destreza manual de Tauro llevan hoy a oportunidades realistas de crear ingresos adicionales. Una de las mayores fortalezas financieras de Tauro es saber cómo convertir habilidades genuinas en dinero—hoy se abren naturalmente oportunidades para explorar esa posibilidad. La gente paga dinero por lo que haces bien—da el primer paso hoy para hacer eso una realidad.' },
      { ko: '황소자리가 오랫동안 기다려온 장기 투자에서 드디어 의미 있는 수익의 싹이 보이기 시작합니다. 이 시점에서 가장 중요한 것은 서두르지 않는 것—황소자리의 "홀딩 능력"은 수많은 투자자들이 결코 따라할 수 없는 재능으로, 바로 이 인내가 시장에서 진정한 복리의 마법을 만들어냅니다. 조금 더 기다리는 것이 지금 가장 현명한 행동입니다.', en: 'In the long-term investments Taurus has waited for patiently, meaningful return sprouts are finally beginning to show. The most important thing at this point is not rushing—Taurus\'s "holding ability" is a talent countless investors can never match, and precisely this patience creates the true magic of compounding in markets. Waiting a little longer is the wisest action right now.', zh: '在金牛座长时间等待的长期投资中，有意义的回报苗头终于开始显现。此时最重要的是不急躁——金牛座的"持有能力"是无数投资者永远无法复制的才能，正是这种耐心在市场中创造真正的复利魔法。再等待一段时间是现在最明智的行动。', ja: '牡牛座が長い間待ってきた長期投資でいよいよ意味のあるリターンの芽が見え始めます。この時点で最も重要なのは焦らないこと——牡牛座の「ホールディング能力」は数多くの投資家が決して真似できない才能で、まさにこの忍耐が市場で真の複利の魔法を作り出します。もう少し待つことが今最も賢明な行動です。', es: 'En las inversiones a largo plazo que Tauro ha esperado pacientemente, finalmente comienzan a verse brotes de retornos significativos. Lo más importante en este punto es no apresurarse—la "capacidad de mantener" de Tauro es un talento que incontables inversores nunca pueden igualar, y precisamente esta paciencia crea la verdadera magia del interés compuesto en los mercados. Esperar un poco más es la acción más sabia en este momento.' },
      { ko: '금성이 지배하는 감각적 분야—음식, 예술, 뷰티, 패션, 인테리어—에서 오늘 재정적 행운이 가장 강하게 작동합니다. 황소자리는 이 분야에서 타고난 안목과 감각을 가지고 있어 트렌드를 남보다 빨리 포착하고, 그 감각이 곧 수익으로 이어질 수 있는 특별한 재능을 갖고 있습니다. 오늘 이 분야와 관련된 재정적 결정이나 기회에 특별한 주의를 기울여보세요.', en: 'In sensory fields governed by Venus—food, art, beauty, fashion, interior design—financial luck operates most powerfully today. Taurus has innate discernment and sensibility in these fields to capture trends faster than others, and that sensibility can directly translate into profit—a special talent unique to you. Pay special attention today to any financial decisions or opportunities related to these fields.', zh: '在金星主管的感官领域——食物、艺术、美容、时尚、室内设计——今天财务运气运作得最强。金牛座在这些领域拥有天生的眼光和感觉，比他人更快捕捉趋势，那种感觉可以直接转化为收益，是你独特的特殊才能。今天对与这些领域相关的财务决策或机会给予特别关注。', ja: '金星が支配する感覚的な分野——食、アート、ビューティー、ファッション、インテリア——で今日財政的な幸運が最も強く作動します。牡牛座はこの分野で生まれつきの審美眼と感覚を持っていてトレンドを他の人より早くキャッチし、その感覚がすぐに収益につながることができる特別な才能を持っています。今日この分野に関連した財政的な決断や機会に特別な注意を払ってみてください。', es: 'En los campos sensoriales gobernados por Venus—gastronomía, arte, belleza, moda, diseño de interiores—la suerte financiera opera con más fuerza hoy. Tauro tiene discernimiento y sensibilidad innatos en estos campos para captar tendencias más rápido que otros, y esa sensibilidad puede traducirse directamente en ganancias—un talento especial único tuyo. Presta especial atención hoy a cualquier decisión financiera u oportunidad relacionada con estos campos.' },
      { ko: '오늘 황소자리는 아끼는 것과 쓰는 것 사이의 완벽한 균형점을 직관적으로 찾아낼 수 있습니다. 이 균형 감각은 황소자리만의 독특한 재정적 지혜로, 너무 아끼어 삶의 질이 떨어지지도, 너무 써서 미래가 불안하지도 않은 스윗 스팟을 오늘 선명하게 느낄 수 있습니다. 오늘의 재정 결정을 그 균형 감각을 믿고 내려보세요—당신의 직관이 정답에 가장 가까이 있습니다.', en: 'Today Taurus can intuitively find the perfect balance point between saving and spending. This sense of balance is Taurus\'s unique financial wisdom—you can clearly feel the sweet spot today where life quality doesn\'t suffer from over-saving, nor does the future from overspending. Make today\'s financial decisions trusting that sense of balance—your intuition is closest to the right answer.', zh: '今天金牛座可以直觉地找到节约和消费之间的完美平衡点。这种平衡感是金牛座独特的财务智慧，今天可以清晰地感受到那个既不因过度节约而降低生活质量、也不因过度消费而让未来感到不安的甜蜜点。相信那种平衡感做出今天的财务决策——你的直觉离正确答案最近。', ja: '今日牡牛座は節約することと使うことの間の完璧なバランス点を直感的に見つけ出すことができます。このバランス感覚は牡牛座だけの独特の財政的知恵で、節約しすぎて生活の質が下がらず、使いすぎて将来が不安にもならないスウィートスポットを今日はっきりと感じることができます。今日の財政的な決断をそのバランス感覚を信じて下してみてください——あなたの直感が正解に最も近くにいます。', es: 'Hoy Tauro puede encontrar intuitivamente el punto de equilibrio perfecto entre ahorrar y gastar. Este sentido del equilibrio es la sabiduría financiera única de Tauro—puedes sentir claramente hoy el punto dulce donde la calidad de vida no sufre del ahorro excesivo, ni el futuro del gasto excesivo. Toma las decisiones financieras de hoy confiando en ese sentido del equilibrio—tu intuición está más cerca de la respuesta correcta.' },
    ],
    medium: [
      { ko: '재정이 드라마틱하지도 위기적이지도 않은 안정적인 흐름 속에 있습니다. 황소자리는 이 평온한 상태에서 가장 현명한 재정 결정을 내리는 경향이 있는데, 흥분이나 불안 없이 차분하게 계획을 점검하고 작은 최적화를 이루는 것이 지금 할 수 있는 가장 가치 있는 재정 활동입니다. 오늘의 평온함을 활용해 재정 계획의 작은 조정을 실천해보세요.', en: 'Finances are in stable flow—neither dramatic nor crisis-level. Taurus tends to make the wisest financial decisions in this calm state, and checking plans and making small optimizations without excitement or anxiety is the most valuable financial activity you can do right now. Use today\'s calm to practice small adjustments to your financial plan.', zh: '财务处于既不戏剧性也不危机性的稳定流动中。金牛座倾向于在这种平静状态下做出最明智的财务决策，没有兴奋或焦虑地冷静检查计划并进行小优化，是现在可以做的最有价值的财务活动。利用今天的平静实践财务计划的小调整。', ja: '財政がドラマチックでも危機的でもない安定した流れの中にあります。牡牛座はこの穏やかな状態で最も賢明な財政的決断を下す傾向がありますが、興奮や不安なく落ち着いて計画を点検し小さな最適化を行うことが今できる最も価値ある財政活動です。今日の穏やかさを活用して財政計画の小さな調整を実践してみてください。', es: 'Las finanzas están en flujo estable—ni dramático ni en crisis. Tauro tiende a tomar las decisiones financieras más sabias en este estado tranquilo, y revisar planes y hacer pequeñas optimizaciones sin emoción ni ansiedad es la actividad financiera más valiosa que puedes hacer ahora mismo. Usa la calma de hoy para practicar pequeños ajustes a tu plan financiero.' },
      { ko: '오늘 황소자리의 꼼꼼한 눈으로 지출 내역을 점검하면, 생각보다 쉽게 제거할 수 있는 불필요한 지출을 발견하게 됩니다. 황소자리는 한번 구독하거나 계약한 것을 끊기 어려워하는 경향이 있는데, 지금이 그 묵은 항목들을 정리하기 좋은 시기입니다. 작은 삭감들이 모여 상당한 여유 자금이 되면, 그 돈을 진짜 가치 있는 것에 쓸 수 있다는 황소자리의 풍요 원칙을 실천하세요.', en: 'Today Taurus\'s meticulous eye examining spending will discover unnecessary expenses easier to eliminate than expected. Taurus tends to find it hard to cancel subscriptions or contracts once started—now is a good time to tidy up those aged items. When small cuts accumulate into substantial spare funds, practice Taurus\'s abundance principle of spending that money on truly valuable things.', zh: '今天用金牛座细致的眼光检查支出明细，会发现比预想中更容易消除的不必要支出。金牛座倾向于难以取消已经订阅或签订的东西，现在是整理那些陈旧项目的好时机。小的削减积累成可观的余裕资金后，实践金牛座把那笔钱用于真正有价值事物的丰盛原则。', ja: '今日牡牛座の几帳面な目で支出内訳を点検すると、思ったより簡単に削除できる不要な支出を発見します。牡牛座は一度サブスクリプションや契約したものを断ちにくい傾向がありますが、今がその古い項目を整理するのに良い時期です。小さな削減が集まって相当のゆとり資金になれば、そのお金を本当に価値あるものに使えるという牡牛座の豊かさの原則を実践してください。', es: 'El ojo meticuloso de Tauro revisando los gastos hoy descubrirá gastos innecesarios más fáciles de eliminar de lo esperado. Tauro tiende a encontrar difícil cancelar suscripciones o contratos una vez iniciados—ahora es buen momento para ordenar esos elementos obsoletos. Cuando los pequeños recortes se acumulen en fondos de reserva sustanciales, practica el principio de abundancia de Tauro de gastar ese dinero en cosas verdaderamente valiosas.' },
      { ko: '황소자리가 가장 잘하는 일 중 하나가 장기적 안목으로 재정을 계획하는 것인데, 오늘이 그 계획을 재점검하기에 이상적인 날입니다. 막연한 목표 대신 "5년 후 얼마를 갖고 있을 것"처럼 구체적인 숫자와 시간표를 설정하는 것이 황소자리의 집중력을 실질적 행동으로 전환시키는 가장 효과적인 방법입니다. 오늘 30분을 투자해 재정 지도를 다시 그려보세요.', en: 'One of Taurus\'s greatest strengths is planning finances with long-term vision—today is an ideal day to re-examine those plans. Setting specific numbers and timelines—like "I will have X amount in 5 years" rather than vague goals—is the most effective way to convert Taurus\'s focus into real action. Invest 30 minutes today to redraw your financial map.', zh: '金牛座最擅长的事情之一是用长远眼光规划财务，今天是重新审查那些计划的理想日子。设定"5年后将拥有多少"这样的具体数字和时间表，而不是模糊的目标，是将金牛座的专注力转化为实际行动的最有效方法。今天投资30分钟重新绘制财务地图。', ja: '牡牛座が最も得意なことの一つが長期的な視野で財政を計画することですが、今日がその計画を再点検するのに理想的な日です。漠然とした目標ではなく「5年後にいくら持っているか」のような具体的な数字と時間軸を設定することが、牡牛座の集中力を実質的な行動に転換する最も効果的な方法です。今日30分を投資して財政の地図を改めて描いてみてください。', es: 'Una de las mayores fortalezas de Tauro es planificar las finanzas con visión a largo plazo—hoy es un día ideal para reexaminar esos planes. Establecer números y plazos específicos—como "tendré X cantidad en 5 años" en lugar de objetivos vagos—es la forma más efectiva de convertir el enfoque de Tauro en acción real. Invierte 30 minutos hoy para redibujar tu mapa financiero.' },
      { ko: '황소자리는 구매 전 철저한 조사를 통해 후회 없는 선택을 하는 능력을 가지고 있습니다. 오늘 필요한 구매가 있다면, 시간을 들여 가격 비교와 리뷰 확인을 하는 것이 단순한 절약이 아닌 황소자리의 가치 식별 능력을 최대로 발휘하는 과정입니다. 이 과정을 통해 당신이 최선의 가치를 얻었다는 확신을 가지고 구매하면, 황소자리의 풍요 에너지가 그 선택에 만족을 더해줍니다.', en: 'Taurus has the ability to make regret-free choices through thorough research before purchasing. If you have purchases to make today, taking time to compare prices and check reviews isn\'t just saving—it\'s the process of maximizing Taurus\'s value-identification ability. When you buy with the conviction that you\'ve obtained the best value through this process, Taurus\'s abundance energy adds satisfaction to that choice.', zh: '金牛座具有通过购买前彻底调查做出无悔选择的能力。如果今天有需要购买的东西，花时间比较价格和查看评价，不只是节约，而是最大发挥金牛座价值识别能力的过程。通过这个过程确信获得了最佳价值后再购买，金牛座的丰盛能量会为那个选择增添满足感。', ja: '牡牛座は購入前の徹底した調査を通じて後悔のない選択をする能力を持っています。今日必要な購入があるなら、時間をかけて価格比較とレビュー確認をすることが単なる節約ではなく、牡牛座の価値識別能力を最大に発揮するプロセスです。このプロセスを通じて最高の価値を得たという確信を持って購入すれば、牡牛座の豊かさエネルギーがその選択に満足を加えてくれます。', es: 'Tauro tiene la habilidad de hacer elecciones sin arrepentimiento a través de una investigación exhaustiva antes de comprar. Si tienes compras que hacer hoy, tomarse tiempo para comparar precios y revisar opiniones no es solo ahorro—es el proceso de maximizar la habilidad de identificación de valor de Tauro. Cuando compras con la convicción de haber obtenido el mejor valor a través de este proceso, la energía de abundancia de Tauro añade satisfacción a esa elección.' },
      { ko: '황소자리의 재정적 마법은 큰 시작이 아닌 꾸준한 지속에서 나옵니다. 오늘 적금이나 정기 저축을 시작한다면, 금액이 작아도 전혀 상관없습니다—중요한 것은 시스템을 만드는 것이고, 황소자리는 한번 시스템을 만들면 누구보다 오래 지속시키는 능력을 갖고 있습니다. 월 1만 원도 10년이면 상당한 금액이 된다는 복리의 마법을 오늘 황소자리의 꾸준함과 결합해보세요.', en: 'Taurus\'s financial magic comes not from big starts but from consistent continuation. If you start savings or regular deposits today, the amount doesn\'t matter at all—what matters is creating the system, and once Taurus creates a system, you have the ability to sustain it longer than anyone. Combine the magic of compounding—even small monthly amounts become substantial over 10 years—with Taurus\'s consistency today.', zh: '金牛座的财务魔法来自持续的坚持，而不是大的开始。如果今天开始定期存款或定期储蓄，金额多少无所谓——重要的是建立系统，金牛座一旦建立了系统，就有比任何人都能长期维持的能力。今天将月定存复利魔法——即使是小额每月存款10年后也会成为相当可观的金额——与金牛座的持续性结合起来。', ja: '牡牛座の財政的な魔法は大きなスタートではなく着実な継続から生まれます。今日積立や定期貯蓄を始めるなら、金額が少なくても全く構いません——重要なのはシステムを作ることで、牡牛座は一度システムを作れば誰よりも長く継続させる能力を持っています。月1万円でも10年で相当な金額になるという複利の魔法を今日牡牛座の着実さと組み合わせてみてください。', es: 'La magia financiera de Tauro proviene no de grandes comienzos sino de la continuación consistente. Si empiezas ahorros o depósitos regulares hoy, el monto no importa en absoluto—lo que importa es crear el sistema, y una vez que Tauro crea un sistema, tienes la habilidad de sustentarlo más que nadie. Combina hoy la magia del interés compuesto—incluso pequeños montos mensuales se vuelven sustanciales en 10 años—con la consistencia de Tauro.' },
      { ko: '금성의 별자리 황소자리는 풍요를 사랑하지만, 진정한 풍요는 가진 것에서 최대한의 기쁨을 뽑아내는 능력에서 옵니다. 오늘 현재 수입의 한계 안에서도 감사하고 즐길 수 있는 것들을 발견하는 황소자리의 감각을 발휘하면, 더 많이 가지려는 불안 대신 지금 이 순간의 충만함이 자연스럽게 찾아옵니다. 이 풍요의 마음가짐이 역설적으로 더 큰 부를 끌어당기는 에너지가 됩니다.', en: 'Taurus—Venus\'s sign—loves abundance, but true abundance comes from the ability to extract maximum joy from what you have. When you exercise Taurus\'s sensibility to discover things to appreciate and enjoy even within current income limits, instead of anxiety about having more, the fullness of this present moment naturally arrives. This mindset of abundance paradoxically becomes the energy that attracts greater wealth.', zh: '金星的星座金牛座热爱丰盛，但真正的丰盛来自从拥有的事物中提取最大喜悦的能力。今天发挥金牛座即使在当前收入限制内也能发现感恩和享受事物的感觉，取代想要更多的焦虑，此刻的充实感自然而来。这种丰盛的心态悖论性地成为吸引更大财富的能量。', ja: '金星の星座牡牛座は豊かさを愛しますが、真の豊かさは持っているものから最大限の喜びを引き出す能力からきます。今日現在の収入の限界の中でも感謝し楽しめるものを発見する牡牛座の感覚を発揮すると、もっと持とうとする不安の代わりに今この瞬間の充実が自然とやってきます。この豊かさのマインドセットが逆説的により大きな富を引き寄せるエネルギーになります。', es: 'Tauro—el signo de Venus—ama la abundancia, pero la verdadera abundancia viene de la habilidad de extraer la máxima alegría de lo que tienes. Cuando ejercitas la sensibilidad de Tauro para descubrir cosas que apreciar y disfrutar incluso dentro de los límites de ingresos actuales, en lugar de la ansiedad por tener más, la plenitud de este momento presente llega naturalmente. Esta mentalidad de abundancia paradójicamente se convierte en la energía que atrae mayor riqueza.' },
      { ko: '황소자리의 실용주의는 오늘 재정 결정에서 가장 강력한 나침반이 됩니다. 싸고 자주 교체해야 하는 것보다 한 번 더 비싸더라도 오래 가는 실용적인 것에 투자하는 황소자리의 철학이, 5년·10년의 시계로 보면 훨씬 더 경제적이라는 것이 수학적으로도 입증됩니다. 오늘 구매를 고려한다면 "이것이 5년 후에도 내 삶을 더 편하게 해줄까?"라는 황소자리의 질문을 던져보세요.', en: 'Taurus\'s pragmatism becomes the most powerful compass in financial decisions today. The Taurus philosophy of investing in practical, lasting things even at higher cost rather than cheap frequent replacements is mathematically proven to be much more economical when viewed over a 5- to 10-year horizon. If considering a purchase today, ask the Taurus question: "Will this make my life more comfortable 5 years from now?"', zh: '金牛座的实用主义今天成为财务决策中最强大的指南针。比起便宜但需要频繁更换的东西，金牛座宁可贵一些也要投资耐用实用物品的哲学，从5年、10年的视角来看，数学上也被证明更经济。如果今天考虑购买，问金牛座的问题："5年后这东西还能让我的生活更舒适吗？"', ja: '牡牛座の実用主義が今日の財政的決断で最も強力なコンパスになります。安くて頻繁に交換が必要なものよりも少し高くても長持ちする実用的なものに投資する牡牛座の哲学が、5年・10年のスケールで見ると数学的にもずっと経済的であることが証明されます。今日購入を考えているなら「これが5年後も私の生活をより便利にしてくれるか？」という牡牛座の問いを投げかけてみてください。', es: 'El pragmatismo de Tauro se convierte hoy en la brújula más poderosa en las decisiones financieras. La filosofía de Tauro de invertir en cosas prácticas y duraderas incluso a mayor costo en lugar de reemplazos baratos frecuentes está matemáticamente probado que es mucho más económica cuando se ve en un horizonte de 5 a 10 años. Si consideras una compra hoy, haz la pregunta de Tauro: "¿Esto hará mi vida más cómoda 5 años a partir de ahora?"' },
      { ko: '황소자리는 재정 지식을 깊이 이해한 후 천천히 적용하는 스타일로, 공부에 투자한 시간이 나중에 더 현명한 결정으로 돌아옵니다. 오늘 재테크 관련 정보를 수집하고 학습하는 시간은 단순한 공부가 아닌, 황소자리의 재정적 자아를 강화하는 투자입니다. 하나의 개념을 제대로 이해하는 것이 열 가지를 얕게 아는 것보다 황소자리에게 훨씬 더 가치 있습니다.', en: 'Taurus\'s style is to deeply understand financial knowledge before slowly applying it—time invested in studying returns later as wiser decisions. Time today gathering and learning financial information isn\'t just study—it\'s an investment that strengthens Taurus\'s financial self. Truly understanding one concept is far more valuable to Taurus than shallowly knowing ten.', zh: '金牛座的风格是深入理解财务知识后缓慢应用，投资于学习的时间后来会以更明智的决策返还。今天收集和学习理财相关信息的时间不只是单纯的学习，而是强化金牛座财务自我的投资。真正理解一个概念对金牛座来说远比浅显知道十件事更有价值。', ja: '牡牛座は財政的な知識を深く理解した後ゆっくり適用するスタイルで、勉強に投資した時間が後で より賢明な決断として戻ってきます。今日財テク関連情報を収集して学習する時間は単なる勉強ではなく、牡牛座の財政的な自己を強化する投資です。一つの概念をしっかり理解することが10つを浅く知ることよりも牡牛座にとってずっと価値があります。', es: 'El estilo de Tauro es entender profundamente el conocimiento financiero antes de aplicarlo lentamente—el tiempo invertido en estudiar regresa más tarde como decisiones más sabias. El tiempo hoy recopilando y aprendiendo información financiera no es solo estudio—es una inversión que fortalece el yo financiero de Tauro. Verdaderamente entender un concepto es mucho más valioso para Tauro que saber superficialmente diez.' },
      { ko: '황소자리의 꼼꼼한 기질은 사실 재정 기록에 천부적인 재능을 가지고 있지만, 귀찮음 때문에 시작하지 않는 경우가 많습니다. 가계부나 지출 앱은 황소자리의 안목으로 자신의 소비 패턴을 시각적으로 볼 수 있게 해주는 도구로, 한번 시작하면 황소자리의 패턴 인식 능력이 빠르게 최적화 포인트를 찾아냅니다. 오늘 딱 일주일만 써보겠다는 마음으로 시작해보세요—습관이 형성되면 자연스럽게 계속됩니다.', en: 'Taurus\'s meticulous nature has natural talent for financial record-keeping, but often doesn\'t start due to the inconvenience. A household ledger or spending app is a tool that lets Taurus\'s discernment visually observe spending patterns—once started, Taurus\'s pattern recognition ability quickly finds optimization points. Start today with the mindset of just trying it for one week—once the habit forms, it continues naturally.', zh: '金牛座细致的气质实际上对财务记录有天赋，但常常因为麻烦而不开始。记账本或支出应用是让金牛座用自己的眼光直观看到消费模式的工具，一旦开始，金牛座的模式识别能力会迅速找到优化点。今天以"就试用一周"的心态开始——习惯形成后自然会继续。', ja: '牡牛座の几帳面な気質は実は財政記録に天賦の才能を持っていますが、面倒くさいためになかなか始めない場合が多いです。家計簿や支出アプリは牡牛座の審美眼で自分の消費パターンを視覚的に見ることができるツールで、一度始めれば牡牛座のパターン認識能力が素早く最適化ポイントを見つけ出します。今日ちょうど一週間だけやってみようという気持ちで始めてみてください——習慣が形成されれば自然と続きます。', es: 'La naturaleza meticulosa de Tauro tiene talento natural para el registro financiero, pero frecuentemente no comienza por la inconveniencia. Un libro de gastos o app de finanzas es una herramienta que permite al discernimiento de Tauro observar visualmente los patrones de gasto—una vez empezado, la capacidad de reconocimiento de patrones de Tauro encuentra rápidamente puntos de optimización. Empieza hoy con la mentalidad de probarlo solo una semana—una vez que se forme el hábito, continúa naturalmente.' },
      { ko: '황소자리는 물질적 안정을 중시하지만, 금성의 별자리인 만큼 진정한 풍요는 숫자 이상임을 본능적으로 압니다. 오늘 돈이 살 수 없는 것—깊은 우정, 잊지 못할 경험, 성장의 기회—에 자원을 투자하는 것을 고려해보세요. 황소자리가 관계와 경험에 투자할 때, 그 풍요로움이 나중에 예상치 못한 방식으로 물질적 가치로도 돌아오는 경우가 많습니다.', en: 'Taurus values material security, but as Venus\'s sign, you instinctively know true abundance is beyond numbers. Today consider investing resources in what money can\'t buy—deep friendships, unforgettable experiences, opportunities for growth. When Taurus invests in relationships and experiences, that richness often returns as material value in unexpected ways later.', zh: '金牛座重视物质安全，但作为金星的星座，本能地知道真正的丰盛超越数字。今天考虑将资源投资于金钱买不到的东西——深厚的友谊、难忘的经历、成长的机会。当金牛座投资于关系和经历时，那种丰富往往以意想不到的方式以物质价值的形式返还。', ja: '牡牛座は物質的安定を重視しますが、金星の星座として真の豊かさは数字以上であることを本能的に知っています。今日お金では買えないもの——深い友情、忘れられない経験、成長の機会——にリソースを投資することを考えてみてください。牡牛座が関係と経験に投資するとき、その豊かさが後に予想外の方法で物質的な価値としても戻ってくることが多いです。', es: 'Tauro valora la seguridad material, pero como signo de Venus, instintivamente sabes que la verdadera abundancia está más allá de los números. Hoy considera invertir recursos en lo que el dinero no puede comprar—amistades profundas, experiencias inolvidables, oportunidades de crecimiento. Cuando Tauro invierte en relaciones y experiencias, esa riqueza frecuentemente regresa como valor material de maneras inesperadas más tarde.' },
    ],
    low: [
      { ko: '오늘 물질적인 것에 대한 집착이 평소보다 강해져 재정적 판단력을 흐릴 수 있습니다. 황소자리의 안전 욕구가 과하게 활성화될 때 나타나는 이 집착은, 사실 내면의 불안이 표면으로 나오는 신호이기도 합니다. 물질적 결정을 내리기 전 잠시 멈추고 "이것이 진짜 필요인가, 아니면 불안을 달래려는 충동인가?"를 스스로에게 물어보세요—그 구분이 오늘의 재정을 지켜줍니다.', en: 'Today attachment to material things may strengthen more than usual, clouding financial judgment. This attachment, which appears when Taurus\'s security needs are overly activated, is also a signal of inner anxiety coming to the surface. Before making material decisions, pause and ask yourself: "Is this a real need, or an impulse to soothe anxiety?"—that distinction protects today\'s finances.', zh: '今天对物质的执着可能比平时更强，模糊财务判断力。当金牛座的安全需求过度激活时出现的这种执着，也是内心焦虑浮现到表面的信号。在做物质决策之前暂停一下，问问自己："这是真正的需要，还是安抚焦虑的冲动？"——这种区分会保护今天的财务。', ja: '今日物質的なものへの執着が普段より強くなって財政的な判断力を曇らせる可能性があります。牡牛座の安全欲求が過度に活性化するときに現れるこの執着は、実は内なる不安が表面に出てくるサインでもあります。物質的な決断を下す前に少し立ち止まって「これは本当の必要か、それとも不安をなだめようとする衝動か？」と自分自身に問いかけてみてください——その区別が今日の財政を守ってくれます。', es: 'Hoy el apego a las cosas materiales puede fortalecerse más de lo usual, nublando el juicio financiero. Este apego, que aparece cuando las necesidades de seguridad de Tauro se activan excesivamente, también es una señal de ansiedad interior saliendo a la superficie. Antes de tomar decisiones materiales, detente y pregúntate: "¿Es esto una necesidad real, o un impulso para calmar la ansiedad?"—esa distinción protege las finanzas de hoy.' },
      { ko: '황소자리의 안전 선호가 오늘 지나치게 강해져, 성장을 가져올 수 있는 기회들을 모두 너무 위험하다고 판단해 지나칠 위험이 있습니다. 역설적이게도 100% 안전만을 추구하는 것이 장기적으로 가장 큰 리스크—구매력 하락, 성장 기회 비용—를 만들어냅니다. 오늘 완전히 새로운 도전은 하지 않더라도, 기존 포트폴리오에서 약간의 분산을 검토하는 것만으로도 현명한 한 발입니다.', en: 'Taurus\'s safety preference may strengthen too much today, risking passing all growth-bringing opportunities as "too risky." Paradoxically, pursuing 100% safety creates the greatest long-term risk—declining purchasing power, opportunity cost of growth. Even without taking completely new challenges today, simply reviewing slight diversification in your existing portfolio is a wise step.', zh: '金牛座的安全偏好今天可能过于强烈，有将所有可能带来增长的机会都判断为"太危险"而错过的风险。矛盾的是，追求100%安全会带来长期最大的风险——购买力下降、成长机会成本。今天即使不进行全新挑战，只是审查现有投资组合中略微分散的可能性，也是明智的一步。', ja: '牡牛座の安全志向が今日過度に強くなって、成長をもたらせる機会をすべて「危険すぎる」と判断して見過ごす危険があります。逆説的に100%安全だけを追求することが長期的に最も大きなリスク——購買力の低下、成長の機会費用——を作り出します。今日完全に新しい挑戦はしなくても、既存のポートフォリオで少しの分散を検討するだけでも賢明な一歩です。', es: 'La preferencia de seguridad de Tauro puede fortalecerse demasiado hoy, arriesgando pasar todas las oportunidades que podrían traer crecimiento como "demasiado riesgosas." Paradójicamente, buscar solo el 100% de seguridad crea el mayor riesgo a largo plazo—disminución del poder adquisitivo, costo de oportunidad del crecimiento. Incluso sin tomar desafíos completamente nuevos hoy, simplemente revisar una ligera diversificación en tu portafolio existente es un paso sabio.' },
      { ko: '황소자리의 감각적 욕구가 오늘 고양되어 좋은 것, 아름다운 것, 고급스러운 것에 유독 끌릴 수 있습니다. 이 감각 에너지는 황소자리의 아름다운 특성이지만, 예산 없이 따라가면 나중에 후회할 지출이 됩니다. 쇼핑 전 구체적인 상한선을 정하고, 그 범위 안에서 가장 최고의 것을 선택하는 황소자리의 안목 게임을 오늘 즐겨보세요—제약 안에서 오히려 더 창의적인 선택이 나옵니다.', en: 'Taurus\'s sensory desires may heighten today, making you especially drawn to nice, beautiful, luxurious things. This sensory energy is a beautiful Taurus trait, but following it without a budget creates spending you\'ll regret later. Before shopping, set a concrete ceiling and enjoy the Taurus discernment game of choosing the very best within that range—constraints actually bring out more creative choices.', zh: '金牛座的感官欲望今天可能高涨，对美好的、漂亮的、奢华的东西特别有吸引力。这种感官能量是金牛座美好的特性，但没有预算地跟随会成为日后后悔的支出。购物前设定具体的上限，在那个范围内选择最好东西的金牛座眼光游戏今天好好享受——约束内反而会产生更有创意的选择。', ja: '牡牛座の感覚的欲求が今日高まって、良いもの、美しいもの、高級なものに特に惹かれる可能性があります。この感覚エネルギーは牡牛座の美しい特性ですが、予算なしに従うと後で後悔する支出になります。ショッピング前に具体的な上限を決めて、その範囲内で最高のものを選ぶ牡牛座の審美眼ゲームを今日楽しんでみてください——制約の中でむしろより創造的な選択が生まれます。', es: 'Los deseos sensoriales de Tauro pueden elevarse hoy, haciéndote especialmente atraído/a por cosas bonitas, hermosas y lujosas. Esta energía sensorial es un rasgo hermoso de Tauro, pero seguirla sin presupuesto crea gastos de los que te arrepentirás después. Antes de comprar, establece un techo concreto y disfruta el juego de discernimiento de Tauro de elegir lo mejor dentro de ese rango—las restricciones en realidad generan elecciones más creativas.' },
      { ko: '오늘 재정적 변동이나 불확실성이 황소자리의 안전 욕구를 자극해 과도한 불안을 만들어낼 수 있습니다. 하지만 황소자리의 진짜 강함은 단기 요동 앞에서도 흔들리지 않는 장기적 시야에 있다는 것을 기억하세요. 지금 불안하게 느껴지는 것들의 대부분은 1년 후에는 기억조차 못할 작은 일들이며, 황소자리의 기반은 그 모든 파도보다 훨씬 더 강하고 깊습니다.', en: 'Today financial fluctuations or uncertainty may stimulate Taurus\'s security needs, creating excessive anxiety. But remember that Taurus\'s true strength lies in long-term vision that doesn\'t waver even before short-term turbulence. Most of what feels anxious now will be things you won\'t even remember a year from now, and Taurus\'s foundation is far stronger and deeper than any of those waves.', zh: '今天财务波动或不确定性可能刺激金牛座的安全需求，产生过度焦虑。但请记住，金牛座真正的力量在于即使在短期波动面前也不动摇的长远视角。现在感到焦虑的大多数事情，1年后可能连记都记不住，而金牛座的基础比所有那些波浪都强大和深厚得多。', ja: '今日財政的な変動や不確実性が牡牛座の安全欲求を刺激して過度な不安を作り出す可能性があります。しかし牡牛座の本当の強さは短期的な揺れの前でも揺らがない長期的な視野にあることを忘れないでください。今不安に感じることの大部分は1年後には記憶にも残らない小さなことであり、牡牛座の基盤はそのすべての波よりもずっと強く深いです。', es: 'Hoy las fluctuaciones financieras o la incertidumbre pueden estimular las necesidades de seguridad de Tauro, creando ansiedad excesiva. Pero recuerda que la verdadera fortaleza de Tauro reside en la visión a largo plazo que no vacila incluso ante la turbulencia a corto plazo. La mayoría de lo que se siente ansioso ahora serán cosas que ni recordarás un año después, y la base de Tauro es mucho más fuerte y profunda que cualquiera de esas olas.' },
      { ko: '황소자리의 관대함과 신뢰 기질이 오늘 타인의 금전 문제에 지나치게 깊이 끌려들어갈 위험을 만들고 있습니다. 도움을 주는 것은 황소자리의 아름다운 면이지만, 자신의 재정적 안정이 위협받는 수준까지 관여하는 것은 상대방에게도 결국 좋지 않습니다. "나는 응원하지만, 이 부분은 도울 수 없다"고 명확하게 말하는 것이 황소자리의 자기 보호이자 진정한 우정의 표현입니다.', en: 'Taurus\'s generosity and trusting nature today creates risk of being pulled too deeply into others\' money problems. Helping is a beautiful Taurus trait, but getting involved to the level where your own financial stability is threatened is ultimately not good for the other person either. Clearly saying "I support you, but I cannot help with this part" is Taurus\'s self-protection and the expression of true friendship.', zh: '金牛座的慷慨和信任气质今天创造了被过深卷入他人金钱问题的风险。帮助他人是金牛座美好的一面，但涉及到威胁自己财务稳定的程度，对对方来说最终也不好。清楚地说"我支持你，但这部分我无法帮忙"，既是金牛座的自我保护，也是真正友谊的表达。', ja: '牡牛座の寛大さと信頼気質が今日他人のお金の問題に深く引き込まれすぎる危険を作り出しています。助けることは牡牛座の美しい面ですが、自分の財政的安定が脅かされるレベルまで関わることは相手にとっても結局良くありません。「応援するが、この部分は助けられない」と明確に言うことが牡牛座の自己保護であり真の友情の表現です。', es: 'La generosidad y la naturaleza confiada de Tauro hoy crea riesgo de ser arrastrado demasiado profundamente en los problemas de dinero de otros. Ayudar es un rasgo hermoso de Tauro, pero involucrarse hasta el nivel donde tu propia estabilidad financiera se ve amenazada no es bueno para la otra persona tampoco. Decir claramente "te apoyo, pero no puedo ayudar con esta parte" es la autoprotección de Tauro y la expresión de la verdadera amistad.' },
      { ko: '재정적으로 힘든 시기일수록 황소자리는 지출을 최소화하려는 인색함 모드에 빠지기 쉬운데, 오늘 그 경향이 소중한 관계에 균열을 만들 수 있습니다. 관계에 쓰는 돈은 낭비가 아닌 투자—함께 한 끼 먹기, 작은 선물, 예상치 못한 응원—가 황소자리의 실질적인 풍요를 보여주는 방식입니다. 오늘 관계를 위해 쓸 수 있는 작은 금액을 의식적으로 허용해보세요.', en: 'The harder times are financially, the more Taurus tends to fall into stinginess mode minimizing all spending—today that tendency may create cracks in precious relationships. Money spent on relationships isn\'t waste but investment—sharing a meal, a small gift, unexpected encouragement—these are the ways Taurus demonstrates genuine abundance. Consciously allow yourself a small amount to spend on relationships today.', zh: '财务越艰难，金牛座越容易陷入将所有支出最小化的吝啬模式——今天这种倾向可能在珍贵的关系中制造裂缝。花在关系上的钱不是浪费而是投资——一起吃顿饭、小礼物、意想不到的鼓励——这些是金牛座展示真实丰盛的方式。今天有意识地允许自己为关系花一小笔钱。', ja: '財政的に厳しい時期ほど牡牛座は支出を最小化しようとする吝嗇モードに陥りやすいのですが、今日その傾向が大切な関係に亀裂を生み出す可能性があります。関係に使うお金は無駄ではなく投資——一緒に食事をすること、小さなプレゼント、予期せぬ応援——が牡牛座の実質的な豊かさを示す方法です。今日関係のために使える小さな金額を意識的に許可してみてください。', es: 'Cuanto más difíciles son los tiempos financieramente, más Tauro tiende a caer en modo de tacañería minimizando todos los gastos—hoy esa tendencia puede crear grietas en relaciones preciosas. El dinero gastado en relaciones no es desperdicio sino inversión—compartir una comida, un pequeño regalo, apoyo inesperado—estas son las formas en que Tauro demuestra abundancia genuina. Permítete conscientemente una pequeña cantidad para gastar en relaciones hoy.' },
      { ko: '황소자리의 저장 본능이 오늘 강하게 발동해 "혹시 필요할지 모르니"라는 생각으로 대량 구매나 불필요한 비축을 하려는 충동이 생길 수 있습니다. 이 충동은 안전 욕구에서 오는 것이지만, 결과적으로는 공간과 돈 모두를 낭비하는 패턴입니다. 구매 전 "지난 6개월 안에 이것이 필요했던 적이 있는가?"를 기준으로 삼으면 황소자리의 비축 충동을 현명하게 걸러낼 수 있습니다.', en: 'Taurus\'s hoarding instinct may activate strongly today, creating impulses to bulk-buy or unnecessarily stockpile with the thought "might be needed." This impulse comes from security needs, but ultimately creates a pattern that wastes both space and money. Before buying, use the criterion "Have I actually needed this in the last 6 months?"—this wisely filters Taurus\'s stockpiling impulse.', zh: '金牛座的囤积本能今天可能强烈触发，产生以"万一需要"的想法大量购买或不必要囤积的冲动。这种冲动来自安全需求，但结果上是同时浪费空间和金钱的模式。购买前以"过去6个月内有没有需要过这个"为标准，可以明智地过滤金牛座的囤积冲动。', ja: '牡牛座の貯蔵本能が今日強く発動して「ひょっとして必要かも」という考えで大量購入や不要な備蓄をしようとする衝動が生じる可能性があります。この衝動は安全欲求から来るものですが、結果的には空間とお金の両方を無駄にするパターンです。購入前に「過去6ヶ月以内にこれが必要だったことがあるか？」を基準にすれば牡牛座の備蓄衝動を賢くフィルタリングできます。', es: 'El instinto de acumulación de Tauro puede activarse fuertemente hoy, creando impulsos de comprar en bulk o acumular innecesariamente con el pensamiento "podría necesitarse." Este impulso viene de necesidades de seguridad, pero en última instancia crea un patrón que desperdicia tanto espacio como dinero. Antes de comprar, usa el criterio "¿He necesitado realmente esto en los últimos 6 meses?"—esto filtra sabiamente el impulso de acumulación de Tauro.' },
      { ko: '황소자리의 고집은 긍정적으로는 꾸준함이지만, 부정적으로는 변화에 저항하는 경직성이 됩니다. 오늘 재정 상황이 지금의 방식으로는 원하는 결과가 나오지 않는다는 신호를 보내고 있다면, 용기 있게 방법을 바꿀 필요가 있습니다. 황소자리에게 "계획 수정"은 실패가 아닌 더 좋은 목표를 향한 지혜로운 방향 전환이며, 그 유연성이 오히려 장기적 성공을 보장합니다.', en: 'Taurus\'s stubbornness is positively consistency, but negatively becomes rigidity resisting change. If today financial situations are sending signals that the current approach isn\'t producing desired results, you need to courageously change methods. For Taurus, "plan revision" isn\'t failure but wise redirection toward better goals, and that flexibility actually guarantees long-term success.', zh: '金牛座的固执积极方面是坚持，消极方面则成为抗拒变化的僵化。如果今天财务状况发出按照现有方式无法得到想要结果的信号，就需要有勇气改变方法。对金牛座来说，"计划修正"不是失败，而是朝向更好目标的明智转向，那种灵活性反而保证了长期成功。', ja: '牡牛座の頑固さはポジティブには着実さですが、ネガティブには変化に抵抗する硬直性になります。今日財政的な状況が今のやり方では望む結果が出ないというサインを送っているなら、勇気を持って方法を変える必要があります。牡牛座にとって「計画修正」は失敗ではなくより良い目標への賢い方向転換であり、その柔軟性がむしろ長期的な成功を保証します。', es: 'La terquedad de Tauro es positivamente consistencia, pero negativamente se convierte en rigidez que resiste el cambio. Si hoy las situaciones financieras están enviando señales de que el enfoque actual no está produciendo los resultados deseados, necesitas cambiar métodos valientemente. Para Tauro, "revisión del plan" no es fracaso sino redirección sabia hacia mejores objetivos, y esa flexibilidad en realidad garantiza el éxito a largo plazo.' },
      { ko: '황소자리의 보수적 투자 성향이 오늘 극단적으로 강화되어, 합리적인 기회마저 너무 위험하게 느껴질 수 있습니다. 하지만 인플레이션 시대에 아무것도 하지 않는 것이 가장 큰 리스크라는 것을 잊지 마세요—돈을 그냥 놔두는 것이 구매력을 조용히 잠식합니다. 오늘 당장 큰 변화를 할 필요는 없지만, 적정 수준의 리스크를 수용하는 황소자리만의 철학을 재점검해볼 시간입니다.', en: 'Taurus\'s conservative investment tendency may intensify extremely today, making even reasonable opportunities feel too risky. But don\'t forget that in an era of inflation, doing nothing is the greatest risk—leaving money alone quietly erodes purchasing power. No need for big changes right now, but it\'s time to re-examine Taurus\'s own philosophy of accepting appropriate levels of risk.', zh: '金牛座保守的投资倾向今天可能极端强化，使得连合理的机会都感觉太危险。但不要忘记，在通胀时代什么都不做才是最大的风险——让钱放着会悄悄侵蚀购买力。今天不需要立刻做大改变，但是重新审视金牛座接受适当风险水平的哲学的时候了。', ja: '牡牛座の保守的な投資性向が今日極端に強化されて、合理的な機会まで危険すぎるように感じられる可能性があります。しかしインフレの時代に何もしないことが最も大きなリスクであることを忘れないでください——お金をそのままにしておくことが購買力を静かに侵食します。今日すぐに大きな変化をする必要はありませんが、適切なレベルのリスクを受容する牡牛座だけの哲学を再点検する時間です。', es: 'La tendencia de inversión conservadora de Tauro puede intensificarse extremadamente hoy, haciendo que incluso las oportunidades razonables se sientan demasiado arriesgadas. Pero no olvides que en una era de inflación, no hacer nada es el mayor riesgo—dejar el dinero quieto erosiona silenciosamente el poder adquisitivo. No hay necesidad de grandes cambios ahora mismo, pero es el momento de reexaminar la propia filosofía de Tauro sobre aceptar niveles apropiados de riesgo.' },
      { ko: '황소자리는 사랑과 관계를 물질적 선물이나 지원으로 표현하는 경향이 있는데, 오늘 그 방식이 진심 대신 돈으로 관계를 유지하려는 패턴으로 흘러갈 수 있습니다. 진짜 관계는 돈으로 살 수도, 잃을 수도 없으며—당신의 진심 어린 현존과 시간과 경청이 어떤 선물보다 더 큰 가치를 가집니다. 오늘 지갑 대신 마음을 여는 용기를 내어보세요.', en: 'Taurus tends to express love and relationships through material gifts or support, but today that approach may slide into a pattern of maintaining relationships with money instead of sincerity. Real relationships cannot be bought or lost with money—your sincere presence, time, and listening hold more value than any gift. Today, find the courage to open your heart instead of your wallet.', zh: '金牛座倾向于通过物质礼物或支持来表达爱和关系，但今天这种方式可能滑入用金钱而非真心来维持关系的模式。真正的关系既买不来也失不了——你真诚的陪伴、时间和倾听比任何礼物都更有价值。今天鼓起勇气打开心而不是钱包。', ja: '牡牛座は愛や関係を物質的な贈り物やサポートで表現する傾向がありますが、今日その方式が真心の代わりにお金で関係を維持しようとするパターンに流れる可能性があります。本物の関係はお金では買うこともできず失うこともできません——あなたの真心こもった存在と時間と傾聴がどんな贈り物よりも大きな価値を持ちます。今日お財布の代わりに心を開く勇気を出してみてください。', es: 'Tauro tiende a expresar el amor y las relaciones a través de regalos materiales o apoyo, pero hoy ese enfoque puede deslizarse hacia un patrón de mantener relaciones con dinero en lugar de sinceridad. Las relaciones reales no pueden comprarse ni perderse con dinero—tu presencia sincera, tiempo y escucha tienen más valor que cualquier regalo. Hoy, encuentra el valor para abrir tu corazón en lugar de tu billetera.' },
    ],
  },
};
